                                                                status === 'OVERDUE' ? 'bg-red-100 text-red-800' :
                                                                    status === 'PARTIAL' ? 'bg-yellow-100 text-yellow-800' :
                                                                        'bg-slate-100 text-slate-800'
                                                                }`}>
