                                                                        </div>
                                                                    )}
                                                                    <div className="border-t border-slate-200 pt-1 mt-1 space-y-0.5">
                                                                        {excess > 0 && (
                                                                            <div className="flex justify-between font-semibold text-green-700">
                                                                                <span>Excess Paid:</span>
                                                                                <span>Γé╣{Number(excess).toFixed(2)}</span>
                                                                            </div>
                                                                        )}
                                                                        {outstanding > 0 ? (
                                                                            <div className="flex justify-between font-semibold text-red-600">
                                                                                <span>Balance Due:</span>
                                                                                <span>Γé╣{Number(outstanding).toFixed(2)}</span>
                                                                            </div>
                                                                        ) : (excess === 0 && status !== 'UNPAID') ? (
                                                                            <div className="flex justify-between font-semibold text-green-600">
                                                                                <span>Balance:</span>
                                                                                <span>Γé╣0.00</span>
                                                                            </div>
                                                                        ) : null}
                                                                    </div>
                                                                </>
                                                            );
                                                        })()}
                                                    </div>
                                                    {/* ΓöÇΓöÇ PARTIAL card action buttons ΓöÇΓöÇ */}
                                                    {status === 'PARTIAL' && (
                                                        <div className="mt-2 grid grid-cols-2 gap-1" onClick={e => e.stopPropagation()}>
                                                            {/* View Receipt ΓÇö opens payment history modal */}
