                                                                >
                                                                    Waive Off
                                                                </button>
                                                            )}
                                                            {/* Revert Waive Off ΓÇö admin only, shown when prior waive-offs exist */}
                                                            {rbac.isAdmin && periodWaiveOffs.length > 0 && (
                                                                <button
                                                                    onClick={(e) => {
                                                                        e.stopPropagation();
                                                                        handleRevertWaiveOff(periodWaiveOffs[periodWaiveOffs.length - 1].id);
                                                                    }}
