                                            <label className="block mb-2 text-sm font-medium text-gray-900">Selected Period</label>
                                            <div className="bg-gray-100 border border-gray-300 text-sm rounded-lg block w-full p-2.5 text-gray-600 font-medium wrap-break-word">
                                                {(() => {
                                                    const matchedPeriod = studentFeeDetails?.feePeriods?.find((fp: any) =>
                                                        fp.months?.length === selectedMonths.filter((mk: string) => studentFeeDetails.monthlyBreakdown?.some((m: any) => m.monthKey === mk)).length &&
                                                        selectedMonths.every((mk: string) => fp.months?.includes(mk))
                                                    );
                                                    if (matchedPeriod) return matchedPeriod.periodLabel;
                                                    return selectedMonths.map((mkey: string) => {
                                                        const m = studentFeeDetails.monthlyBreakdown.find((m: any) => m.monthKey === mkey);
                                                        if (m) return m.monthName;
                                                        if (studentFeeDetails.oneTimeFees?.monthKey === mkey) return studentFeeDetails.oneTimeFees.label;
                                                        return mkey;
                                                    }).join(', ');
                                                })()}
                                            </div>
                                        </div>

                                        {(() => {
                                            const totalBalance = (() => {
                                                const feePeriodsArr: any[] = studentFeeDetails.feePeriods ?? [];
                                                const countedPeriodKeys = new Set<string>();
                                                let total = 0;
                                                for (const mkey of selectedMonths) {
                                                    if (studentFeeDetails.oneTimeFees?.monthKey === mkey) {
                                                        total += Number(studentFeeDetails.oneTimeFees.outstanding) || 0;
                                                        continue;
                                                    }
                                                    const matchedPeriod = feePeriodsArr.find((p: any) =>
                                                        (p.months ?? [p.monthKey])?.includes(mkey)
                                                    );
                                                    if (matchedPeriod) {
                                                        // Only count each period once ΓÇö all months in a period share the same outstanding
                                                        if (!countedPeriodKeys.has(matchedPeriod.periodKey ?? matchedPeriod.monthKey)) {
                                                            countedPeriodKeys.add(matchedPeriod.periodKey ?? matchedPeriod.monthKey);
                                                            total += Number(matchedPeriod.adjustedOutstanding) || 0;
                                                        }
                                                    } else {
                                                        const m = studentFeeDetails.monthlyBreakdown.find((m: any) => m.monthKey === mkey);
                                                        total += Number(m?.outstanding) || 0;
                                                    }
                                                }
                                                return total;
                                            })();

                                            return (
                                                <div className="mb-4">
                                                    <div className="flex justify-between items-center mb-2">
                                                        <label className="text-sm font-bold text-blue-700">Amount Paying (Γé╣)</label>
                                                        <span className="text-xs text-gray-500 font-medium">Total Balance: Γé╣{totalBalance.toFixed(2)}</span>
                                                    </div>
                                                    <input
                                                        type="number" step="0.01"
                                                        value={payAmount}
                                                        onChange={(e) => setPayAmount(e.target.value)}
                                                        placeholder={`Recommended: ${totalBalance.toFixed(2)}`}
                                                        className="bg-blue-50 border-2 border-blue-200 rounded-lg block w-full p-2.5 focus:ring-blue-500 focus:border-blue-500 text-lg font-bold text-blue-900 transition-colors"
                                                        required
                                                    />
                                                    <button
                                                        type="button"
                                                        onClick={() => setPayAmount(totalBalance.toFixed(2))}
                                                        className="mt-2 text-xs text-blue-600 hover:text-blue-800 hover:underline font-medium"
                                                    >
                                                        Fill Total Balance
                                                    </button>
                                                </div>
                                            );
                                        })()}

                                        <div className="mb-5 text-sm font-medium">
                                            <label className="block mb-3 text-gray-900">Payment Method</label>
                                            <div className="grid grid-cols-2 gap-3">
                                                {['CASH', 'CARD', 'ONLINE', 'CHEQUE'].map(method => (
                                                    <label key={method} className={`flex items-center justify-center p-3 border rounded-lg cursor-pointer transition-all ${payMethod === method ? 'border-blue-500 bg-blue-50 text-blue-700 ring-1 ring-blue-500' : 'border-gray-200 bg-white hover:bg-gray-50 text-gray-600'}`}>
                                                        <input type="radio" name="payMethod" value={method} checked={payMethod === method} onChange={(e) => setPayMethod(e.target.value)} className="sr-only" />
                                                        <span className="font-medium text-xs">{method}</span>
                                                    </label>
                                                ))}
                                            </div>
                                        </div>
                                        <div className="mb-6">
                                            <label className="block mb-2 text-sm font-medium text-gray-900">Remarks/Ref No.</label>
                                            <input type="text" value={payRemarks} onChange={(e) => setPayRemarks(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 transition-colors focus:ring-blue-500 focus:border-blue-500" placeholder="Optional transaction ID..." />
                                        </div>
                                        <div className="flex gap-3">
                                            <button type="submit" disabled={loadingCollection} className="flex-1 text-white bg-blue-600 hover:bg-blue-700 py-3 rounded-lg font-bold disabled:opacity-50 transition-colors shadow-sm">
                                                Confirm Payment
                                            </button>
                                            <button type="button" onClick={() => setSelectedMonths([])} className="px-5 py-3 bg-gray-100 text-gray-700 border border-gray-200 rounded-lg font-medium hover:bg-gray-200 transition-colors">
                                                Clear Selection
                                            </button>
                                        </div>
                                        {/* Issue Refund / Waive Off shortcuts */}
                                        {studentFeeDetails && (() => {
                                            const excessMonth = studentFeeDetails.monthlyBreakdown?.find((m: any) => (m.excess ?? 0) > 0) ||
                                                (( studentFeeDetails.oneTimeFees?.excess ?? 0) > 0 ? studentFeeDetails.oneTimeFees : null);
                                            const outstandingMonth = studentFeeDetails.monthlyBreakdown?.find((m: any) => (m.outstanding ?? 0) > 0) ||
                                                ((studentFeeDetails.oneTimeFees?.outstanding ?? 0) > 0 ? studentFeeDetails.oneTimeFees : null);
                                            return (
                                                <div className="mt-3 flex flex-col gap-2">
                                                    {rbac.isAdmin && excessMonth && (
                                                        <button
                                                            type="button"
                                                            onClick={() => openAdjModal(excessMonth.monthKey, 'REFUND')}
                                                            className="w-full py-2 text-sm font-medium text-orange-700 bg-orange-50 border border-orange-200 rounded-lg hover:bg-orange-100 transition-colors"
                                                        >
                                                            Issue Refund (Excess Paid)
                                                        </button>
                                                    )}
                                                    {rbac.isAdmin && outstandingMonth && (
                                                        <button
                                                            type="button"
                                                            onClick={() => openAdjModal(outstandingMonth.monthKey, 'WAIVE_OFF')}
                                                            className="w-full py-2 text-sm font-medium text-purple-700 bg-purple-50 border border-purple-200 rounded-lg hover:bg-purple-100 transition-colors"
                                                        >
                                                            Waive Off Outstanding Dues
                                                        </button>
                                                    )}
                                                </div>
                                            );
                                        })()}
                                    </form>
                                )}
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* TAB: APPLY_DISCOUNTS, APPLY_OTHER_FEE & FEE_DETAILS */}
            {(activeTab === 'APPLY_DISCOUNTS' || activeTab === 'APPLY_OTHER_FEE' || activeTab === 'FEE_DETAILS') && (
                <div className="no-print animate-in fade-in duration-300">
                    {/* Shared Advanced Student Search */}
                    <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200 mb-6 relative z-20">
                        <h2 className="text-xl font-bold mb-4 text-slate-800">
                            {activeTab === 'APPLY_DISCOUNTS' ? 'Find Students to Apply Discounts'
                                : activeTab === 'APPLY_OTHER_FEE' ? 'Find Students to Apply Special Fee'
                                : 'Find Student to View Fee Details'}
                        </h2>
                        <form onSubmit={handleSearchFormStudents} className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-7 gap-4 mb-4">
                            <input type="text" placeholder="Student ID" value={searchFormId} onChange={e => setSearchFormId(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block p-2.5 focus:ring-blue-500 focus:border-blue-500" />
                            <input type="text" placeholder="First Name" value={searchFormFirstName} onChange={e => setSearchFormFirstName(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block p-2.5 focus:ring-blue-500 focus:border-blue-500" />
                            <input type="text" placeholder="Last Name" value={searchFormLastName} onChange={e => setSearchFormLastName(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block p-2.5 focus:ring-blue-500 focus:border-blue-500" />
                            <input type="text" placeholder="Mobile" value={searchFormMobile} onChange={e => setSearchFormMobile(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block p-2.5 focus:ring-blue-500 focus:border-blue-500" />
                            
                            <select value={searchFormClassId} onChange={e => setSearchFormClassId(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block p-2.5 focus:ring-blue-500 focus:border-blue-500">
                                <option value="">Class (All)</option>
                                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                            <select value={searchFormSectionId} onChange={e => setSearchFormSectionId(e.target.value)} disabled={!searchFormClassId} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block p-2.5 focus:ring-blue-500 focus:border-blue-500">
                                <option value="">Section (All)</option>
                                {searchFormSections.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                            <select value={searchFormSessionId} onChange={e => setSearchFormSessionId(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block p-2.5 focus:ring-blue-500 focus:border-blue-500">
                                <option value="">Session (All)</option>
                                {sessions.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>

                            <div className="lg:col-span-7 flex justify-end gap-2">
                                <button type="button" onClick={() => { setSearchFormId(""); setSearchFormFirstName(""); setSearchFormLastName(""); setSearchFormMobile(""); setSearchFormClassId(""); setSearchFormSectionId(""); setSearchFormSessionId(""); setHasSearchFormSearched(false); setSearchFormStudentsList([]); }} className="text-gray-700 bg-white border border-gray-300 font-medium rounded-lg text-sm px-4 py-2 hover:bg-gray-50 transition-colors">Clear</button>
                                <button type="submit" disabled={isSearchingStudents} className="text-white bg-blue-600 font-medium rounded-lg text-sm px-6 py-2 hover:bg-blue-700 transition-colors disabled:opacity-50">
                                    {isSearchingStudents ? 'Searching...' : 'Search'}
                                </button>
                            </div>
                        </form>

                        {hasSearchFormSearched && (<>
                            <div className="overflow-x-auto border border-gray-200 rounded-lg max-h-64 mt-4">
                                <table className="w-full text-sm text-left text-gray-500 relative">
                                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 sticky top-0 z-10 shadow-sm">
                                        <tr>
                                            <th className="px-4 py-3">ID</th>
                                            <th className="px-4 py-3">Name</th>
                                            <th className="px-4 py-3">Class/Section</th>
                                            <th className="px-4 py-3">Mobile</th>
                                            <th className="px-4 py-3 text-right">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {searchFormStudentsList.length > 0 ? (
                                            searchFormStudentsList.map((s: any) => {
                                                const enr = s.enrollments?.find((e: any) => e.status === 'ACTIVE') || s.enrollments?.[0];
                                                const classNameStr = enr?.class?.name || s.class?.name || 'N/A';
                                                const sectionNameStr = enr?.section?.name || s.section?.name || 'N/A';
                                                const mobile = s.user?.mobile || s.mobile || 'N/A';
                                                return (
                                                    <tr key={s.id} className="bg-white border-b hover:bg-slate-50 last:border-0 transition-colors">
                                                        <td className="px-4 py-3 font-medium text-gray-900">{s.id}</td>
                                                        <td className="px-4 py-3">{s.firstName} {s.lastName}</td>
                                                        <td className="px-4 py-3">{classNameStr} - {sectionNameStr}</td>
                                                        <td className="px-4 py-3">{mobile}</td>
                                                        <td className="px-4 py-3 text-right">
                                                            <button
                                                                onClick={() => {
                                                                    if (activeTab === 'APPLY_DISCOUNTS') {
                                                                        setApplyDiscountStudentId(s.id.toString());
                                                                        setSelectedDiscountsToApply(
                                                                            s.studentDiscounts
                                                                                ? s.studentDiscounts.filter((sd: any) => sd.isActive).map((sd: any) => sd.discountCategory?.id || sd.discountCategoryId)
                                                                                : []
                                                                        );
                                                                    } else if (activeTab === 'APPLY_OTHER_FEE') {
                                                                        setApplyOtherFeeStudentId(s.id.toString());
                                                                        setApplyOtherFeeStudentName(`${s.firstName} ${s.lastName}`);
                                                                    } else {
                                                                        // FEE_DETAILS
                                                                        handleLoadFeeDetails(s.id.toString(), `${s.firstName} ${s.lastName}`);
                                                                    }
                                                                    setTimeout(() => {
                                                                        window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
                                                                    }, 100);
                                                                }}
                                                                className="text-xs px-3 py-1.5 bg-blue-50 text-blue-700 font-semibold rounded hover:bg-blue-100 transition-colors border border-blue-100"
                                                            >
                                                                {activeTab === 'FEE_DETAILS' ? 'View Details' : 'Select'}
                                                            </button>
                                                        </td>
                                                    </tr>
                                                );
                                            })
                                        ) : (
                                            <tr>
                                                <td colSpan={5} className="px-4 py-6 text-center text-gray-500">
                                                    {isSearchingStudents ? 'Loading...' : 'No students found matching filters.'}
                                                </td>
                                            </tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                            {/* Pagination Controls */}
                            {searchFormTotal > SEARCH_PAGE_SIZE && (
                                <div className="flex items-center justify-between mt-3 px-1">
                                    <p className="text-xs text-gray-500">
                                        Showing {(searchFormPage - 1) * SEARCH_PAGE_SIZE + 1}ΓÇô{Math.min(searchFormPage * SEARCH_PAGE_SIZE, searchFormTotal)} of {searchFormTotal} students
                                    </p>
                                    <div className="flex gap-1">
                                        <button
                                            disabled={searchFormPage <= 1 || isSearchingStudents}
                                            onClick={(e) => handleSearchFormStudents(e as any, searchFormPage - 1)}
                                            className="px-3 py-1 text-xs border rounded hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed"
                                        >ΓåÉ Prev</button>
                                        <span className="px-3 py-1 text-xs bg-blue-50 text-blue-700 border border-blue-200 rounded font-semibold">
                                            {searchFormPage} / {Math.ceil(searchFormTotal / SEARCH_PAGE_SIZE)}
                                        </span>
                                        <button
                                            disabled={searchFormPage >= Math.ceil(searchFormTotal / SEARCH_PAGE_SIZE) || isSearchingStudents}
                                            onClick={(e) => handleSearchFormStudents(e as any, searchFormPage + 1)}
                                            className="px-3 py-1 text-xs border rounded hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed"
                                        >Next ΓåÆ</button>
                                    </div>
                                </div>
                            )}
                        </>)}
                    </div>

                    {/* APPLY_DISCOUNTS specific content */}
                    {activeTab === 'APPLY_DISCOUNTS' && applyDiscountStudentId && (
                        <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200 animate-in slide-in-from-bottom-2 duration-300 relative z-10 w-full md:w-2/3">
                            <h2 className="text-xl font-bold mb-4 text-slate-800">Assign Fee Discounts</h2>
                            <p className="text-sm text-gray-600 mb-6">Select which discounts should apply to this student's monthly fee structure. Note: Only Admin users can modify these assignments.</p>

                            <form onSubmit={async (e) => {
                                e.preventDefault();
                                setApplyingDiscounts(true);
                                try {
                                    const res = await authFetch(`${API_BASE_URL}/students/${applyDiscountStudentId}`, {
                                        method: 'PATCH',
                                        headers: { 'Content-Type': 'application/json' },
                                        body: JSON.stringify({ discountIds: selectedDiscountsToApply })
                                    });
                                    if (res.ok) {
                                        toast.success("Discounts applied successfully!");
                                        // Refresh student query
                                        handleSearchFormStudents(e); 
                                    } else {
                                        throw new Error("Failed to apply discounts");
                                    }
                                } catch (err) {
                                    toast.error("Error applying discounts");
                                } finally {
                                    setApplyingDiscounts(false);
                                }
                            }}>
                                <div className="space-y-4 mb-6 max-h-96 overflow-y-auto p-4 border rounded-lg bg-slate-50">
                                    {discounts.length === 0 ? (
                                        <div className="text-sm text-gray-500">No discount categories exist. Create them in Fee Setup first.</div>
                                    ) : (
                                        discounts.map(d => {
                                            const isSelected = selectedDiscountsToApply.includes(d.id);
                                            return (
                                                <div key={`d-select-${d.id}`}
                                                    onClick={() => {
                                                        setSelectedDiscountsToApply(prev =>
                                                            prev.includes(d.id) ? prev.filter(id => id !== d.id) : [...prev, d.id]
                                                        );
                                                    }}
                                                    className={`cursor-pointer flex items-center p-4 rounded-lg border transition-all ${isSelected ? 'bg-blue-50 border-blue-400 shadow-sm' : 'bg-white border-gray-200 hover:border-blue-300'
                                                        }`}
                                                >
                                                    <input
                                                        type="checkbox"
                                                        checked={isSelected}
                                                        onChange={() => { }}
                                                        className="w-5 h-5 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
                                                    />
                                                    <div className="ml-4 flex-1">
                                                        <span className="block text-sm font-semibold text-gray-900">{d.name}</span>
                                                        <span className="block text-xs text-gray-500 mt-0.5">
                                                            {d.type === 'PERCENTAGE' ? `${d.value}% Off Base Fee` : `$${d.value} Flat Off Base Fee`}
                                                            {d.applicationType === 'AUTO' && <span className="ml-2 inline-block px-2 py-0.5 rounded-full bg-blue-100 text-blue-800 text-[10px] font-bold">AUTO: {d.logicReference}</span>}
                                                        </span>
                                                    </div>
                                                </div>
                                            );
                                        })
                                    )}
                                </div>

                                <div className="flex justify-end pt-4 border-t">
                                    <button
                                        type="submit"
                                        disabled={applyingDiscounts}
                                        className="text-white bg-blue-600 hover:bg-blue-700 focus:ring-4 focus:ring-blue-300 font-medium rounded-lg text-sm px-6 py-2.5 transition-colors disabled:opacity-50"
                                    >
                                        {applyingDiscounts ? 'Saving...' : 'Save Discount Assignments'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    )}

                    {/* APPLY_OTHER_FEE specific content */}
                    {activeTab === 'APPLY_OTHER_FEE' && applyOtherFeeStudentId && (
                        <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200 animate-in slide-in-from-bottom-2 duration-300 relative z-10 w-full">
                            <h2 className="text-xl font-bold mb-4 text-slate-800">Assign Special & Optional Fee</h2>
                            <p className="text-sm text-gray-600 mb-6">Assign a custom fee amount and frequency distinctively to <span className="font-semibold text-blue-700">{applyOtherFeeStudentName}</span> (ID: {applyOtherFeeStudentId}). Note: Optional fees do not undergo discounts automatically unless specified directly.</p>

                            <form onSubmit={handleApplyOtherFeeSubmit}>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                    <div>
                                        <label className="block mb-2 text-sm font-medium text-gray-900">Fee Category</label>
                                        <select
                                            value={applyOtherFeeCategoryId}
                                            onChange={(e) => setApplyOtherFeeCategoryId(e.target.value)}
                                            required
                                            className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 focus:ring-blue-500 focus:border-blue-500"
                                        >
                                            <option value="">Select Category...</option>
                                            {addOnCategories.filter(c => c.isActive !== false).map(c => (
                                                <option key={c.id} value={c.id}>{c.name}</option>
                                            ))}
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block mb-2 text-sm font-medium text-gray-900">Amount (Γé╣)</label>
                                        <input
                                            type="number" step="0.01" min="0" required
                                            value={applyOtherFeeAmount}
                                            onChange={(e) => setApplyOtherFeeAmount(e.target.value)}
                                            placeholder="e.g. 500"
                                            className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 focus:ring-blue-500 focus:border-blue-500"
                                        />
                                    </div>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                                    <div>
                                        <label className="block mb-2 text-sm font-medium text-gray-900">Frequency</label>
                                        <select
                                            value={applyOtherFeeFrequency}
                                            onChange={(e) => setApplyOtherFeeFrequency(e.target.value)}
                                            required
                                            className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 focus:ring-blue-500 focus:border-blue-500"
                                        >
                                            <option value="MONTHLY">Monthly</option>
                                            <option value="QUARTERLY">Quarterly</option>
                                            <option value="HALF_YEARLY">Half Yearly</option>
                                            <option value="ANNUALLY">Annually</option>
                                            <option value="ONE_TIME">One Time</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block mb-2 text-sm font-medium text-gray-900">Remarks / Description</label>
                                        <input
                                            type="text"
                                            value={applyOtherFeeDescription}
                                            onChange={(e) => setApplyOtherFeeDescription(e.target.value)}
                                            placeholder="e.g. Transport fees for Route 4"
                                            className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 focus:ring-blue-500 focus:border-blue-500"
                                        />
                                    </div>
                                </div>

                                <div className="flex justify-end pt-4 border-t">
                                    <button
                                        type="submit"
                                        disabled={applyingOtherFee}
                                        className="text-white bg-blue-600 hover:bg-blue-700 focus:ring-4 focus:ring-blue-300 font-medium rounded-lg text-sm px-6 py-2.5 transition-colors disabled:opacity-50"
                                    >
                                        {applyingOtherFee ? 'Applying...' : 'Apply Special Fee'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    )}
                </div>
            )}

            {/* FEE_DETAILS ΓÇö Detail Panel (rendered below the shared search when a student is selected) */}
            {activeTab === 'FEE_DETAILS' && feeDetailsStudentId && (
                <div className="no-print mt-4 animate-in slide-in-from-bottom-2 duration-300">
                    {loadingFeeDetails ? (
                        <div className="bg-white p-8 rounded-lg shadow-sm border border-slate-200 text-center">
                            <div className="animate-spin w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full mx-auto mb-3"></div>
                            <p className="text-gray-500 text-sm">Loading fee details for {feeDetailsStudentName}...</p>
                        </div>
                    ) : (() => {
                            // 1. Core Summary Calculations
                            const annualLiability = (feeDetailsFull.monthlyBreakdown?.reduce((acc: number, m: any) => acc + (m.totalDue || 0), 0) || 0) + (feeDetailsFull.oneTimeFees?.totalDue || 0);
                            const amountPaid = (feeDetailsFull.monthlyBreakdown?.reduce((acc: number, m: any) => acc + (m.totalPaid || 0), 0) || 0) + (feeDetailsFull.oneTimeFees?.totalPaid || 0);
                            const balanceDue = annualLiability - amountPaid;
                            const pendingMonthsCount = feeDetailsFull.monthlyBreakdown?.filter((m: any) => m.outstanding > 0 || m.status === 'OVERDUE').length || 0;
                            
                            // 2. Representative Monthly Recurring (The standard expected bill)
                            // We look for the first billing month with a baseFee > 0 and use its netFee (Core + Optional - Discounts)
                            const recurringMonth = feeDetailsFull.monthlyBreakdown?.find((m: any) => m.baseFee > 0);
                            const monthlyRecurring = recurringMonth?.netFee || 0;

                            return (
                                <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                    {/* Premium Profile Header - Glassmorphism style */}
                                    <div className="relative overflow-hidden bg-slate-900 rounded-2xl shadow-xl border border-slate-800 p-8">
                                        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/20 rounded-full blur-3xl -mr-20 -mt-20"></div>
                                        <div className="absolute bottom-0 left-0 w-48 h-48 bg-indigo-600/10 rounded-full blur-3xl -ml-20 -mb-20"></div>
                                        
                                        <div className="relative flex flex-col md:flex-row items-center gap-6">
                                            <div className="w-24 h-24 rounded-2xl bg-linear-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-3xl font-bold text-white shadow-lg border border-blue-400/30">
                                                {feeDetailsStudentName.split(' ').map(n => n[0]).join('')}
                                            </div>
                                            <div className="text-center md:text-left flex-1">
                                                <div className="flex items-center justify-center md:justify-start gap-2 mb-1">
                                                    <span className="px-2 py-0.5 bg-blue-500/10 text-blue-400 text-[10px] font-bold uppercase tracking-widest rounded-full border border-blue-500/20">Student Profile</span>
                                                    <span className="px-2 py-0.5 bg-green-500/10 text-green-400 text-[10px] font-bold uppercase tracking-widest rounded-full border border-green-500/20">Active</span>
                                                </div>
                                                <h3 className="text-3xl font-black text-white tracking-tight">{feeDetailsStudentName}</h3>
                                                <div className="flex items-center justify-center md:justify-start gap-4 mt-2 text-slate-400 text-sm">
                                                    <span className="flex items-center gap-1.5 font-medium">
                                                        <svg className="w-4 h-4 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                                                        ID: <span className="text-slate-200">{feeDetailsStudentId}</span>
                                                    </span>
                                                    <span className="flex items-center gap-1.5 font-medium">
                                                        <svg className="w-4 h-4 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                                                        Session: <span className="text-slate-200">{collectionYear}</span>
                                                    </span>
                                                </div>
                                            </div>
                                            <div className="mt-4 md:mt-0 flex flex-col items-center md:items-end">
                                                <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mb-1">Total Balance Due</p>
                                                <p className="text-4xl font-black text-white drop-shadow-sm">
                                                    Γé╣{Number(balanceDue).toLocaleString('en-IN')}
                                                </p>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Stats Grid - 4 Columns */}
                                    <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                                        {[
                                            { 
                                                label: "Annual Liability", 
                                                value: annualLiability, 
                                                icon: "M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m.599-1c.532-.1 1.01-.304 1.43-.591m-1.43.591c-1.01 0-2.08-.402-2.599-1M9.401 13c-.532.1-1.01.304-1.43.591m1.43-.591c.532.1 1.01.304 1.43.591", 
                                                color: "blue" 
                                            },
                                            { 
                                                label: "Amount Paid", 
                                                value: amountPaid, 
                                                icon: "M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z", 
                                                color: "green" 
                                            },
                                            { 
                                                label: "Monthly Recurring", 
                                                value: monthlyRecurring,
                                                icon: "M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15", 
                                                color: "indigo" 
                                            },
                                            { 
                                                label: "Pending Months", 
                                                value: pendingMonthsCount,
                                                isCurrency: false,
                                                icon: "M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z", 
                                                color: "orange" 
                                            }
                                        ].map((stat, i) => (
                                            <div key={i} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm hover:shadow-md transition-all duration-300">
                                                <div className={`w-8 h-8 rounded-lg ${stat.color === 'blue' ? 'bg-blue-50' : stat.color === 'green' ? 'bg-green-50' : stat.color === 'orange' ? 'bg-orange-50' : 'bg-indigo-50'} flex items-center justify-center mb-3`}>
                                                    <svg className={`w-4 h-4 ${stat.color === 'blue' ? 'text-blue-600' : stat.color === 'green' ? 'text-green-600' : stat.color === 'orange' ? 'text-orange-600' : 'text-indigo-600'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={stat.icon}></path></svg>
                                                </div>
                                                <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">{stat.label}</p>
                                                <p className="text-xl font-black text-slate-900 mt-0.5">
                                                    {stat.isCurrency === false ? stat.value : `Γé╣${Number(stat.value || 0).toLocaleString('en-IN')}`}
                                                </p>
                                            </div>
                                        ))}
                                    </div>

                                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                                        {/* 1. Standard Fees (From Class Structure) */}
                                        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                                            <div className="px-5 py-4 border-b border-slate-50 flex items-center justify-between">
                                                <h4 className="font-bold text-slate-800 flex items-center gap-2">
                                                    <div className="w-1.5 h-1.5 bg-blue-600 rounded-full"></div>
                                                    Standard Class Fees
                                                </h4>
                                                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Recurring</span>
                                            </div>
                                            <div className="p-5">
                                                {!feeDetailsFull ? (
                                                    <p className="text-sm text-gray-400 italic">Finding fees...</p>
                                                ) : (
                                                    <div className="space-y-4">
                                                        <ul className="space-y-3">
                                                            {(feeDetailsFull.monthlyBreakdown?.find((m: any) => m.categoryBreakdown?.length > 0) || feeDetailsFull.monthlyBreakdown?.[0])?.categoryBreakdown?.map((cat: any, idx: number) => (
                                                                <li key={`std-${idx}`} className="flex justify-between items-center group">
                                                                    <div className="flex items-center gap-3">
                                                                        <div className="w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-600 transition-colors">
                                                                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"></path></svg>
                                                                        </div>
                                                                        <div>
                                                                            <span className="text-sm font-semibold text-slate-700">{cat.categoryName}</span>
                                                                            <span className="text-[10px] text-slate-400 block uppercase tracking-tight leading-none mt-0.5">{cat.frequency}</span>
                                                                        </div>
                                                                    </div>
                                                                    <span className="text-sm font-black text-slate-900 bg-slate-50 px-3 py-1 rounded-lg">Γé╣{Number(cat.amount).toLocaleString('en-IN')}</span>
                                                                </li>
                                                            ))}
                                                        </ul>
                                                    </div>
                                                )}
                                            </div>
                                        </div>

                                        {/* 2. Applied Optional/Other Fees */}
                                        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                                            <div className="px-5 py-4 border-b border-slate-50 flex items-center justify-between">
                                                <h4 className="font-bold text-slate-800 flex items-center gap-2">
                                                    <div className="w-1.5 h-1.5 bg-orange-600 rounded-full"></div>
                                                    Special/Opted Fees
                                                </h4>
                                                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Custom</span>
                                            </div>
                                            <div className="p-5">
                                                {feeDetailsOptionalFees.length === 0 ? (
                                                    <div className="flex flex-col items-center py-6">
                                                        <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center mb-3">
                                                            <svg className="w-6 h-6 text-slate-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                                                        </div>
                                                        <p className="text-xs text-slate-400 italic">No extra fees opted by student.</p>
                                                    </div>
                                                ) : (
                                                    <ul className="space-y-3">
                                                        {feeDetailsOptionalFees.map((fee: any) => (
                                                            <li key={fee.id} className="flex items-start justify-between p-3 rounded-xl bg-orange-50/50 border border-orange-100/50 hover:bg-orange-50 hover:border-orange-200 transition-all gap-3">
                                                                <div className="flex-1 min-w-0">
                                                                    <span className="font-bold text-sm text-slate-800 block truncate">{fee.feeCategory?.name || 'Category'}</span>
                                                                    <div className="flex items-center gap-2 mt-1">
                                                                        <span className="text-xs font-black text-orange-700">Γé╣{Number(fee.amount).toLocaleString('en-IN')}</span>
                                                                        <span className="text-[10px] text-orange-400 font-bold uppercase tracking-tighter">┬╖ {fee.frequency?.replace('_', ' ')}</span>
                                                                    </div>
                                                                </div>
                                                                {rbac.canConfigureFees && (
                                                                    <button
                                                                        onClick={() => handleRemoveOptionalFee(fee.id)}
                                                                        disabled={removingFeeId === fee.id}
                                                                        className="shrink-0 text-[10px] px-3 py-1.5 text-red-600 border border-red-200 bg-white rounded-lg hover:bg-red-50 transition-all font-black uppercase tracking-tighter shadow-sm"
                                                                    >
                                                                        {removingFeeId === fee.id ? 'Wait...' : 'Unlink'}
                                                                    </button>
                                                                )}
                                                            </li>
                                                        ))}
                                                    </ul>
                                                )}
                                            </div>
                                        </div>

                                        {/* 3. Applied Discounts */}
                                        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden lg:col-span-2">
                                            <div className="px-5 py-4 border-b border-slate-50 flex items-center justify-between">
                                                <h4 className="font-bold text-slate-800 flex items-center gap-2">
                                                    <div className="w-1.5 h-1.5 bg-green-600 rounded-full"></div>
                                                    Benefit Summary
                                                </h4>
                                                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Discounts</span>
                                            </div>
                                            <div className="p-5">
                                                {feeDetailsDiscounts.length === 0 ? (
                                                    <p className="text-sm text-slate-400 italic text-center py-4">No active scholarships or discounts assigned.</p>
                                                ) : (
                                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                                        {feeDetailsDiscounts.map((sd: any) => {
                                                            const calculatedSaving = feeDetailsFull?.monthlyBreakdown?.find((m: any) => m.baseFee > 0)?.appliedDiscounts?.find((d: any) => d.name === (sd.discountCategory?.name || sd.name))?.amount || 0;
                                                            return (
                                                                <div key={sd.id} className="flex items-center justify-between p-4 rounded-xl bg-green-50/50 border border-green-100/50">
                                                                    <div className="flex items-center gap-4">
                                                                        <div className="w-10 h-10 rounded-xl bg-green-100 flex items-center justify-center text-green-600">
                                                                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v13m0-13V6a2 2 0 112 2h-2zm0 0V5.5A2.5 2.5 0 109.5 8H12zm-7 4h14M5 12a2 2 0 110-4h14a2 2 0 110 4M5 12v7a2 2 0 002 2h10a2 2 0 002-2v-7"></path></svg>
                                                                        </div>
                                                                        <div>
                                                                            <span className="font-bold text-sm text-slate-800 block leading-tight">{sd.discountCategory?.name || 'Discount'}</span>
                                                                            <span className="text-[10px] text-green-600 font-black uppercase tracking-widest mt-0.5">
                                                                                {sd.discountCategory?.type === 'PERCENTAGE' ? `${sd.discountCategory.value}% Scholarship` : `Monthly Relief`}
                                                                            </span>
                                                                        </div>
                                                                    </div>
                                                                    <div className="text-right">
                                                                        <span className="text-lg font-black text-green-700">-{calculatedSaving > 0 ? `Γé╣${calculatedSaving}` : 'Γé╣0'}</span>
                                                                        <span className="block text-[10px] text-green-400 font-bold uppercase tracking-tighter">Savings / month</span>
                                                                    </div>
                                                                </div>
                                                            );
                                                        })}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            );
                        })()}
                </div>
            )}
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useForm, useWatch } from "react-hook-form";
import { toast } from "react-hot-toast";
import { authFetch } from "@/lib/auth";
import { API_BASE_URL } from "@/lib/api";
import { useRbac } from "@/lib/rbac";
import { useRouter } from "next/navigation";
import Link from "next/link";

type NotificationAudience = "PARENT" | "STAFF" | "ALL" | "CUSTOM";

export default function NewNotificationPage() {
  const { isSubAdmin, isAdmin, isSuperAdmin } = useRbac();
  const canSendNotifications = isSubAdmin || isAdmin || isSuperAdmin;
  const router = useRouter();

  // Custom Audience States
  const [classes, setClasses] = useState<any[]>([]);
  const [sections, setSections] = useState<any[]>([]);
  const [students, setStudents] = useState<any[]>([]);
  const [sessions, setSessions] = useState<any[]>([]);
  
  const [selectedSessionId, setSelectedSessionId] = useState<string>("");
  const [selectedClassId, setSelectedClassId] = useState<string>("");
  const [selectedSectionId, setSelectedSectionId] = useState<string>("");
  const [selectedStudentIds, setSelectedStudentIds] = useState<string[]>([]);
  
  const [isLoadingClasses, setIsLoadingClasses] = useState(false);
  const [isLoadingStudents, setIsLoadingStudents] = useState(false);

  const {
    register,
    handleSubmit,
    control,
    formState: { errors, isSubmitting }
  } = useForm<{ title: string; message: string; targetAudience: NotificationAudience }>({
    defaultValues: { title: "", message: "", targetAudience: "" as unknown as NotificationAudience }
  });

  const watchAudience = useWatch({ control, name: "targetAudience" });

  const fetchSessions = async () => {
    try {
      const res = await authFetch(`${API_BASE_URL}/academic-sessions`);
      if (res.ok) {
        const data = await res.json();
        setSessions(data);
        const active = data.find((s: any) => s.isActive);
        if (active) setSelectedSessionId(active.id.toString());
      }
    } catch (e) {
      console.error(e);
    }
  };

  const fetchClasses = async () => {
    setIsLoadingClasses(true);
    try {
      const res = await authFetch(`${API_BASE_URL}/classes`);
      if (res.ok) setClasses(await res.json());
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingClasses(false);
    }
  };

  const fetchSections = async (classId: string) => {
    try {
      const res = await authFetch(`${API_BASE_URL}/classes/${classId}/sections`);
      if (res.ok) setSections(await res.json());
    } catch (e) {
      console.error(e);
    }
  };

  const fetchStudents = async (sessionId: string, classId: string, sectionId?: string) => {
    if (!classId) return setStudents([]);
    setIsLoadingStudents(true);
    try {
      let url = `${API_BASE_URL}/students?classId=${classId}`;
      if (sessionId) url += `&academicSessionId=${sessionId}`;
      if (sectionId) url += `&sectionId=${sectionId}`;
      const res = await authFetch(url);
      if (res.ok) {
        const data = await res.json();
        setStudents(Array.isArray(data) ? data : data.data || []);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingStudents(false);
    }
  };

  useEffect(() => {
    if (canSendNotifications) {
      fetchSessions();
      fetchClasses();
    }
  }, [canSendNotifications]);

  useEffect(() => {
    if (watchAudience === "CUSTOM") {
      fetchStudents(selectedSessionId, selectedClassId, selectedSectionId);
    }
  }, [selectedSessionId, selectedClassId, selectedSectionId, watchAudience]);

  // Handle Session selection
  const handleSessionChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedSessionId(e.target.value);
    setSelectedStudentIds([]); // Reset students
  };

  // Handle Class selection
  const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const cid = e.target.value;
    setSelectedClassId(cid);
    setSelectedSectionId(""); // Reset section
    setSelectedStudentIds([]); // Reset students
    if (cid) {
      fetchSections(cid);
    } else {
      setSections([]);
    }
  };

  const toggleStudentSelection = (id: string) => {
    setSelectedStudentIds(prev => 
      prev.includes(id) ? prev.filter(s => s !== id) : [...prev, id]
    );
  };

  const onSubmit = async (data: { title: string; message: string; targetAudience: NotificationAudience }) => {
    if (data.targetAudience === "CUSTOM" && selectedStudentIds.length === 0) {
      toast.error("Please select at least one student for the custom audience.");
      return;
    }

    try {
      const payload: any = { ...data };
      if (data.targetAudience === "CUSTOM") {
        payload.targetUserIds = selectedStudentIds;
      }

      const res = await authFetch(`${API_BASE_URL}/api/app-notifications`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        toast.success("Notification sent successfully!");
        router.push('/dashboard/notifications');
      } else {
        const errorData = await res.json();
        toast.error(errorData.message || "Failed to send notification.");
      }
    } catch (error) {
      toast.error("An error occurred. Please try again.");
    }
  };

  if (!canSendNotifications) {
    return (
      <div className="p-4">
        <div className="bg-red-50 text-red-600 p-4 rounded-lg">You do not have permission to send notifications.</div>
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-6 lg:p-8 max-w-4xl mx-auto space-y-6">
      <div className="flex items-center gap-4">
        <Link href="/dashboard/notifications" className="p-2 bg-white border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-colors">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </Link>
        <div>
          <h1 className="text-2xl sm:text-3xl font-bold tracking-tight text-slate-900">Create Notification</h1>
          <p className="mt-1 text-sm text-slate-500">Draft a new message and select your target audience.</p>
        </div>
      </div>

      <div className="bg-white border text-card-foreground shadow-sm rounded-xl overflow-hidden p-6 sm:p-8">
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          
          <div className="space-y-1.5">
            <label className="text-sm font-semibold text-slate-900 w-full block">Notification Title</label>
            <input
              {...register("title", { required: "Title is required" })}
              className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all placeholder:text-slate-400"
              placeholder="e.g., Important Parent-Teacher Meeting"
            />
            {errors.title && <p className="text-red-500 text-sm mt-1">{errors.title.message}</p>}
          </div>

          <div className="space-y-1.5">
            <label className="text-sm font-semibold text-slate-900 w-full block">Message Overview</label>
            <textarea
              {...register("message", { required: "Message is required" })}
              className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all min-h-[120px] resize-y placeholder:text-slate-400"
              placeholder="Write the full message details here..."
            />
            {errors.message && <p className="text-red-500 text-sm mt-1">{errors.message.message}</p>}
          </div>

          <div className="space-y-1.5">
            <label className="text-sm font-semibold text-slate-900 w-full block">Target Audience</label>
            <select
              {...register("targetAudience", { required: "Please select an audience" })}
              className="w-full px-4 py-3 border border-slate-200 text-slate-700 bg-white rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
            >
              <option value="" disabled>-- Select an Audience --</option>
              <option value="ALL">All Users (Parents & Staff)</option>
              <option value="PARENT">All Parents</option>
              <option value="STAFF">All Staff Members</option>
              <option value="CUSTOM">Custom Selection (Targeted Students)</option>
            </select>
            {errors.targetAudience && <p className="text-red-500 text-sm mt-1">{errors.targetAudience.message}</p>}
          </div>

          {watchAudience === "CUSTOM" && (
            <div className="space-y-5 p-5 border border-amber-100 rounded-xl bg-amber-50/30">
              <h4 className="text-sm font-semibold text-slate-800 border-b border-slate-200 pb-2">Custom Audience Filter</h4>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="space-y-1.5">
                  <label className="text-xs font-medium text-slate-600">Academic Session</label>
                  <select
                    value={selectedSessionId}
                    onChange={handleSessionChange}
                    className="w-full px-3 py-2.5 border border-slate-200 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm font-medium"
                  >
                    {sessions.map(s => (
                      <option key={s.id} value={s.id}>{s.name} {s.isActive ? '(Active)' : ''}</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-1.5">
                  <label className="text-xs font-medium text-slate-600">Select Class</label>
                  <select
                    value={selectedClassId}
                    onChange={handleClassChange}
                    className="w-full px-3 py-2.5 border border-slate-200 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
                  >
                    <option value="">-- All Classes --</option>
                    {classes.map(c => (
                      <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                  </select>
                </div>
                
                <div className="space-y-1.5">
                  <label className="text-xs font-medium text-slate-600">Select Section (Optional)</label>
                  <select
                    value={selectedSectionId}
                    onChange={(e) => { setSelectedSectionId(e.target.value); setSelectedStudentIds([]); }}
                    disabled={!selectedClassId || sections.length === 0}
                    className="w-full px-3 py-2.5 border border-slate-200 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm disabled:opacity-50 disabled:bg-slate-50"
                  >
                    <option value="">-- All Sections --</option>
                    {sections.map(sec => (
                      <option key={sec.id} value={sec.id}>{sec.name}</option>
                    ))}
                  </select>
                </div>
              </div>
              
              {isLoadingStudents ? (
                <div className="py-8 text-center bg-white rounded-lg border border-slate-200 text-sm text-slate-500 flex items-center justify-center gap-2">
                   <div className="w-4 h-4 border-2 border-blue-500 border-t-white rounded-full animate-spin"></div> Loading students...
                </div>
              ) : students.length > 0 ? (
                <div className="space-y-3">
                   <div className="flex justify-between items-center bg-white px-4 py-3 rounded-lg border border-slate-200 shadow-sm">
                     <label className="flex items-center gap-3 cursor-pointer group">
                       <input 
                         type="checkbox" 
                         checked={students.length > 0 && selectedStudentIds.length === students.length}
                         onChange={(e) => {
                           if (e.target.checked) {
                             setSelectedStudentIds(students.map(s => s.id.toString()));
                           } else {
                             setSelectedStudentIds([]);
                           }
                         }}
                         className="w-4 h-4 text-blue-600 bg-slate-100 border-slate-300 rounded focus:ring-blue-500"
                       />
                       <span className="text-sm font-semibold text-slate-700 group-hover:text-blue-600 transition-colors">
                         Select All Students ({students.length})
                       </span>
                     </label>
                     <div className="flex items-center gap-3">
                       {selectedStudentIds.length > 0 && (
                         <button 
                           type="button" 
                           onClick={() => setSelectedStudentIds([])}
                           className="text-xs font-medium text-red-500 hover:text-red-700 transition-colors"
                         >
                           Clear Selection
                         </button>
                       )}
                       <div className="text-xs font-bold text-blue-600 bg-blue-50 px-2 py-1 rounded border border-blue-100">
                         {selectedStudentIds.length} Selected
                       </div>
                     </div>
                   </div>
                   
                   <div className="max-h-72 overflow-y-auto border border-slate-200 rounded-lg bg-white divide-y divide-slate-100 shadow-inner">
                     {students.map(s => (
                       <label key={s.id} className="flex items-center gap-4 p-3 hover:bg-blue-50/50 cursor-pointer transition-colors">
                         <input 
                           type="checkbox" 
                           checked={selectedStudentIds.includes(s.id.toString())}
                           onChange={() => toggleStudentSelection(s.id.toString())}
                           className="w-4 h-4 text-blue-600 bg-slate-100 border-slate-300 rounded focus:ring-blue-500 mt-0.5"
                         />
                         <div className="flex-1">
                           <p className="text-sm font-semibold text-slate-900">{s.firstName} {s.lastName}</p>
                           <p className="text-xs text-slate-500 font-medium">Class: {s.class?.name || 'N/A'}{s.section ? ` - ${s.section.name}` : ''} | Roll: {s.enrollments?.[0]?.rollNo || 'N/A'}</p>
                         </div>
                       </label>
                     ))}
                   </div>
                </div>
              ) : selectedClassId ? (
                <div className="py-8 text-center bg-white rounded-lg border border-slate-200 text-sm text-slate-500 shadow-sm">
                  No students found matching these filters.
                </div>
              ) : (
                <div className="py-8 text-center bg-white rounded-lg border border-slate-200 text-sm text-slate-500 shadow-sm">
                  Select a class to view students.
                </div>
              )}
            </div>
          )}

          <div className="pt-4 flex justify-end gap-3 border-t border-slate-100">
            <button
              type="submit"
              disabled={isSubmitting}
              className="px-8 py-3 text-sm font-semibold text-white bg-blue-600 hover:bg-blue-700 rounded-xl transition-all shadow-md hover:shadow-lg disabled:opacity-50 disabled:shadow-none flex items-center justify-center gap-2"
            >
              {isSubmitting ? (
                <>
                  <span className="w-4 h-4 rounded-full border-2 border-white/30 border-t-white animate-spin" />
                  Sending Broadcast...
                </>
              ) : "Send Broadcast Now"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { getUser, getToken, getRefreshToken, setTokens, removeToken, authFetch } from "@/lib/auth";
import { API_BASE_URL } from "@/lib/api";

type Session = {
    id: string;
    deviceInfo: string;
    ipAddress: string;
    lastActive: string;
    expiresAt: string;
    isCurrent?: boolean;
};

export default function ProfilePage() {
    const [user, setUser] = useState<any>(null);
    const [activeTab, setActiveTab] = useState<"general" | "security">("general");

    // Session State
    const [sessions, setSessions] = useState<Session[]>([]);
    const [loadingSessions, setLoadingSessions] = useState(false);

    // Password State
    const [currentPassword, setCurrentPassword] = useState("");
    const [newPassword, setNewPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [pwLoading, setPwLoading] = useState(false);
    const [pwError, setPwError] = useState("");
    const [pwSuccess, setPwSuccess] = useState("");
    const [showCurrent, setShowCurrent] = useState(false);
    const [showNew, setShowNew] = useState(false);

    useEffect(() => {
        const u = getUser();
        if (u) setUser(u);
    }, []);

    const fetchSessions = useCallback(async () => {
        setLoadingSessions(true);
        try {
            const refresh = getRefreshToken();
            const res = await authFetch(`${API_BASE_URL}/auth/sessions?currentRefreshToken=${refresh || ''}`);
            if (res.ok) {
                const data = await res.json();
                setSessions(data);
            }
        } catch (err) {
            console.error("Failed to fetch sessions", err);
        } finally {
            setLoadingSessions(false);
        }
    }, []);

    // Fetch sessions when switching to security tab
    useEffect(() => {
        if (activeTab === "security") {
            fetchSessions();
        }
    }, [activeTab, fetchSessions]);

    // PWA fix: re-fetch when user returns to the tab/app from background
    useEffect(() => {
        if (activeTab !== "security") return;
        const handleVisibility = () => {
            if (document.visibilityState === "visible") {
                fetchSessions();
            }
        };
        document.addEventListener("visibilitychange", handleVisibility);
        return () => document.removeEventListener("visibilitychange", handleVisibility);
    }, [activeTab, fetchSessions]);

    const handleChangePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setPwError("");
        setPwSuccess("");

        if (newPassword !== confirmPassword) {
            setPwError("New passwords do not match");
            return;
        }
        if (newPassword.length < 6) {
            setPwError("Password must be at least 6 characters");
            return;
        }
        if (newPassword === currentPassword) {
            setPwError("New password must be different from current password");
            return;
        }

        setPwLoading(true);
        try {
            const res = await authFetch(`${API_BASE_URL}/auth/change-password`, {
                method: "POST",
                body: JSON.stringify({ currentPassword, newPassword }),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.message || "Failed to change password");

            if (data.refresh_token) {
                setTokens(data.access_token, data.refresh_token);
            }

            setPwSuccess("Password changed successfully!");
            setCurrentPassword("");
            setNewPassword("");
            setConfirmPassword("");
        } catch (err: any) {
            setPwError(err.message || "Failed to change password");
        } finally {
            setPwLoading(false);
        }
    };

    const handleLogoutDevice = async (sessionId: string) => {
        try {
            const res = await authFetch(`${API_BASE_URL}/auth/logout-device/${sessionId}`, {
                method: "POST",
            });
            if (res.ok) {
                setSessions(sessions.filter(s => s.id !== sessionId));
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleLogoutAll = async () => {
        try {
            const res = await authFetch(`${API_BASE_URL}/auth/logout-all`, {
                method: "POST",
            });
            if (res.ok) {
                // Clear local tokens immediately so this device is logged out right away
                removeToken();
                window.location.href = "/";
            }
        } catch (err) {
            console.error(err);
        }
    };


    if (!user) return null;

    return (
        <div className="max-w-4xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
            <h1 className="text-2xl font-bold text-slate-900 mb-6">My Profile</h1>

            {/* Tabs */}
            <div className="bg-slate-100 border border-slate-200 rounded-2xl p-1.5 flex gap-1.5 mb-6">
                <button
                    onClick={() => setActiveTab("general")}
                    className={`flex-1 flex items-center justify-center gap-2 py-2.5 px-4 rounded-xl text-sm font-semibold transition-all duration-200 ${activeTab === "general"
                        ? "bg-white shadow text-indigo-600 border border-slate-200"
                        : "text-slate-500 hover:text-slate-700"
                    }`}
                >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                    </svg>
                    General Information
                </button>
                <button
                    onClick={() => setActiveTab("security")}
                    className={`flex-1 flex items-center justify-center gap-2 py-2.5 px-4 rounded-xl text-sm font-semibold transition-all duration-200 ${activeTab === "security"
                        ? "bg-white shadow text-indigo-600 border border-slate-200"
                        : "text-slate-500 hover:text-slate-700"
                    }`}
                >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                    </svg>
                    Security &amp; Login
                </button>
            </div>

            {/* General Tab */}
            {activeTab === "general" && (
                <div className="bg-white shadow rounded-xl p-6 border border-slate-100">
                    <div className="flex items-center gap-6 mb-8">
                        <div className="h-24 w-24 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white text-3xl font-bold shadow-lg">
                            {user.firstName[0]}{user.lastName[0]}
                        </div>
                        <div>
                            <h2 className="text-2xl font-bold text-slate-900">{user.firstName} {user.lastName}</h2>
                            <p className="text-slate-500 font-medium">{user.role?.replace("_", " ")}</p>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-sm font-medium text-slate-500 mb-1">First Name</label>
                            <div className="px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-slate-900 min-h-[44px]">
                                {user.firstName || '\u00A0'}
                            </div>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-500 mb-1">Last Name</label>
                            <div className="px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-slate-900 min-h-[44px]">
                                {user.lastName || '\u00A0'}
                            </div>
                        </div>
                        {user.email && (
                            <div className="sm:col-span-2">
                                <label className="block text-sm font-medium text-slate-500 mb-1">Email Address</label>
                                <div className="px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-slate-900">
                                    {user.email}
                                </div>
                            </div>
                        )}
                        {user.mobile && (
                            <div className="sm:col-span-2">
                                <label className="block text-sm font-medium text-slate-500 mb-1">Mobile Number</label>
                                <div className="px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-slate-900">
                                    +91 {user.mobile}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Security Tab */}
            {activeTab === "security" && (
                <div className="space-y-6">
                    {/* Change Password Block */}
                    <div className="bg-white shadow rounded-xl p-6 border border-slate-100">
                        <h3 className="text-lg font-bold text-slate-900 mb-1">Change Password</h3>
                        <p className="text-sm text-slate-500 mb-6">Update your account password to stay secure.</p>

                        <form onSubmit={handleChangePassword} className="space-y-4 max-w-md">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1.5">Current Password</label>
                                <div className="relative">
                                    <input
                                        type={showCurrent ? "text" : "password"}
                                        value={currentPassword}
                                        onChange={e => setCurrentPassword(e.target.value)}
                                        required
                                        className="w-full bg-slate-50 border border-slate-300 text-slate-900 rounded-lg px-4 py-2 pr-10 focus:ring-2 focus:ring-indigo-500 outline-none"
                                    />
                                    <button type="button" onClick={() => setShowCurrent(!showCurrent)} className="absolute right-3 top-2.5 text-slate-400">
                                        ≡ƒæü∩╕ÅΓÇì≡ƒù¿∩╕Å
                                    </button>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1.5">New Password</label>
                                <div className="relative">
                                    <input
                                        type={showNew ? "text" : "password"}
                                        value={newPassword}
                                        onChange={e => setNewPassword(e.target.value)}
                                        required minLength={6}
                                        className="w-full bg-slate-50 border border-slate-300 text-slate-900 rounded-lg px-4 py-2 pr-10 focus:ring-2 focus:ring-indigo-500 outline-none"
                                    />
                                    <button type="button" onClick={() => setShowNew(!showNew)} className="absolute right-3 top-2.5 text-slate-400">
                                        ≡ƒæü∩╕ÅΓÇì≡ƒù¿∩╕Å
                                    </button>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1.5">Confirm Password</label>
                                <input
                                    type="password"
                                    value={confirmPassword}
                                    onChange={e => setConfirmPassword(e.target.value)}
                                    required
                                    className="w-full bg-slate-50 border border-slate-300 text-slate-900 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                                />
                            </div>

                            {pwError && <div className="text-sm text-red-600 bg-red-50 p-3 rounded-lg border border-red-100">{pwError}</div>}
                            {pwSuccess && <div className="text-sm text-green-600 bg-green-50 p-3 rounded-lg border border-green-100">{pwSuccess}</div>}

                            <button
                                type="submit"
                                disabled={pwLoading}
                                className="px-5 py-2.5 bg-indigo-600 text-white font-medium rounded-lg hover:bg-indigo-700 disabled:opacity-50 transition-colors"
                            >
                                {pwLoading ? "Updating..." : "Update Password"}
                            </button>
                        </form>
                    </div>

                    {/* Active Sessions Block */}
                    <div className="bg-white shadow rounded-xl border border-slate-100 overflow-hidden">
                        <div className="p-6 border-b border-slate-100">
                            <h3 className="text-lg font-bold text-slate-900 mb-1">Active Sessions</h3>
                            <p className="text-sm text-slate-500">You're currently logged in on these devices. If you don't recognize a device, log out of it immediately.</p>
                        </div>

                        {loadingSessions ? (
                            <div className="p-6 text-center text-slate-500">Loading sessions...</div>
                        ) : (
                            <ul className="divide-y divide-slate-100">
                                {sessions.map((session) => {
                                    const isCurrent = !!session.isCurrent;
                                    return (
                                        <li key={session.id} className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4 hover:bg-slate-50/50 transition-colors">
                                            <div className="flex items-start gap-4">
                                                <div className="p-3 bg-indigo-50 text-indigo-600 rounded-xl">
                                                    {session.deviceInfo?.toLowerCase().includes("mobile") || session.deviceInfo?.toLowerCase().includes("android") || session.deviceInfo?.toLowerCase().includes("iphone") ? '≡ƒô▒' : '≡ƒÆ╗'}
                                                </div>
                                                <div>
                                                    <p className="font-semibold text-slate-900 flex items-center gap-2">
                                                        {session.deviceInfo || "Unknown Device"}
                                                        {isCurrent && <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-green-100 text-green-700 uppercase tracking-wide">Current</span>}
                                                    </p>
                                                    <div className="text-sm text-slate-500 mt-1 space-y-0.5">
                                                        <p>IP: {session.ipAddress || "Unknown"}</p>
                                                        <p>Last active: {new Date(session.lastActive).toLocaleString()}</p>
                                                    </div>
                                                </div>
                                            </div>
                                            {!isCurrent && (
                                                <button
                                                    onClick={() => handleLogoutDevice(session.id)}
                                                    className="px-4 py-2 text-sm font-medium text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors whitespace-nowrap self-start sm:self-center"
                                                >
                                                    Log Out
                                                </button>
                                            )}
                                        </li>
                                    );
                                })}
                            </ul>
                        )}

                        <div className="p-6 bg-red-50/50 border-t border-red-100">
                            <h4 className="text-red-800 font-semibold mb-2">Logout capability</h4>
                            <p className="text-sm text-red-600/80 mb-4">
                                If you lost your device or notice suspicious activity, you can log out of all devices immediately. You will need to log back in on this device.
                            </p>
                            <button
                                onClick={handleLogoutAll}
                                className="px-5 py-2.5 bg-red-600 hover:bg-red-700 text-white font-medium rounded-lg transition-colors shadow-sm"
                            >
                                Log out of all devices
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import toast, { Toaster } from "react-hot-toast";
import { useRbac } from "@/lib/rbac";
import { useRouter } from "next/navigation";
import { API_BASE_URL } from "@/lib/api";
import { authFetch } from "@/lib/auth";
import { 
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
    PieChart, Pie, Cell, LineChart, Line 
} from 'recharts';
import { Wallet, AlertCircle, ClipboardList, CalendarCheck, Users, UserCircle, Download } from "lucide-react";

const COLORS = ['#0ea5e9', '#f43f5e', '#10b981', '#f59e0b', '#8b5cf6', '#64748b'];

export default function ReportsDashboard() {
    const router = useRouter();
    const rbac = useRbac();
    const [mounted, setMounted] = useState(false);
    const [activeTab, setActiveTab] = useState<'FEES' | 'PENDING_DUES' | 'FEE_RECEIVED' | 'EXAMINATIONS' | 'ATTENDANCE' | 'STUDENTS' | 'STAFF'>('FEES');

    // FILTERS
    const [academicSessions, setAcademicSessions] = useState<any[]>([]);
    const [examTerms, setExamTerms] = useState<any[]>([]);

    const [feeCollectionSession, setFeeCollectionSession] = useState('');
    const [collectionStatusSession, setCollectionStatusSession] = useState('');
    const [collectionPendingMonth, setCollectionPendingMonth] = useState((new Date().getMonth() + 1).toString());
    const [feeAdjustmentsFromDate, setFeeAdjustmentsFromDate] = useState(new Date().toISOString().split('T')[0]);
    const [feeAdjustmentsToDate, setFeeAdjustmentsToDate] = useState(new Date().toISOString().split('T')[0]);
    const [waivedOffTrendSession, setWaivedOffTrendSession] = useState('');

    const [selectedExamYear, setSelectedExamYear] = useState('');
    const [selectedExamTerm, setSelectedExamTerm] = useState('');
    const [selectedExamClass, setSelectedExamClass] = useState('');
    const [classes, setClasses] = useState<any[]>([]);
    const [availableSections, setAvailableSections] = useState<any[]>([]);
    const [selectedExamSection, setSelectedExamSection] = useState('');

    const [attendanceSession, setAttendanceSession] = useState('');
    const [attendanceMonth, setAttendanceMonth] = useState((new Date().getMonth() + 1).toString());
    const [attendanceFromDate, setAttendanceFromDate] = useState(new Date().toISOString().split('T')[0]);
    const [attendanceToDate, setAttendanceToDate] = useState(new Date().toISOString().split('T')[0]);

    const [enrollmentFromSession, setEnrollmentFromSession] = useState('');
    const [admissionsFromSession, setAdmissionsFromSession] = useState('');
    const [admissionsToSession, setAdmissionsToSession] = useState('');

    // Pending Dues Filters
    const [pendingSessionId, setPendingSessionId] = useState('');
    
    // Pending Dues Notification State
    const [showNotifModal, setShowNotifModal] = useState(false);
    const [useCustomMessage, setUseCustomMessage] = useState(false);
    const [customNotifMessage, setCustomNotifMessage] = useState('');
    const [sendingNotif, setSendingNotif] = useState(false);
    const [pendingClassId, setPendingClassId] = useState('');
    const [pendingAvailableSections, setPendingAvailableSections] = useState<any[]>([]);
    const [pendingSectionId, setPendingSectionId] = useState('');
    const [pendingSearchQuery, setPendingSearchQuery] = useState('');
    const [pendingMobile, setPendingMobile] = useState('');
    const [pendingMonth, setPendingMonth] = useState('');
    const [pendingDuesData, setPendingDuesData] = useState<any[]>([]);
    const [pendingDuesLoading, setPendingDuesLoading] = useState(false);
    const [pendingSortColumn, setPendingSortColumn] = useState<string>('className');
    const [pendingSortDirection, setPendingSortDirection] = useState<'asc' | 'desc'>('asc');
    const [selectedPendingStudents, setSelectedPendingStudents] = useState<number[]>([]);
    const [pendingHasSearched, setPendingHasSearched] = useState(false);

    // Pagination for pending dues
    const [pendingDuesPage, setPendingDuesPage] = useState(1);
    const PENDING_DUES_PER_PAGE = 20;

    // Pagination for adjustments
    const [feeAdjPage, setFeeAdjPage] = useState(1);
    const FEE_ADJ_PER_PAGE = 10;

    // Fee Received Filters
    const [receivedSessionId, setReceivedSessionId] = useState('');
    const [receivedFromDate, setReceivedFromDate] = useState('');
    const [receivedToDate, setReceivedToDate] = useState('');
    const [receivedClassId, setReceivedClassId] = useState('');
    const [receivedAvailableSections, setReceivedAvailableSections] = useState<any[]>([]);
    const [receivedSectionId, setReceivedSectionId] = useState('');
    const [receivedSearchQuery, setReceivedSearchQuery] = useState('');
    const [receivedMobile, setReceivedMobile] = useState('');
    const [receivedData, setReceivedData] = useState<any[]>([]);
    const [receivedLoading, setReceivedLoading] = useState(false);
    
    const [receivedHasSearched, setReceivedHasSearched] = useState(false);

    // Pagination for fee received
    const [receivedPage, setReceivedPage] = useState(1);
    const [receivedTotalCount, setReceivedTotalCount] = useState(0);
    const RECEIVED_PER_PAGE = 20;

    // DATA STATES
    const [monthlyCollection, setMonthlyCollection] = useState<any[]>([]);
    const [collectionStatus, setCollectionStatus] = useState<any[]>([]);
    const [feeAdjustments, setFeeAdjustments] = useState<any[]>([]);
    const [waivedOffTrend, setWaivedOffTrend] = useState([]);
    const [examClassAvg, setExamClassAvg] = useState([]);
    const [topPerformers, setTopPerformers] = useState<any[]>([]);
    const [attendanceByClass, setAttendanceByClass] = useState([]);
    const [attendanceTrend, setAttendanceTrend] = useState([]);
    const [staffDistribution, setStaffDistribution] = useState([]);
    const [enrollmentClass, setEnrollmentClass] = useState([]);
    const [admissionsTrend, setAdmissionsTrend] = useState([]);

    useEffect(() => {
        const fetchFiltersData = async () => {
            try {
                const [sessionsRes, examsRes, classesRes] = await Promise.all([
                    authFetch(`${API_BASE_URL}/academic-sessions`),
                    authFetch(`${API_BASE_URL}/exams/categories/active`),
                    authFetch(`${API_BASE_URL}/classes`)
                ]);

                if (classesRes.ok) {
                    const data = await classesRes.json();
                    setClasses(data);
                }

                if (sessionsRes.ok) {
                    const data = await sessionsRes.json();
                    setAcademicSessions(data);
                    const activeSession = data.find((s: any) => s.isActive);
                    if (activeSession) {
                        const sid = activeSession.id.toString();
                        setFeeCollectionSession(sid);
                        setCollectionStatusSession(sid);
                        setWaivedOffTrendSession(sid);
                        setSelectedExamYear(sid);
                        setAttendanceSession(sid);
                        setEnrollmentFromSession(sid);
                        setPendingSessionId(sid);
                        setReceivedSessionId(sid);
                        setAdmissionsToSession(sid);
                        if (data.length > 3) setAdmissionsFromSession(data[3].id.toString());
                        else if (data.length > 0) setAdmissionsFromSession(data[data.length - 1].id.toString());
                    }
                }
                if (examsRes.ok) {
                    const data = await examsRes.json();
                    setExamTerms(data);
                    if (data.length > 0) setSelectedExamTerm(data[0].id.toString());
                }
            } catch (err) {
                console.error("Failed to fetch filters data", err);
            }
        };
        fetchFiltersData();
    }, []);

    // FEES
    useEffect(() => {
        if (activeTab !== 'FEES') return;
        const fetchData = async () => {
            try {
                const currentMonth = new Date().getMonth() + 1;
                const acYearName = academicSessions.find(s => s.id.toString() === collectionStatusSession)?.name || '';
                
                const [mcRes, csRes, faRes, wotRes, pdRes] = await Promise.all([
                    authFetch(`${API_BASE_URL}/dashboard/reports/monthly-collection?sessionId=${feeCollectionSession}`),
                    authFetch(`${API_BASE_URL}/dashboard/reports/collection-status?sessionId=${collectionStatusSession}&month=${currentMonth}`),
                    authFetch(`${API_BASE_URL}/dashboard/reports/fee-adjustments?fromDate=${feeAdjustmentsFromDate}&toDate=${feeAdjustmentsToDate}`),
                    authFetch(`${API_BASE_URL}/dashboard/reports/waived-off-trend?sessionId=${waivedOffTrendSession}`),
                    // Only fetch pending dues if we have the academic year
                    acYearName ? authFetch(`${API_BASE_URL}/fees/reports/pending-dues?academicYear=${encodeURIComponent(acYearName)}`) : Promise.resolve(null)
                ]);
                if (mcRes.ok) setMonthlyCollection(await mcRes.json());
                
                if (csRes.ok) {
                    const statusData = await csRes.json();
                    let totalPending = 0;
                    
                    if (pdRes && pdRes.ok) {
                        const pendingData = await pdRes.json();
                        totalPending = pendingData.reduce((sum: number, row: any) => sum + (Number(row.pendingAmount) || 0), 0);
                    } else {
                        // Fallback to the mocked pending dues if real calculation fails
                        totalPending = statusData.find((d: any) => d.name === 'Pending Dues')?.value || 0;
                    }
                    
                    const collectedAmount = statusData.find((d: any) => d.name === 'Collected')?.value || 0;
                    
                    setCollectionStatus([
                        { name: 'Collected', value: collectedAmount },
                        { name: 'Pending Dues', value: totalPending }
                    ]);
                }

                if (faRes.ok) setFeeAdjustments(await faRes.json());
                if (wotRes.ok) setWaivedOffTrend(await wotRes.json());
            } catch (e) { console.error(e); }
        };
        fetchData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeTab, feeCollectionSession, collectionStatusSession, feeAdjustmentsFromDate, feeAdjustmentsToDate, waivedOffTrendSession, academicSessions]);

    // EXAMS
    useEffect(() => {
        if (activeTab !== 'EXAMINATIONS') return;
        const fetchData = async () => {
            try {
                let query = `?sessionId=${selectedExamYear}&termId=${selectedExamTerm}`;
                if (selectedExamClass) query += `&classId=${selectedExamClass}`;
                if (selectedExamSection) query += `&sectionId=${selectedExamSection}`;
                const [ecaRes, tpRes] = await Promise.all([
                    authFetch(`${API_BASE_URL}/dashboard/reports/exam-class-average${query}`),
                    authFetch(`${API_BASE_URL}/dashboard/reports/top-performers${query}`)
                ]);
                if (ecaRes.ok) setExamClassAvg(await ecaRes.json());
                if (tpRes.ok) setTopPerformers(await tpRes.json());
            } catch (e) { console.error(e); }
        };
        fetchData();
    }, [activeTab, selectedExamYear, selectedExamTerm, selectedExamClass, selectedExamSection]);

    // ATTENDANCE
    useEffect(() => {
        if (activeTab !== 'ATTENDANCE') return;
        const fetchData = async () => {
            try {
                const [abcRes, atRes] = await Promise.all([
                    authFetch(`${API_BASE_URL}/dashboard/reports/attendance-by-class?sessionId=${attendanceSession}&month=${attendanceMonth}`),
                    authFetch(`${API_BASE_URL}/dashboard/reports/attendance-trend?fromDate=${attendanceFromDate}&toDate=${attendanceToDate}`)
                ]);
                if (abcRes.ok) setAttendanceByClass(await abcRes.json());
                if (atRes.ok) setAttendanceTrend(await atRes.json());
            } catch (e) { console.error(e); }
        };
        fetchData();
    }, [activeTab, attendanceSession, attendanceMonth, attendanceFromDate, attendanceToDate]);

    // STUDENTS
    useEffect(() => {
        if (activeTab !== 'STUDENTS') return;
        const fetchData = async () => {
            try {
                const [ecRes, atRes] = await Promise.all([
                    authFetch(`${API_BASE_URL}/dashboard/reports/enrollment-by-class?sessionId=${enrollmentFromSession}`),
                    authFetch(`${API_BASE_URL}/dashboard/reports/admissions-trend?fromSessionId=${admissionsFromSession}&toSessionId=${admissionsToSession}`)
                ]);
                if (ecRes.ok) setEnrollmentClass(await ecRes.json());
                if (atRes.ok) setAdmissionsTrend(await atRes.json());
            } catch (e) { console.error(e); }
        };
        fetchData();
    }, [activeTab, enrollmentFromSession, admissionsFromSession, admissionsToSession]);

    // STAFF
    useEffect(() => {
        if (activeTab !== 'STAFF') return;
        const fetchData = async () => {
            try {
                const res = await authFetch(`${API_BASE_URL}/dashboard/reports/staff-distribution`);
                if (res.ok) setStaffDistribution(await res.json());
            } catch (e) { console.error(e); }
        };
        fetchData();
    }, [activeTab]);

    // PENDING DUES - manual fetch (triggered by Apply Filters button)
    const fetchPendingDues = async () => {
        if (!pendingSessionId) {
            toast.error('Please select an academic session');
            return;
        }
        setPendingDuesLoading(true);
        setPendingHasSearched(true);
        setPendingDuesPage(1);
        setSelectedPendingStudents([]);
        try {
            let query = `?academicYear=${encodeURIComponent(
                academicSessions.find(s => s.id.toString() === pendingSessionId)?.name || ''
            )}`;
            if (pendingClassId) query += `&classId=${pendingClassId}`;
            if (pendingSectionId) query += `&sectionId=${pendingSectionId}`;
            if (pendingMobile) query += `&mobileNumber=${pendingMobile}`;
            if (pendingMonth) query += `&month=${pendingMonth}`;

            const res = await authFetch(`${API_BASE_URL}/fees/reports/pending-dues${query}`);
            if (res.ok) {
                const data = await res.json();
                setPendingDuesData(data);
            } else {
                toast.error('Failed to fetch pending dues data');
            }
        } catch (e) {
            console.error(e);
            toast.error('An error occurred while fetching pending dues data');
        } finally {
            setPendingDuesLoading(false);
        }
    };

    // FEE RECEIVED - manual fetch (triggered by Apply Filters button)
    const fetchFeeReceived = async (pageOverride?: number) => {
        if (!receivedSessionId) {
            toast.error('Please select an academic session');
            return;
        }
        const page = pageOverride ?? receivedPage;
        setReceivedLoading(true);
        if (!pageOverride) {
            setReceivedHasSearched(true);
            setReceivedPage(1);
        }
        try {
            let query = `?academicYear=${encodeURIComponent(
                academicSessions.find(s => s.id.toString() === receivedSessionId)?.name || ''
            )}`;
            if (receivedClassId) query += `&classId=${receivedClassId}`;
            if (receivedSectionId) query += `&sectionId=${receivedSectionId}`;
            if (receivedMobile) query += `&mobileNumber=${receivedMobile}`;
            if (receivedFromDate) query += `&fromDate=${receivedFromDate}`;
            if (receivedToDate) query += `&toDate=${receivedToDate}`;
            if (receivedSearchQuery && !isNaN(Number(receivedSearchQuery))) query += `&studentId=${receivedSearchQuery}`;

            query += `&page=${pageOverride ?? 1}&limit=${RECEIVED_PER_PAGE}`;

            const res = await authFetch(`${API_BASE_URL}/fees/reports/fee-received${query}`);
            if (res.ok) {
                const data = await res.json();
                setReceivedData(data.data || []);
                setReceivedTotalCount(data.totalCount || 0);
                if (!pageOverride) setReceivedPage(1);
            } else {
                toast.error('Failed to fetch fee received data');
            }
        } catch (e) {
            console.error(e);
            toast.error('An error occurred while fetching fee received data');
        } finally {
            setReceivedLoading(false);
        }
    };

    // Sorting Helper for Pending Dues
    const handlePendingSort = (column: string) => {
        if (pendingSortColumn === column) {
            setPendingSortDirection(pendingSortDirection === 'asc' ? 'desc' : 'asc');
        } else {
            setPendingSortColumn(column);
            setPendingSortDirection('asc');
        }
    };

    const sortedPendingDues = [...pendingDuesData].sort((a, b) => {
        let valA = a[pendingSortColumn];
        let valB = b[pendingSortColumn];
        
        if (typeof valA === 'string') valA = valA.toLowerCase();
        if (typeof valB === 'string') valB = valB.toLowerCase();
        
        if (valA < valB) return pendingSortDirection === 'asc' ? -1 : 1;
        if (valA > valB) return pendingSortDirection === 'asc' ? 1 : -1;
        return 0;
    });

    // Client-side filtering for student name and ID
    const displayedPendingDuesAll = sortedPendingDues.filter(row => {
        if (!pendingSearchQuery) return true;
        const q = pendingSearchQuery.toLowerCase();
        const fullName = `${row.firstName || ''} ${row.lastName || ''}`.toLowerCase();
        return fullName.includes(q) || row.studentId.toString().includes(q) || (row.rollNo && row.rollNo.toString().includes(q));
    });
    
    // Pagination logic
    const totalPendingPages = Math.ceil(displayedPendingDuesAll.length / PENDING_DUES_PER_PAGE);
    const paginatedPendingDues = displayedPendingDuesAll.slice(
        (pendingDuesPage - 1) * PENDING_DUES_PER_PAGE,
        pendingDuesPage * PENDING_DUES_PER_PAGE
    );

    const exportToCSV = () => {
        if (displayedPendingDuesAll.length === 0) {
            toast.error('No data to export');
            return;
        }

        const headers = ['Student ID', 'Roll No', 'First Name', 'Last Name', 'Mobile', 'Class', 'Section', 'Pending Amount'];
        const rows = displayedPendingDuesAll.map(row => [
            row.studentId,
            row.rollNo || '',
            `"${row.firstName || ''}"`,
            `"${row.lastName || ''}"`,
            `"${row.mobile || ''}"`,
            `"${row.className || ''}"`,
            `"${row.sectionName || ''}"`,
            row.pendingAmount
        ]);

        const csvContent = [
            headers.join(','),
            ...rows.map(e => e.join(','))
        ].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `Pending_Dues_Report_${new Date().toISOString().split('T')[0]}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const exportFeeReceivedCSV = async () => {
        if (!receivedSessionId) return;
        setReceivedLoading(true);
        try {
            let query = `?academicYear=${encodeURIComponent(
                academicSessions.find(s => s.id.toString() === receivedSessionId)?.name || ''
            )}`;
            if (receivedClassId) query += `&classId=${receivedClassId}`;
            if (receivedSectionId) query += `&sectionId=${receivedSectionId}`;
            if (receivedMobile) query += `&mobileNumber=${receivedMobile}`;
            if (receivedFromDate) query += `&fromDate=${receivedFromDate}`;
            if (receivedToDate) query += `&toDate=${receivedToDate}`;
            if (receivedSearchQuery && !isNaN(Number(receivedSearchQuery))) query += `&studentId=${receivedSearchQuery}`;
            
            // Limit 0 indicates we want to fetch the whole set matching filters
            query += `&page=1&limit=0`;

            const res = await authFetch(`${API_BASE_URL}/fees/reports/fee-received${query}`);
            if (res.ok) {
                const json = await res.json();
                const bulkData = json.data || [];
                
                if (bulkData.length === 0) {
                    toast.error('No data to export');
                    return;
                }

                const headers = ['Receipt No', 'Payment Date', 'Student ID', 'First Name', 'Last Name', 'Mobile', 'Class', 'Section', 'Payment Method', 'Fee Month(s)', 'Amount Paid', 'Collected By'];
                const rows = bulkData.map((row: any) => [
                    `"${row.receiptNumber || ''}"`,
                    row.paymentDate,
                    row.studentId,
                    `"${row.firstName || ''}"`,
                    `"${row.lastName || ''}"`,
                    `"${row.mobile || ''}"`,
                    `"${row.className || ''}"`,
                    `"${row.sectionName || ''}"`,
                    row.paymentMethod || '',
                    `"${row.feeMonth || ''}"`,
                    row.amountPaid,
                    `"${row.collectedBy || ''}"`
                ]);

                const csvContent = [headers.join(','), ...rows.map((e: any[]) => e.join(','))].join('\n');
                const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement("a");
                link.setAttribute("href", url);
                link.setAttribute("download", `Fee_Received_Report_${new Date().toISOString().split('T')[0]}.csv`);
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
            } else {
                toast.error('Failed to export bulk fee received data');
            }
        } catch (e) {
            console.error(e);
            toast.error('Failed to export fee received data');
        } finally {
            setReceivedLoading(false);
        }
    };

    const handleSendNotification = async () => {
        if (selectedPendingStudents.length === 0) return;
        
        setSendingNotif(true);
        try {
            const defaultMsg = "Dear Parent, this is a reminder that your ward has pending school fee dues. Kindly clear the outstanding amount at the earliest to avoid any inconvenience. Thank you.";
            const message = useCustomMessage ? customNotifMessage : defaultMsg;
            const targetUserIds = selectedPendingStudents.map(id => id.toString());
            
            const payload = {
                title: "Fee Payment Reminder",
                message,
                targetAudience: "CUSTOM",
                targetUserIds
            };

            const res = await authFetch(`${API_BASE_URL}/api/app-notifications`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload)
            });

            if (res.ok) {
                toast.success('Notification sent successfully!');
                setShowNotifModal(false);
                setUseCustomMessage(false);
                setCustomNotifMessage('');
            } else {
                const errData = await res.json();
                toast.error(errData.message || 'Failed to send notification');
            }
        } catch (e) {
            console.error("Notification Error:", e);
            toast.error('An error occurred while sending notification');
        } finally {
            setSendingNotif(false);
        }
    };

    useEffect(() => {
        if (mounted && !rbac.isAdmin) {
            toast.error("You don't have permission to access Reports.");
            router.replace('/dashboard');
        }
    }, [mounted, rbac.isAdmin, router]);

    useEffect(() => {
        setMounted(true);
    }, []);

    if (!mounted) {
        return (
            <div className="p-8 flex justify-center items-center h-full">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    return (
        <main className="p-4 flex-1 h-full overflow-y-auto w-full max-w-7xl mx-auto">
            <Toaster position="top-right" />
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-3xl font-bold text-slate-800">Reports Dashboard</h1>
            </div>

            {/* TABS */}
            <div className="flex p-1 bg-slate-100 rounded-xl mb-6 w-full md:w-fit shadow-inner border border-slate-200/60 overflow-x-auto">
                <button
                    onClick={() => setActiveTab('FEES')}
                    className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                        activeTab === 'FEES'
                            ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                            : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                    }`}
                >
                    <Wallet className="w-4 h-4" />
                    Fees & Revenue
                </button>
                <button
                    onClick={() => setActiveTab('FEE_RECEIVED')}
                    className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                        activeTab === 'FEE_RECEIVED'
                            ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                            : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                    }`}
                >
                    <ClipboardList className="w-4 h-4" />
                    Fee Received
                </button>
                <button
                    onClick={() => setActiveTab('PENDING_DUES')}
                    className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                        activeTab === 'PENDING_DUES'
                            ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                            : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                    }`}
                >
                    <AlertCircle className="w-4 h-4" />
                    Pending Dues
                </button>
                <button
                    onClick={() => setActiveTab('EXAMINATIONS')}
                    className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                        activeTab === 'EXAMINATIONS'
                            ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                            : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                    }`}
                >
                    <ClipboardList className="w-4 h-4" />
                    Examinations
                </button>
                <button
                    onClick={() => setActiveTab('ATTENDANCE')}
                    className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                        activeTab === 'ATTENDANCE'
                            ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                            : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                    }`}
                >
                    <CalendarCheck className="w-4 h-4" />
                    Attendance
                </button>
                <button
                    onClick={() => setActiveTab('STUDENTS')}
                    className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                        activeTab === 'STUDENTS'
                            ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                            : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                    }`}
                >
                    <Users className="w-4 h-4" />
                    Students
                </button>
                <button
                    onClick={() => setActiveTab('STAFF')}
                    className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                        activeTab === 'STAFF'
                            ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                            : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                    }`}
                >
                    <UserCircle className="w-4 h-4" />
                    Staff
                </button>
            </div>

            {/* TAB CONTENT: FEES */}
            {activeTab === 'FEES' && (
                <div className="space-y-6">
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        {/* Monthly Collection Chart */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <div className="flex justify-between items-center mb-4">
                                <h2 className="text-lg font-bold text-slate-800">Monthly Fee Collection Trend</h2>
                                <select 
                                    className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                    value={feeCollectionSession}
                                    onChange={(e) => setFeeCollectionSession(e.target.value)}
                                >
                                    <option value="">Select Session</option>
                                    {academicSessions.map(session => (
                                        <option key={session.id} value={session.id.toString()}>{session.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div className="h-72">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={monthlyCollection}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                                        <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748B'}} tickFormatter={(val) => `Γé╣${val/1000}k`} />
                                        <Tooltip formatter={(val: any) => `Γé╣${val.toLocaleString()}`} cursor={{fill: '#F1F5F9'}} />
                                        <Legend />
                                        <Bar dataKey="collected" name="Collected" fill="#0ea5e9" radius={[4,4,0,0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        {/* Collection vs Pending */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col">
                            <div className="flex justify-between items-start mb-2">
                                <div>
                                    <h2 className="text-lg font-bold text-slate-800">Collection vs Pending Dues</h2>
                                    <p className="text-sm text-gray-500 mt-1 max-w-md">
                                        This chart compares the total amount <strong>collected in the current month</strong> against the overall <strong>pending dues up to today's date</strong>.
                                    </p>
                                </div>
                            </div>
                            
                            <div className="h-72 flex-1 mt-4 relative">
                                {collectionStatus.every((d) => d.value === 0) ? (
                                    <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-400">
                                        <svg className="w-12 h-12 mb-2 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4"></path></svg>
                                        <p>No fee data found for this period.</p>
                                    </div>
                                ) : (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <PieChart>
                                            <Pie
                                                data={collectionStatus}
                                                innerRadius={70}
                                                outerRadius={100}
                                                paddingAngle={5}
                                                dataKey="value"
                                            >
                                                <Cell fill="#10b981" />
                                                <Cell fill="#f43f5e" />
                                            </Pie>
                                            <Tooltip formatter={(val: any) => `Γé╣${val.toLocaleString()}`} />
                                            <Legend verticalAlign="bottom" height={36}/>
                                        </PieChart>
                                    </ResponsiveContainer>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                        {/* Fee Adjustments Log */}
                        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                            <div className="p-5 border-b border-gray-200 flex justify-between items-center flex-wrap gap-4">
                                <div>
                                    <h2 className="text-lg font-bold text-slate-800">Recent Fee Adjustments (Waive-off & Refund)</h2>
                                    <p className="text-sm text-gray-500">Log of recent records from the fee_adjustment table.</p>
                                </div>
                                <div className="flex items-center gap-2">
                                    <input 
                                        type="date" 
                                        className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                        value={feeAdjustmentsFromDate}
                                        onChange={(e) => setFeeAdjustmentsFromDate(e.target.value)}
                                    />
                                    <span className="text-slate-500 text-sm">to</span>
                                    <input 
                                        type="date" 
                                        className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                        value={feeAdjustmentsToDate}
                                        onChange={(e) => setFeeAdjustmentsToDate(e.target.value)}
                                    />
                                </div>
                            </div>
                            <div className="overflow-x-auto">
                                <div className="max-h-72 overflow-y-auto">
                                    <table className="w-full text-sm text-left text-gray-600">
                                        <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-gray-200 sticky top-0 z-10">
                                            <tr>
                                                <th className="px-5 py-3 font-semibold">Date</th>
                                                <th className="px-5 py-3 font-semibold">Student</th>
                                                <th className="px-5 py-3 font-semibold">Type</th>
