                                                />
                                            </th>
                                            <th className="px-5 py-3 font-semibold cursor-pointer hover:bg-slate-100 group select-none" onClick={() => handlePendingSort('studentId')}>
                                                <div className="flex items-center gap-1">
                                                    Student ID 
                                                    <span className="text-gray-400 text-xs">
                                                        {pendingSortColumn === 'studentId' ? (pendingSortDirection === 'asc' ? 'Γåæ' : 'Γåô') : <span className="opacity-0 group-hover:opacity-50">Γåò</span>}
                                                    </span>
                                                </div>
                                            </th>
                                            <th className="px-5 py-3 font-semibold cursor-pointer hover:bg-slate-100 group select-none" onClick={() => handlePendingSort('rollNo')}>
                                                <div className="flex items-center gap-1">
                                                    Roll No 
                                                    <span className="text-gray-400 text-xs">
                                                        {pendingSortColumn === 'rollNo' ? (pendingSortDirection === 'asc' ? 'Γåæ' : 'Γåô') : <span className="opacity-0 group-hover:opacity-50">Γåò</span>}
                                                    </span>
                                                </div>
                                            </th>
                                            <th className="px-5 py-3 font-semibold cursor-pointer hover:bg-slate-100 group select-none" onClick={() => handlePendingSort('firstName')}>
                                                <div className="flex items-center gap-1">
                                                    Name 
                                                    <span className="text-gray-400 text-xs">
                                                        {pendingSortColumn === 'firstName' ? (pendingSortDirection === 'asc' ? 'Γåæ' : 'Γåô') : <span className="opacity-0 group-hover:opacity-50">Γåò</span>}
                                                    </span>
                                                </div>
                                            </th>
                                            <th className="px-5 py-3 font-semibold cursor-pointer hover:bg-slate-100 group select-none" onClick={() => handlePendingSort('className')}>
                                                <div className="flex items-center gap-1">
                                                    Class 
                                                    <span className="text-gray-400 text-xs">
                                                        {pendingSortColumn === 'className' ? (pendingSortDirection === 'asc' ? 'Γåæ' : 'Γåô') : <span className="opacity-0 group-hover:opacity-50">Γåò</span>}
                                                    </span>
                                                </div>
                                            </th>
                                            <th className="px-5 py-3 font-semibold cursor-pointer hover:bg-slate-100 group select-none" onClick={() => handlePendingSort('sectionName')}>
                                                <div className="flex items-center gap-1">
                                                    Section 
                                                    <span className="text-gray-400 text-xs">
                                                        {pendingSortColumn === 'sectionName' ? (pendingSortDirection === 'asc' ? 'Γåæ' : 'Γåô') : <span className="opacity-0 group-hover:opacity-50">Γåò</span>}
                                                    </span>
                                                </div>
                                            </th>
                                            <th className="px-5 py-3 font-semibold cursor-pointer hover:bg-slate-100 group select-none" onClick={() => handlePendingSort('mobile')}>
                                                <div className="flex items-center gap-1">
                                                    Mobile 
                                                    <span className="text-gray-400 text-xs">
                                                        {pendingSortColumn === 'mobile' ? (pendingSortDirection === 'asc' ? 'Γåæ' : 'Γåô') : <span className="opacity-0 group-hover:opacity-50">Γåò</span>}
                                                    </span>
                                                </div>
                                            </th>
                                            <th className="px-5 py-3 font-semibold cursor-pointer hover:bg-slate-100 group select-none" onClick={() => handlePendingSort('pendingAmount')}>
                                                <div className="flex items-center justify-end gap-1">
                                                    Pending Amount 
                                                    <span className="text-gray-400 text-xs">
                                                        {pendingSortColumn === 'pendingAmount' ? (pendingSortDirection === 'asc' ? 'Γåæ' : 'Γåô') : <span className="opacity-0 group-hover:opacity-50">Γåò</span>}
                                                    </span>
                                                </div>
                                            </th>
                                        </tr>
