                                <select
                                    className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                    value={receivedSessionId}
                                    onChange={(e) => setReceivedSessionId(e.target.value)}
