                                    className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                    value={receivedSearchQuery}
                                    onChange={(e) => setReceivedSearchQuery(e.target.value)}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Mobile No.</label>
                                <input
                                    type="text"
                                    placeholder="Mobile..."
                                    className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                    value={receivedMobile}
                                    onChange={(e) => setReceivedMobile(e.target.value)}
                                />
                            </div>
                            <div className="flex gap-2 lg:col-span-1">
                                <div className="w-1/2">
                                    <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">From</label>
                                    <input
                                        type="date"
                                        className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-[11px] p-2 bg-gray-50"
                                        value={receivedFromDate}
                                        onChange={(e) => setReceivedFromDate(e.target.value)}
                                    />
                                </div>
                                <div className="w-1/2">
                                    <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">To</label>
                                    <input
                                        type="date"
                                        className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-[11px] p-2 bg-gray-50"
                                        value={receivedToDate}
                                        onChange={(e) => setReceivedToDate(e.target.value)}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="flex justify-end mb-4">
                            <button
                                onClick={() => fetchFeeReceived()}
                                disabled={!receivedSessionId}
                                className="bg-blue-600 text-white px-6 py-2 rounded-lg shadow hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed font-medium"
                            >
                                Apply Filters
                            </button>
                        </div>

                        {!receivedHasSearched ? (
                            <div className="border border-dashed border-slate-300 rounded-lg p-12 text-center text-slate-400">
                                <svg className="w-12 h-12 mx-auto mb-3 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2a1 1 0 01-.293.707L13 13.414V19a1 1 0 01-.553.894l-4 2A1 1 0 017 21v-7.586L3.293 6.707A1 1 0 013 6V4z"/></svg>
                                <p className="text-sm font-medium">Select filters above and click <span className="text-blue-600 font-semibold">Apply Filters</span> to view fee received records.</p>
                            </div>
                        ) : (
                        <>
                        <div className="overflow-x-auto border border-gray-200 rounded-lg max-h-[600px] overflow-y-auto">
                            {receivedLoading ? (
                                <div className="p-12 flex justify-center">
                                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                                </div>
                            ) : (
                                <table className="w-full text-sm text-left text-gray-600">
                                    <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-gray-200 sticky top-0 z-10 shadow-sm">
                                        <tr>
                                            <th className="px-5 py-3 font-semibold">Payment Date</th>
                                            <th className="px-5 py-3 font-semibold">Receipt No</th>
                                            <th className="px-5 py-3 font-semibold">Student Name</th>
                                            <th className="px-5 py-3 font-semibold">Class</th>
                                            <th className="px-5 py-3 font-semibold">Method</th>
                                            <th className="px-5 py-3 font-semibold">Fee Month</th>
                                            <th className="px-5 py-3 font-semibold">Collected By</th>
                                            <th className="px-5 py-3 font-semibold text-right">Amount Paid</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {receivedData.length > 0 ? (
                                            receivedData.map((row, idx) => (
                                                <tr key={idx} className="border-b border-gray-100 hover:bg-slate-50/50">
                                                    <td className="px-5 py-3">{new Date(row.paymentDate).toLocaleDateString()}</td>
                                                    <td className="px-5 py-3 font-medium text-slate-800">{row.receiptNumber}</td>
                                                    <td className="px-5 py-3">
                                                        {row.firstName} {row.lastName}
                                                        <div className="text-xs text-gray-400">ID: {row.studentId}</div>
                                                    </td>
                                                    <td className="px-5 py-3">{row.className} {row.sectionName}</td>
                                                    <td className="px-5 py-3">{row.paymentMethod}</td>
                                                    <td className="px-5 py-3">{row.feeMonth || '-'}</td>
                                                    <td className="px-5 py-3">{row.collectedBy}</td>
                                                    <td className="px-5 py-3 text-right font-bold text-green-600">Γé╣{row.amountPaid?.toLocaleString()}</td>
                                                </tr>
                                            ))
                                        ) : (
                                            <tr>
                                                <td colSpan={8} className="p-8 text-center text-gray-500">
                                                    No fee received records matching the selected filters.
                                                </td>
                                            </tr>
                                        )}
                                    </tbody>
                                </table>
                            )}
                        </div>

                        {/* Pagination */}
                        {receivedHasSearched && receivedTotalCount > 0 && (
                            <div className="p-4 border-t border-slate-100 flex items-center justify-between bg-slate-50/50 mt-4 rounded-lg">
                                <div className="text-sm text-slate-500">
                                    Showing <span className="font-medium text-slate-900">{(receivedPage - 1) * RECEIVED_PER_PAGE + 1}</span> to <span className="font-medium text-slate-900">{Math.min(receivedPage * RECEIVED_PER_PAGE, receivedTotalCount)}</span> of <span className="font-medium text-slate-900">{receivedTotalCount}</span> records
                                </div>
                                <div className="flex gap-2">
                                    <button 
                                        onClick={() => { const p = Math.max(1, receivedPage - 1); setReceivedPage(p); fetchFeeReceived(p); }}
                                        disabled={receivedPage === 1}
                                        className="px-3 py-1 border border-slate-200 rounded text-sm disabled:opacity-50 bg-white hover:bg-slate-50 transition"
                                    >
                                        Previous
                                    </button>
                                    <span className="px-3 py-1 text-sm flex items-center">
                                        Page {receivedPage} of {Math.ceil(receivedTotalCount / RECEIVED_PER_PAGE) || 1}
                                    </span>
                                    <button 
                                        onClick={() => { const p = Math.min(Math.ceil(receivedTotalCount / RECEIVED_PER_PAGE), receivedPage + 1); setReceivedPage(p); fetchFeeReceived(p); }}
                                        disabled={receivedPage === Math.ceil(receivedTotalCount / RECEIVED_PER_PAGE)}
                                        className="px-3 py-1 border border-slate-200 rounded text-sm disabled:opacity-50 bg-white hover:bg-slate-50 transition"
                                    >
                                        Next
                                    </button>
                                </div>
                            </div>
                        )}
                        </>
                        )}
                    </div>
                </div>
            )}

            {/* TAB CONTENT: EXAMINATIONS */}
            {activeTab === 'EXAMINATIONS' && (
                <div className="space-y-6">
                    {/* Filters Row */}
                    <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-end">
                        <div className="flex-1 min-w-[150px]">
                            <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Academic Year</label>
                            <select 
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-white"
                                value={selectedExamYear}
                                onChange={(e) => setSelectedExamYear(e.target.value)}
                            >
                                <option value="">Select Session</option>
                                {academicSessions.map(session => (
                                    <option key={session.id} value={session.id.toString()}>{session.name}</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex-1 min-w-[150px]">
                            <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Exam Term</label>
                            <select 
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-white"
                                value={selectedExamTerm}
                                onChange={(e) => setSelectedExamTerm(e.target.value)}
                            >
                                <option value="">Select Term</option>
                                {examTerms.map(term => (
                                    <option key={term.id} value={term.id.toString()}>{term.name}</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex-1 min-w-[150px]">
                            <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Class</label>
                            <select 
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-white"
                                value={selectedExamClass}
                                onChange={(e) => {
                                    setSelectedExamClass(e.target.value);
                                    setSelectedExamSection('');
                                    const cls = classes.find((c: any) => c.id.toString() === e.target.value);
                                    setAvailableSections(cls ? cls.sections : []);
                                }}
                            >
                                <option value="">All Classes</option>
                                {classes.map((cls: any) => (
                                    <option key={cls.id} value={cls.id.toString()}>{cls.name}</option>
                                ))}
                            </select>
                        </div>
                        {selectedExamClass && availableSections.length > 0 && (
                            <div className="flex-1 min-w-[150px]">
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Section</label>
                                <select 
                                    className="w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-white"
                                    value={selectedExamSection}
                                    onChange={(e) => setSelectedExamSection(e.target.value)}
                                >
                                    <option value="">All Sections</option>
                                    {availableSections.map((sec: any) => (
                                        <option key={sec.id} value={sec.id.toString()}>{sec.name}</option>
                                    ))}
                                </select>
                            </div>
                        )}
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h2 className="text-lg font-bold text-slate-800 mb-4">Average Marks by Class</h2>
                            <div className="h-72">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={examClassAvg}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748B'}} domain={[0, 100]} />
                                        <Tooltip formatter={(val: any) => `${val}%`} cursor={{fill: '#F1F5F9'}} />
                                        <Bar dataKey="avg" name="Average %" fill="#8b5cf6" radius={[4,4,0,0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                            <div className="p-5 border-b border-gray-200 flex justify-between items-center">
                                <div>
                                    <h2 className="text-lg font-bold text-slate-800">Top Performers / Highest Marks</h2>
                                    <p className="text-sm text-gray-500">Highest scores per subject</p>
                                </div>
                            </div>
                            <div className="overflow-x-auto">
                                <table className="w-full text-sm text-left text-gray-600">
                                    <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-gray-200">
                                        <tr>
                                            <th className="px-5 py-3 font-semibold">Subject</th>
                                            <th className="px-5 py-3 font-semibold">Class</th>
                                            <th className="px-5 py-3 font-semibold">Student Name</th>
                                            <th className="px-5 py-3 font-semibold text-right">Highest %</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {topPerformers.map((tp, idx) => (
                                            <tr key={idx} className="border-b border-gray-100 hover:bg-slate-50/50">
                                                <td className="px-5 py-3 font-medium">{tp.subject}</td>
                                                <td className="px-5 py-3">{tp.className}</td>
                                                <td className="px-5 py-3">{tp.studentName}</td>
                                                <td className="px-5 py-3 text-right font-bold text-green-600">{tp.percentage}%</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                                {topPerformers.length === 0 && (
                                    <div className="p-4 text-center text-gray-500">No score records found.</div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* TAB CONTENT: ATTENDANCE */}
            {activeTab === 'ATTENDANCE' && (
                <div className="space-y-6">
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <div className="flex justify-between items-center mb-4 flex-wrap gap-2">
                                <h2 className="text-lg font-bold text-slate-800">Average Attendance by Class</h2>
                                <select 
                                    className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50 mr-2"
                                    value={attendanceSession}
                                    onChange={(e) => setAttendanceSession(e.target.value)}
                                >
                                    <option value="">Select Session</option>
                                    {academicSessions.map(session => (
                                        <option key={session.id} value={session.id.toString()}>{session.name}</option>
                                    ))}
                                </select>
                                <select 
                                    className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                    value={attendanceMonth}
                                    onChange={(e) => setAttendanceMonth(e.target.value)}
                                >
                                    <option value="">Whole Year</option>
                                    <option value="4">April</option>
                                    <option value="5">May</option>
                                    <option value="6">June</option>
                                    <option value="7">July</option>
                                    <option value="8">August</option>
                                    <option value="9">September</option>
                                    <option value="10">October</option>
                                    <option value="11">November</option>
                                    <option value="12">December</option>
                                    <option value="1">January</option>
                                    <option value="2">February</option>
                                    <option value="3">March</option>
                                </select>
                            </div>
                            <div className="h-72">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={attendanceByClass} layout="vertical">
                                        <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#E2E8F0" />
                                        <XAxis type="number" domain={[0, 100]} axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{fill: '#64748B'}} width={60} />
                                        <Tooltip formatter={(val: any) => `${val}%`} cursor={{fill: '#F1F5F9'}} />
                                        <Bar dataKey="attendance" name="Attendance %" fill="#10b981" radius={[0,4,4,0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <div className="flex justify-between items-center mb-4 flex-wrap gap-4">
                                <h2 className="text-lg font-bold text-slate-800">School-Wide Daily Trend</h2>
                                <div className="flex items-center gap-2">
                                    <input 
                                        type="date" 
                                        className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                        value={attendanceFromDate}
                                        onChange={(e) => setAttendanceFromDate(e.target.value)}
                                    />
                                    <span className="text-slate-500 text-sm">to</span>
                                    <input 
                                        type="date" 
                                        className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                        value={attendanceToDate}
                                        onChange={(e) => setAttendanceToDate(e.target.value)}
                                    />
                                </div>
                            </div>
                            <div className="h-72">
                                <ResponsiveContainer width="100%" height="100%">
                                    <LineChart data={attendanceTrend}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                                        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <Tooltip formatter={(val: any) => `${val}%`} />
                                        <Line type="monotone" dataKey="percent" name="Attendance %" stroke="#f59e0b" strokeWidth={3} dot={{r:4, fill:'#f59e0b'}} activeDot={{r:6}} />
                                    </LineChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* TAB CONTENT: STUDENTS */}
            {activeTab === 'STUDENTS' && (
                <div className="space-y-6">
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <div className="flex justify-between items-center mb-4 flex-wrap gap-2">
                                <h2 className="text-lg font-bold text-slate-800">Student Enrollment by Class</h2>
                                <div className="flex items-center gap-2">
                                    <select 
                                        className="border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                        value={enrollmentFromSession}
                                        onChange={(e) => setEnrollmentFromSession(e.target.value)}
                                    >
                                        <option value="">Filter Session</option>
                                        {academicSessions.map(session => (
                                            <option key={session.id} value={session.id.toString()}>{session.name}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                            <div className="h-72">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={enrollmentClass}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <Tooltip cursor={{fill: '#F1F5F9'}} />
                                        <Bar dataKey="students" name="Enrolled Students" fill="#3b82f6" radius={[4,4,0,0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <div className="flex justify-between items-center mb-4 flex-wrap gap-2">
                                <h2 className="text-lg font-bold text-slate-800">New Admissions Trend</h2>
                                <div className="flex items-center gap-2">
                                    <select 
                                        className="w-32 border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                        value={admissionsFromSession}
                                        onChange={(e) => setAdmissionsFromSession(e.target.value)}
                                    >
                                        <option value="">From Session</option>
                                        {academicSessions.map(session => (
                                            <option key={session.id} value={session.id.toString()}>{session.name}</option>
                                        ))}
                                    </select>
                                    <span className="text-slate-500 text-sm">to</span>
                                    <select 
                                        className="w-32 border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 text-sm p-2 bg-gray-50"
                                        value={admissionsToSession}
                                        onChange={(e) => setAdmissionsToSession(e.target.value)}
                                    >
                                        <option value="">To Session</option>
                                        {academicSessions.map(session => (
                                            <option key={session.id} value={session.id.toString()}>{session.name}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                            <div className="h-72">
                                <ResponsiveContainer width="100%" height="100%">
                                    <LineChart data={admissionsTrend}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                                        <XAxis dataKey="year" axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748B'}} />
                                        <Tooltip />
                                        <Line type="monotone" dataKey="admissions" name="New Admissions" stroke="#10b981" strokeWidth={3} dot={{r: 4, fill: '#10b981'}} />
                                    </LineChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* TAB CONTENT: STAFF */}
            {activeTab === 'STAFF' && (
                <div className="space-y-6">
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h2 className="text-lg font-bold text-slate-800 mb-4">Staff Distribution</h2>
                            <div className="h-72">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={staffDistribution}
                                            innerRadius={60}
                                            outerRadius={100}
                                            paddingAngle={2}
                                            dataKey="value"
                                            label
                                        >
                                            {staffDistribution.map((entry: any, index: number) => (
                                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                            ))}
                                        </Pie>
                                        <Tooltip />
                                        <Legend verticalAlign="bottom" height={36}/>
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {showNotifModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden animate-scale-in">
                        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                            <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                                <svg className="w-5 h-5 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                                </svg>
                                Send Fee Reminder Notification
                            </h3>
                            <button onClick={() => setShowNotifModal(false)} className="text-slate-400 hover:text-slate-600 transition">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                            </button>
                        </div>
                        <div className="p-6 space-y-5">
                            <div className="bg-indigo-50 text-indigo-700 p-3 rounded-lg text-sm border border-indigo-100 flex gap-3 items-center">
                                <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                <span>Will notify parents of <strong>{selectedPendingStudents.length}</strong> selected student(s).</span>
                            </div>

                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-1">Notification Title</label>
                                <input type="text" value="Fee Payment Reminder" disabled className="w-full border-slate-200 bg-slate-50 text-slate-500 rounded-lg p-2.5 text-sm" />
                            </div>

                            <div className="space-y-3">
                                <div className="flex items-center justify-between">
                                    <label className="text-sm font-semibold text-slate-700">Message Content</label>
                                    <label className="flex items-center gap-2 cursor-pointer">
                                        <input type="checkbox" checked={useCustomMessage} onChange={(e) => setUseCustomMessage(e.target.checked)} className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500" />
                                        <span className="text-xs text-slate-600 font-medium">Use custom message</span>
                                    </label>
                                </div>
                                
                                {useCustomMessage ? (
                                    <textarea
                                        value={customNotifMessage}
                                        onChange={(e) => setCustomNotifMessage(e.target.value)}
                                        placeholder="Write your custom reminder message here..."
                                        className="w-full border-slate-300 rounded-lg p-3 text-sm focus:ring-indigo-500 focus:border-indigo-500 min-h-[120px]"
                                    />
                                ) : (
                                    <div className="w-full border border-slate-200 bg-slate-50 rounded-lg p-4 text-sm text-slate-500 italic">
                                        "Dear Parent, this is a reminder that your ward has pending school fee dues. Kindly clear the outstanding amount at the earliest to avoid any inconvenience. Thank you."
                                    </div>
                                )}
                            </div>
                        </div>
                        <div className="p-5 border-t border-slate-100 bg-slate-50 flex justify-end gap-3">
                            <button
                                onClick={() => setShowNotifModal(false)}
                                disabled={sendingNotif}
                                className="px-5 py-2.5 text-sm font-medium text-slate-600 hover:bg-slate-200 bg-slate-100 rounded-lg transition"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleSendNotification}
                                disabled={sendingNotif || (useCustomMessage && !customNotifMessage.trim())}
                                className="px-5 py-2.5 text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg shadow transition flex items-center gap-2 disabled:opacity-50"
                            >
                                {sendingNotif && <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
                                {sendingNotif ? 'Sending...' : 'Send Notification'}
                            </button>
                        </div>
                    </div>
                </div>
            )}

        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import toast, { Toaster } from "react-hot-toast";
import useSWR from "swr";
import { API_BASE_URL, fetcher } from "@/lib/api";
import { Loader } from "@/components/ui/Loader";
import { Plus, Trash2, Edit2, CheckCircle2, XCircle, Settings2, GraduationCap, CalendarDays } from "lucide-react";
import { useRbac } from "@/lib/rbac";
import { authFetch } from "@/lib/auth";

export default function SettingsPage() {
    const [activeTab, setActiveTab] = useState<'system' | 'examination' | 'holidays'>('system');
    const rbac = useRbac();

    // --- System Settings State ---
    const { data: sessions = [], error, isLoading: loading, mutate } = useSWR('/academic-sessions', fetcher);
    const [newSessionName, setNewSessionName] = useState("");
    const [newSessionStart, setNewSessionStart] = useState("");
    const [newSessionEnd, setNewSessionEnd] = useState("");

    const { data: designations = [], mutate: mutateDesignations, isLoading: loadingDesignations } = useSWR('/designations', fetcher);
    const [newDesigTitle, setNewDesigTitle] = useState("");
    const [newDesigDesc, setNewDesigDesc] = useState("");

    const [openDropdownId, setOpenDropdownId] = useState<string | null>(null);
    const [dropdownPosition, setDropdownPosition] = useState({ top: 0, left: 0 });

    const [editingDesig, setEditingDesig] = useState<any>(null);
    const [editDesigTitle, setEditDesigTitle] = useState("");
    const [editDesigDesc, setEditDesigDesc] = useState("");

    // --- Examination Settings State ---
    const [selectedExamSessionId, setSelectedExamSessionId] = useState<number | null>(null);
    const { data: examCategories = [], mutate: mutateCategories } = useSWR(
        selectedExamSessionId ? `/exams/categories?sessionId=${selectedExamSessionId}` : null,
        fetcher
    );
    const { data: examSettings, mutate: mutateSettings } = useSWR(
        selectedExamSessionId ? `/exams/settings?sessionId=${selectedExamSessionId}` : null,
        fetcher
    );
    const [newCategoryName, setNewCategoryName] = useState("");
    const [newCategoryDesc, setNewCategoryDesc] = useState("");
    const [selectedCategoryIds, setSelectedCategoryIds] = useState<number[]>([]);
    const [selectedTargetCategoryId, setSelectedTargetCategoryId] = useState<number | null>(null);

    // Grading System Settings State
    const [selectedGradingSessionId, setSelectedGradingSessionId] = useState<number | null>(null);
    const { data: gradingSystems = [], mutate: mutateGradingSystems } = useSWR(
        selectedGradingSessionId ? `/exams/grading-system/session/${selectedGradingSessionId}` : null,
        fetcher
    );
    const [newGradeName, setNewGradeName] = useState("");
    const [newGradeMin, setNewGradeMin] = useState<string>("");
    const [newGradeMax, setNewGradeMax] = useState<string>("");
    const [newGradeIsFail, setNewGradeIsFail] = useState(false);


    useEffect(() => {
        const handleClose = (e: Event) => {
            if ((e.target as Element).closest('.action-dropdown-btn') || 
                (e.target as Element).closest('.action-dropdown-menu')) {
                return;
            }
            setOpenDropdownId(null);
        };
        document.addEventListener('click', handleClose);
        document.addEventListener('scroll', handleClose, true);
        return () => {
            document.removeEventListener('click', handleClose);
            document.removeEventListener('scroll', handleClose, true);
        }
    }, []);

    const handleDropdownClick = (e: React.MouseEvent, id: string) => {
        e.preventDefault();
        e.stopPropagation();

        if (openDropdownId === id) {
            setOpenDropdownId(null);
        } else {
            const button = e.currentTarget as HTMLElement;
            const rect = button.getBoundingClientRect();
            const menuHeight = 80;
            const menuWidth = 130;
            const viewportHeight = window.innerHeight;
            const viewportWidth = window.innerWidth;

            const spaceBelow = viewportHeight - rect.bottom;
            const top = spaceBelow >= menuHeight
                ? rect.bottom + 4
                : rect.top - menuHeight - 4;

            const left = Math.min(rect.right - menuWidth, viewportWidth - menuWidth - 8);

            setDropdownPosition({ top, left });
            setOpenDropdownId(id);
        }
    };

    useEffect(() => {
        if (examSettings && examSettings.hasOwnProperty('contributingCategoryIds')) {
            setSelectedCategoryIds(examSettings.contributingCategoryIds || []);
            setSelectedTargetCategoryId(examSettings.finalTargetCategoryId || null);
        }
    }, [examSettings]);

    // Handle initial session selection for grading
    useEffect(() => {
        if (activeTab === 'examination' && sessions.length > 0) {
            const activeSession = sessions.find((s: any) => s.isActive);
            const defaultId = activeSession ? activeSession.id : sessions[0].id;
            
            if (!selectedGradingSessionId) {
                setSelectedGradingSessionId(defaultId);
            }
            if (!selectedExamSessionId) {
                setSelectedExamSessionId(defaultId);
            }
        }
    }, [activeTab, sessions, selectedGradingSessionId, selectedExamSessionId]);


    // --- Holidays Settings State ---
    const { data: holidays = [], mutate: mutateHolidays, isLoading: loadingHolidays } = useSWR('/holidays', fetcher);
    const { data: classes = [] } = useSWR('/classes', fetcher);
    const [showHolidayModal, setShowHolidayModal] = useState(false);
    const [editingHolidayId, setEditingHolidayId] = useState<number | null>(null);
    const [holidayDesc, setHolidayDesc] = useState("");
    const [holidayStart, setHolidayStart] = useState("");
    const [holidayEnd, setHolidayEnd] = useState("");
    const [holidayIsEntireSchool, setHolidayIsEntireSchool] = useState(true);
    const [holidayClassIds, setHolidayClassIds] = useState<number[]>([]);
    const [isSavingHoliday, setIsSavingHoliday] = useState(false);

    const handleOpenHolidayModal = (holiday?: any) => {
        if (holiday) {
            setEditingHolidayId(holiday.id);
            setHolidayDesc(holiday.description);
            // Convert ISO dates to YYYY-MM-DD for input fields if they exist
            setHolidayStart(holiday.startDate ? new Date(holiday.startDate).toISOString().split('T')[0] : "");
            setHolidayEnd(holiday.endDate ? new Date(holiday.endDate).toISOString().split('T')[0] : "");
            setHolidayIsEntireSchool(holiday.isEntireSchool);
            setHolidayClassIds(holiday.classes ? holiday.classes.map((c: any) => c.id) : []);
        } else {
            setEditingHolidayId(null);
            setHolidayDesc("");
            setHolidayStart("");
            setHolidayEnd("");
            setHolidayIsEntireSchool(true);
            setHolidayClassIds([]);
        }
        setShowHolidayModal(true);
    };

    const handleSaveHoliday = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSavingHoliday(true);
        try {
            const payload: any = {
                description: holidayDesc,
                startDate: holidayStart,
                endDate: holidayEnd,
                isEntireSchool: holidayIsEntireSchool,
            };
            if (!holidayIsEntireSchool) {
                payload.classIds = holidayClassIds;
            }

            const url = editingHolidayId
                ? `${API_BASE_URL}/holidays/${editingHolidayId}`
                : `${API_BASE_URL}/holidays`;
            const method = editingHolidayId ? 'PATCH' : 'POST';

            const res = await authFetch(url, {
                method,
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload)
            });

            if (res.ok) {
                toast.success(`Holiday ${editingHolidayId ? 'updated' : 'created'} successfully!`);
                setShowHolidayModal(false);
                mutateHolidays();
            } else {
                const data = await res.json();
                toast.error(data.message || "Failed to save holiday");
            }
        } catch (err) {
            toast.error("Network error");
        } finally {
            setIsSavingHoliday(false);
        }
    };

    const handleDeleteHoliday = async (id: number) => {
        if (!confirm("Are you sure you want to delete this holiday? This will also remove the holiday status from student attendance records for those dates.")) return;
        try {
            const res = await authFetch(`${API_BASE_URL}/holidays/${id}`, { method: "DELETE" });
            if (res.ok) {
                toast.success("Holiday deleted");
                mutateHolidays();
            } else {
                toast.error("Failed to delete holiday");
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleHolidaySelectAllClasses = () => {
        if (holidayClassIds.length === classes.length) {
            setHolidayClassIds([]);
        } else {
            setHolidayClassIds(classes.map((c: any) => c.id));
        }
    };

    // --- System Setting Handlers ---
    const handleCreateSession = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await authFetch(`${API_BASE_URL}/academic-sessions`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name: newSessionName,
                    startDate: newSessionStart,
                    endDate: newSessionEnd,
                    isActive: sessions.length === 0, // First session defaults to active
                })
            });
            if (res.ok) {
                toast.success("Academic Session created!");
                setNewSessionName("");
                setNewSessionStart("");
                setNewSessionEnd("");
                mutate();
            } else {
                const data = await res.json();
                toast.error(data.message || "Failed to create session");
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleSetActive = async (id: number) => {
        try {
            // Unset all active
            for (const s of sessions) {
                if (s.isActive && s.id !== id) {
                    await authFetch(`${API_BASE_URL}/academic-sessions/${s.id}`, {
                        method: "PATCH",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({ isActive: false })
                    });
                }
            }
            // Set target active
            const res = await authFetch(`${API_BASE_URL}/academic-sessions/${id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ isActive: true })
            });
            if (res.ok) {
                toast.success("Active session updated!");
                mutate();
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleCreateDesignation = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await authFetch(`${API_BASE_URL}/designations`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ title: newDesigTitle, description: newDesigDesc, isActive: true })
            });
            if (res.ok) {
                toast.success("Designation created!");
                setNewDesigTitle("");
                setNewDesigDesc("");
                mutateDesignations();
            } else {
                const data = await res.json();
                toast.error(data.message || "Failed to create designation");
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleDeleteDesignation = async (id: number) => {
        if (!confirm("Are you sure you want to delete this designation?")) return;
        try {
            const res = await authFetch(`${API_BASE_URL}/designations/${id}`, { method: "DELETE" });
            if (res.ok) {
                toast.success("Designation deleted");
                mutateDesignations();
            } else {
                const data = await res.json();
                toast.error(data.message || "Failed to delete designation");
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleUpdateDesignation = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editingDesig) return;
        try {
            const res = await authFetch(`${API_BASE_URL}/designations/${editingDesig.id}`, {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ title: editDesigTitle, description: editDesigDesc })
            });
            if (res.ok) {
                toast.success("Designation updated!");
                setEditingDesig(null);
                mutateDesignations();
            } else {
                const data = await res.json();
                toast.error(data.message || "Failed to update designation");
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    // --- Examination Setting Handlers ---
    const handleCreateCategory = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedExamSessionId) return toast.error("Select a session first");

        try {
            const res = await authFetch(`${API_BASE_URL}/exams/categories`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ 
                    name: newCategoryName, 
                    description: newCategoryDesc,
                    sessionId: selectedExamSessionId
                })
            });
            if (res.ok) {
                toast.success("Exam Category created!");
                setNewCategoryName("");
                setNewCategoryDesc("");
                mutateCategories();
            } else {
                const data = await res.json();
                toast.error(data.message || "Failed to create category");
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleToggleCategory = async (id: number, currentStatus: boolean) => {
        try {
            const res = await authFetch(`${API_BASE_URL}/exams/categories/${id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ isActive: !currentStatus })
            });
            if (res.ok) {
                toast.success("Category status updated!");
                mutateCategories();
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const toggleFinalResultCategory = (id: number) => {
        if (id === selectedTargetCategoryId) {
            toast.error("The Target Final Category cannot also be a contributing category.");
            return;
        }
        setSelectedCategoryIds(prev =>
            prev.includes(id) ? prev.filter(cId => cId !== id) : [...prev, id]
        );
    };

    const handleTargetCategoryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const val = e.target.value ? parseInt(e.target.value) : null;
        if (val && selectedCategoryIds.includes(val)) {
            // Remove from contributing if it was there
            setSelectedCategoryIds(prev => prev.filter(id => id !== val));
        }
        setSelectedTargetCategoryId(val);
    };

    const handleSaveSettings = async () => {
        if (!selectedExamSessionId) return toast.error("Select a session first");

        try {
            const res = await authFetch(`${API_BASE_URL}/exams/settings`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    sessionId: selectedExamSessionId,
                    contributingCategoryIds: selectedCategoryIds,
                    finalTargetCategoryId: selectedTargetCategoryId
                })
            });
            if (res.ok) {
                toast.success("Exam settings updated!");
                mutateSettings();
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleCreateGrading = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedGradingSessionId) return toast.error("Select a session first");

        const parsedMin = parseFloat(newGradeMin);
        const parsedMax = parseFloat(newGradeMax);
        if (isNaN(parsedMin) || isNaN(parsedMax)) return toast.error("Enter valid percentage values");
        if (parsedMin < 0 || parsedMax < 0) return toast.error("Percentages cannot be negative");
        if (parsedMax > 100) return toast.error("Percentages cannot exceed 100");
        if (parsedMin >= parsedMax) return toast.error("Min % must be strictly less than Max %");

        try {
            const res = await authFetch(`${API_BASE_URL}/exams/grading-system`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    sessionId: selectedGradingSessionId,
                    gradeName: newGradeName,
                    minPercentage: parsedMin,
                    maxPercentage: parsedMax,
                    isFailGrade: newGradeIsFail
                })
            });
            if (res.ok) {
                toast.success("Grading band created!");
                setNewGradeName("");
                setNewGradeMin("");
                setNewGradeMax("");
                setNewGradeIsFail(false);
                mutateGradingSystems();
            } else {
                const data = await res.json();
                const errMsg = Array.isArray(data.message) ? data.message[0] : (data.message || "Failed to create grading");
                toast.error(errMsg);
            }
        } catch (err) {
            toast.error("Network error");
        }
    };

    const handleDeleteGrading = async (id: number) => {
        if (!confirm("Are you sure you want to delete this grading band?")) return;
        try {
            const res = await authFetch(`${API_BASE_URL}/exams/grading-system/${id}`, { method: "DELETE" });
            if (res.ok) {
                toast.success("Grading band deleted");
                mutateGradingSystems();
            }
        } catch (err) {
            toast.error("Network error");
        }
    };


    return (
        <main className="p-4 flex-1 h-full overflow-y-auto w-full max-w-7xl mx-auto">
            {error && <div className="p-4 text-red-600 mb-4 bg-red-50 rounded">Error loading sessions</div>}
            <Toaster position="top-right" />
            <div className="flex flex-col md:flex-row md:justify-between md:items-center mb-6 gap-4 border-b pb-4 border-gray-200">
                <h1 className="text-3xl font-bold text-slate-800 pb-2 md:pb-0">Settings</h1>
                <div className="flex p-1 bg-slate-100 rounded-xl w-full md:w-fit shadow-inner border border-slate-200/60 overflow-x-auto">
                    <button
                        onClick={() => setActiveTab('system')}
                        className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                            activeTab === 'system'
                                ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                                : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                        }`}
                    >
                        <Settings2 className="w-4 h-4" />
                        System Settings
                    </button>
                    <button
                        onClick={() => setActiveTab('examination')}
                        className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                            activeTab === 'examination'
                                ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                                : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                        }`}
                    >
                        <GraduationCap className="w-4 h-4" />
                        Examination Settings
                    </button>
                    <button
                        onClick={() => setActiveTab('holidays')}
                        className={`flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-lg whitespace-nowrap transition-all duration-200 ${
                            activeTab === 'holidays'
                                ? "bg-white text-blue-700 shadow-sm ring-1 ring-black/5"
                                : "text-slate-600 hover:text-slate-900 hover:bg-slate-200/50"
                        }`}
                    >
                        <CalendarDays className="w-4 h-4" />
                        Holidays
                    </button>
                </div>
            </div>

            {activeTab === 'system' && (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Academic Sessions panel */}
                    <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                        <h2 className="text-xl font-bold mb-4 text-slate-800">Academic Sessions</h2>

                        {/* Create Session form ΓÇö ADMIN+ only */}
                        {rbac.canManageSessions && (
                            <form onSubmit={handleCreateSession} className="mb-8 p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                <h3 className="text-sm font-semibold text-slate-700 mb-3">Add New Session</h3>
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                                    <div>
                                        <label className="block mb-1 text-xs font-medium text-gray-700">Name (e.g. 2026-2027)</label>
                                        <input type="text" value={newSessionName} onChange={(e) => setNewSessionName(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
                                    </div>
                                    <div>
                                        <label className="block mb-1 text-xs font-medium text-gray-700">Start Date</label>
                                        <input type="date" value={newSessionStart} onChange={(e) => setNewSessionStart(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
                                    </div>
                                    <div>
                                        <label className="block mb-1 text-xs font-medium text-gray-700">End Date</label>
                                        <input type="date" value={newSessionEnd} onChange={(e) => setNewSessionEnd(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
                                    </div>
                                </div>
                                <button type="submit" className="w-full px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 transition">Create Session</button>
                            </form>
                        )}

                        {loading ? (
                            <Loader text="Loading sessions..." />
                        ) : (
                            <div className="relative overflow-x-auto rounded-lg border border-gray-200">
                                <table className="w-full text-sm text-left text-gray-500">
                                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b">
                                        <tr>
                                            <th scope="col" className="px-4 py-3">ID</th>
                                            <th scope="col" className="px-4 py-3">Name</th>
                                            <th scope="col" className="px-4 py-3">Period</th>
                                            <th scope="col" className="px-4 py-3 text-center">Status</th>
                                            <th scope="col" className="px-4 py-3 text-right">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {sessions.map((s: any) => (
                                            <tr key={s.id} className="bg-white border-b hover:bg-gray-50">
                                                <td className="px-4 py-3 font-mono text-xs text-gray-500">{s.id}</td>
                                                <td className="px-4 py-3 font-semibold text-slate-800">{s.name}</td>
                                                <td className="px-4 py-3 text-xs">
                                                    {new Date(s.startDate).toLocaleDateString()} to {new Date(s.endDate).toLocaleDateString()}
                                                </td>
                                                <td className="px-4 py-3 text-center">
                                                    {s.isActive ? (
                                                        <span className="px-2 py-1 bg-green-100 text-green-800 text-xs font-bold rounded uppercase">Active</span>
                                                    ) : (
                                                        <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs font-bold rounded uppercase">Inactive</span>
                                                    )}
                                                </td>
                                                <td className="px-4 py-3 text-right">
                                                    {!s.isActive && rbac.canManageSessions && (
                                                        <button onClick={() => handleSetActive(s.id)} className="text-blue-600 hover:underline font-medium text-xs">
                                                            Set Active
                                                        </button>
                                                    )}
                                                </td>
                                            </tr>
                                        ))}
                                        {sessions.length === 0 && (
                                            <tr><td colSpan={4} className="px-4 py-6 text-center text-gray-500 italic">No academic sessions found.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>

                    {/* Staff Designations panel */}
                    <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                        <h2 className="text-xl font-bold mb-4 text-slate-800">Staff Designations</h2>

                        {rbac.isAdmin && (
                            <form onSubmit={handleCreateDesignation} className="mb-8 p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                <h3 className="text-sm font-semibold text-slate-700 mb-3">Add Designation</h3>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                    <div>
                                        <label className="block mb-1 text-xs font-medium text-gray-700">Title (e.g. Principal)</label>
                                        <input type="text" value={newDesigTitle} onChange={(e) => setNewDesigTitle(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
                                    </div>
                                    <div>
                                        <label className="block mb-1 text-xs font-medium text-gray-700">Description</label>
                                        <input type="text" value={newDesigDesc} onChange={(e) => setNewDesigDesc(e.target.value)} className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
                                    </div>
                                </div>
                                <button type="submit" className="w-full px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 transition">Create Designation</button>
                            </form>
                        )}

                        {/* Edit Designation Modal */}
                        {editingDesig && (
                            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black bg-opacity-50">
                                <div className="bg-white p-6 rounded-lg shadow-xl w-full max-w-md animate-in zoom-in-95 duration-200">
                                    <h3 className="text-lg font-bold mb-4 text-slate-800">Edit Designation</h3>
                                    <form onSubmit={handleUpdateDesignation}>
                                        <div className="mb-4">
                                            <label className="block mb-2 text-sm font-medium text-gray-900">Title</label>
                                            <input
                                                type="text"
                                                value={editDesigTitle}
                                                onChange={(e) => setEditDesigTitle(e.target.value)}
                                                className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 focus:ring-blue-500 focus:border-blue-500"
                                                required
                                            />
                                        </div>
                                        <div className="mb-6">
                                            <label className="block mb-2 text-sm font-medium text-gray-900">Description</label>
                                            <input
                                                type="text"
                                                value={editDesigDesc}
                                                onChange={(e) => setEditDesigDesc(e.target.value)}
                                                className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 focus:ring-blue-500 focus:border-blue-500"
                                            />
                                        </div>
                                        <div className="flex gap-3 justify-end">
                                            <button
                                                type="button"
                                                onClick={() => setEditingDesig(null)}
                                                className="px-4 py-2 bg-white border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
                                            >
                                                Cancel
                                            </button>
                                            <button
                                                type="submit"
                                                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                                            >
                                                Save Changes
                                            </button>
                                        </div>
                                    </form>
                                </div>
                            </div>
                        )}

                        {loadingDesignations ? (
                            <Loader text="Loading designations..." />
                        ) : (
                            <div className="relative overflow-x-auto rounded-lg border border-gray-200">
                                <table className="w-full text-sm text-left text-gray-500">
                                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b">
                                        <tr>
                                            <th scope="col" className="px-4 py-3">Title</th>
                                            <th scope="col" className="px-4 py-3">Description</th>
                                            <th scope="col" className="px-4 py-3 text-right">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {designations.map((d: any) => (
                                            <tr key={d.id} className="bg-white border-b hover:bg-gray-50">
                                                <td className="px-4 py-3 font-semibold text-slate-800">{d.title}</td>
                                                <td className="px-4 py-3 text-xs">{d.description || '-'}</td>
                                                <td className="px-4 py-3 text-right">
                                                    {rbac.isAdmin && (
                                                        <div className="relative inline-block text-left">
                                                            <button
                                                                type="button"
                                                                onClick={(e) => handleDropdownClick(e, `desig-${d.id}`)}
                                                                className="action-dropdown-btn text-gray-500 hover:text-gray-700 p-1 rounded hover:bg-gray-100 focus:outline-none"
                                                            >
                                                                <svg className="w-5 h-5 pointer-events-none" fill="currentColor" viewBox="0 0 20 20"><path d="M10 6a2 2 0 110-4 2 2 0 010 4zM10 12a2 2 0 110-4 2 2 0 010 4zM10 18a2 2 0 110-4 2 2 0 010 4z"></path></svg>
                                                            </button>
                                                            {openDropdownId === `desig-${d.id}` && (
                                                                <div
                                                                    className="action-dropdown-menu fixed w-32 rounded-md shadow-lg bg-white ring-1 ring-black ring-opacity-5 z-[9999] border border-gray-100"
                                                                    style={{ top: dropdownPosition.top, left: dropdownPosition.left }}
                                                                >
                                                                    <div className="py-1">
                                                                        <button type="button" onClick={(e) => { e.stopPropagation(); setEditingDesig(d); setEditDesigTitle(d.title); setEditDesigDesc(d.description || ""); setOpenDropdownId(null); }} className="block w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-100">Edit</button>
                                                                        <button type="button" onClick={(e) => { e.stopPropagation(); handleDeleteDesignation(d.id); setOpenDropdownId(null); }} className="block w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-gray-100">Delete</button>
                                                                    </div>
                                                                </div>
                                                            )}
                                                        </div>
                                                    )}
                                                </td>
                                            </tr>
                                        ))}
                                        {designations.length === 0 && (
                                            <tr><td colSpan={3} className="px-4 py-6 text-center text-gray-500 italic">No designations found.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {activeTab === 'examination' && (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    <div className="space-y-6">
                        {/* Exam Categories panel */}
                        <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6">
                                <h2 className="text-xl font-bold text-slate-800">Exam Categories</h2>
                                <div className="mt-2 sm:mt-0">
                                    <label className="text-xs text-slate-500 mr-2 uppercase font-semibold">For Session:</label>
                                    <select
                                        className="text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 p-1"
                                        value={selectedExamSessionId || ''}
                                        onChange={(e) => setSelectedExamSessionId(Number(e.target.value))}
                                    >
                                        <option value="">Select Session</option>
                                        {sessions.map((s: any) => (
                                            <option key={s.id} value={s.id}>{s.name} {s.isActive && '(Active)'}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>

                            {/* Create category form ΓÇö ADMIN+ only */}
                            {rbac.canManageExamSettings && (
                                <form onSubmit={handleCreateCategory} className="mb-8 p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                    <h3 className="text-sm font-semibold text-slate-700 mb-3">Add New Exam Category</h3>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                        <div>
                                            <label className="block mb-1 text-xs font-medium text-gray-700">Name (e.g. SA1, Final)</label>
                                            <input type="text" value={newCategoryName} onChange={(e) => setNewCategoryName(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
                                        </div>
                                        <div>
                                            <label className="block mb-1 text-xs font-medium text-gray-700">Description</label>
                                            <input type="text" value={newCategoryDesc} onChange={(e) => setNewCategoryDesc(e.target.value)} className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
                                        </div>
                                    </div>
                                    <button type="submit" className="w-full px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 transition">Create Category</button>
                                </form>
                            )}

                            <div className="relative overflow-x-auto rounded-lg border border-gray-200">
                                <table className="w-full text-sm text-left text-gray-500">
                                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b">
                                        <tr>
                                            <th className="px-4 py-3">Name</th>
                                            <th className="px-4 py-3 text-center">Status</th>
                                            <th className="px-4 py-3 text-right">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {examCategories.map((c: any) => (
                                            <tr key={c.id} className="bg-white border-b hover:bg-gray-50">
                                                <td className="px-4 py-3 font-semibold text-slate-800">{c.name}</td>
                                                <td className="px-4 py-3 text-center">
                                                    {c.isActive ? (
                                                        <span className="px-2 py-1 bg-green-100 text-green-800 text-xs font-bold rounded uppercase">Active</span>
                                                    ) : (
                                                        <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs font-bold rounded uppercase">Inactive</span>
                                                    )}
                                                </td>
                                                <td className="px-4 py-3 text-right">
                                                    {rbac.canManageExamSettings && (
                                                        <button onClick={() => handleToggleCategory(c.id, c.isActive)} className="text-blue-600 hover:underline font-medium text-xs">
                                                            {c.isActive ? 'Deactivate' : 'Activate'}
                                                        </button>
                                                    )}
                                                </td>
                                            </tr>
                                        ))}
                                        {examCategories.length === 0 && (
                                            <tr><td colSpan={3} className="px-4 py-6 text-center text-gray-500 italic">No exam categories found.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>

                        {/* Final Result Settings panel */}
                        <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6">
                                <h2 className="text-xl font-bold text-slate-800">Final Result Settings</h2>
                                <div className="mt-2 sm:mt-0">
                                    <label className="text-xs text-slate-500 mr-2 uppercase font-semibold">For Session:</label>
                                    <select
                                        className="text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 p-1"
                                        value={selectedExamSessionId || ''}
                                        onChange={(e) => setSelectedExamSessionId(Number(e.target.value))}
                                    >
                                        <option value="">Select Session</option>
                                        {sessions.map((s: any) => (
                                            <option key={s.id} value={s.id}>{s.name} {s.isActive && '(Active)'}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>

                            <div className="mb-6">
                                <label className="block mb-2 text-sm font-semibold text-slate-700">Target Final Category</label>
                                <select
                                    className="w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 p-2"
                                    value={selectedTargetCategoryId || ''}
                                    onChange={handleTargetCategoryChange}
                                >
                                    <option value="">-- None Configured --</option>
                                    {examCategories.filter((c: any) => c.isActive).map((c: any) => (
                                        <option key={c.id} value={c.id}>{c.name}</option>
                                    ))}
                                </select>
                                <p className="text-xs text-slate-500 mt-1">This category's marks will be automatically generated by summing the contributing components.</p>
                            </div>

                            <p className="text-sm font-semibold text-slate-700 mb-3">Contributing Categories:</p>
                            <div className="flex flex-col gap-2 mb-6">
                                {examCategories.filter((c: any) => c.isActive).map((c: any) => {
                                    const isTarget = c.id === selectedTargetCategoryId;
                                    return (
                                        <label key={c.id} className={`flex items-center space-x-2 text-sm font-medium ${isTarget ? 'text-slate-400 cursor-not-allowed' : 'text-slate-800 cursor-pointer'}`}>
                                            <input
                                                type="checkbox"
                                                checked={selectedCategoryIds.includes(c.id)}
                                                onChange={() => toggleFinalResultCategory(c.id)}
                                                disabled={isTarget}
                                                className={`rounded ${isTarget ? 'text-gray-400 focus:ring-gray-400 cursor-not-allowed' : 'text-blue-600 focus:ring-blue-500'}`}
                                            />
                                            <span>{c.name} {isTarget && <span className="text-xs italic font-normal text-slate-400">(Selected as Target)</span>}</span>
                                        </label>
                                    );
                                })}
                                {examCategories.filter((c: any) => c.isActive).length === 0 && (
                                    <span className="text-sm text-slate-500 italic">Please create and activate exam categories first.</span>
                                )}
                            </div>
                            {rbac.canManageExamSettings && (
                                <button onClick={handleSaveSettings} className="px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 transition">Save Result Settings</button>
                            )}
                        </div>
                    </div>


                    {/* Grading System Engine */}
                    <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6">
                            <h2 className="text-xl font-bold text-slate-800">Grading System Rules</h2>
                            <div className="mt-2 sm:mt-0">
                                <label className="text-xs text-slate-500 mr-2 uppercase font-semibold">For Session:</label>
                                <select
                                    className="text-sm border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 p-1"
                                    value={selectedGradingSessionId || ''}
                                    onChange={(e) => setSelectedGradingSessionId(Number(e.target.value))}
                                >
                                    <option value="">Select Session</option>
                                    {sessions.map((s: any) => (
                                        <option key={s.id} value={s.id}>{s.name} {s.isActive && '(Active)'}</option>
                                    ))}
                                </select>
                            </div>
                        </div>

                        {/* Add grading band form ΓÇö ADMIN+ only */}
                        {rbac.canManageExamSettings && (
                            <form onSubmit={handleCreateGrading} className="mb-8 p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                <h3 className="text-sm font-semibold text-slate-700 mb-3">Add Grading Band</h3>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                                    <div>
                                        <label className="block mb-1 text-[10px] uppercase font-bold text-gray-500">Grade (e.g. A+)</label>
                                        <input type="text" value={newGradeName} onChange={(e) => setNewGradeName(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm py-1.5 px-3 focus:ring-blue-500" />
                                    </div>
                                    <div>
                                        <label className="block mb-1 text-[10px] uppercase font-bold text-gray-500">Min %</label>
                                        <input type="number" step="0.01" min="0" max="100" value={newGradeMin} onChange={(e) => setNewGradeMin(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm py-1.5 px-3 focus:ring-blue-500" />
                                    </div>
                                    <div>
                                        <label className="block mb-1 text-[10px] uppercase font-bold text-gray-500">Max % <span className="text-[9px] font-normal lowercase">(excluding)</span></label>
                                        <input type="number" step="0.01" min="0" max="100" value={newGradeMax} onChange={(e) => setNewGradeMax(e.target.value)} required className="w-full text-sm border-gray-300 rounded-md shadow-sm py-1.5 px-3 focus:ring-blue-500" />
                                    </div>
                                    <div className="flex items-center pt-5">
                                        <label className="flex items-center space-x-2 text-sm font-medium text-slate-800 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={newGradeIsFail}
                                                onChange={(e) => setNewGradeIsFail(e.target.checked)}
                                                className="rounded text-red-600 focus:ring-red-500 h-4 w-4"
                                            />
                                            <span className="text-red-600 font-bold">Is Fail?</span>
                                        </label>
                                    </div>
                                </div>
                                <button type="submit" disabled={!selectedGradingSessionId} className="w-full px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 transition disabled:bg-blue-300">Add Grade Band</button>
                            </form>
                        )}

                        {!selectedGradingSessionId ? (
                            <div className="py-8 text-center text-slate-500 italic">Please select an academic session above.</div>
                        ) : (
                            <div className="relative overflow-x-auto rounded-lg border border-gray-200">
                                <table className="w-full text-sm text-left text-gray-500">
                                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b">
                                        <tr>
                                            <th className="px-4 py-3">Grade</th>
                                            <th className="px-4 py-3 text-center">Min %</th>
                                            <th className="px-4 py-3 text-center">Max % <span className="text-[10px] font-normal normal-case">(excluding)</span></th>
                                            <th className="px-4 py-3 text-center">Effect</th>
                                            <th className="px-4 py-3 text-right">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {gradingSystems.map((g: any) => (
                                            <tr key={g.id} className="bg-white border-b hover:bg-gray-50">
                                                <td className="px-4 py-3 font-bold text-slate-800">{g.gradeName}</td>
                                                <td className="px-4 py-3 text-center font-medium">{g.minPercentage}%</td>
                                                <td className="px-4 py-3 text-center font-medium">{g.maxPercentage}%</td>
                                                <td className="px-4 py-3 text-center">
                                                    {g.isFailGrade ? (
                                                        <span className="px-2 py-1 bg-red-100 text-red-700 text-xs font-bold rounded uppercase">Fail</span>
                                                    ) : (
                                                        <span className="px-2 py-1 bg-green-100 text-green-700 text-xs font-bold rounded uppercase">Pass</span>
                                                    )}
                                                </td>
                                                <td className="px-4 py-3 text-right">
                                                    {rbac.canManageExamSettings && (
                                                        <button onClick={() => handleDeleteGrading(g.id)} className="text-red-500 hover:text-red-700 hover:underline font-medium text-xs">
                                                            Delete
                                                        </button>
                                                    )}
                                                </td>
                                            </tr>
                                        ))}
                                        {gradingSystems.length === 0 && (
                                            <tr><td colSpan={5} className="px-4 py-6 text-center text-gray-500 italic">No grading systems defined for this session.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>

                </div>
            )}

            {activeTab === 'holidays' && (
                <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                    <div className="flex justify-between items-center mb-6">
                        <h2 className="text-xl font-bold text-slate-800">School Holidays</h2>
                        {rbac.canManageHolidays && (
                            <button
                                onClick={() => handleOpenHolidayModal()}
                                className="bg-sky-600 hover:bg-sky-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
                            >
                                <Plus className="w-4 h-4" /> Add Holiday
                            </button>
                        )}
                    </div>

                    {loadingHolidays ? (
                        <div className="py-12"><Loader text="Loading holidays..." /></div>
                    ) : (
                        <div className="relative overflow-x-auto rounded-lg border border-gray-200">
                            <table className="w-full text-sm text-left text-gray-500">
                                <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b">
                                    <tr>
                                        <th className="px-4 py-3">Description</th>
                                        <th className="px-4 py-3">Date Range</th>
                                        <th className="px-4 py-3">Applicability</th>
                                        <th className="px-4 py-3 text-right">Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {holidays.map((h: any) => (
                                        <tr key={h.id} className="bg-white border-b hover:bg-gray-50">
                                            <td className="px-4 py-3 font-semibold text-slate-800">{h.description}</td>
                                            <td className="px-4 py-3 whitespace-nowrap">
                                                {new Date(h.startDate).toLocaleDateString()}
                                                {h.startDate !== h.endDate && ` - ${new Date(h.endDate).toLocaleDateString()}`}
                                            </td>
                                            <td className="px-4 py-3">
                                                {h.isEntireSchool ? (
                                                    <span className="flex items-center gap-1 text-green-700 text-xs font-bold bg-green-100 px-2 py-1 rounded-full w-max">
                                                        <CheckCircle2 className="w-3 h-3" /> Entire School
                                                    </span>
                                                ) : (
                                                    <div className="flex flex-wrap gap-1">
                                                        {h.classes?.map((c: any) => (
                                                            <span key={c.id} className="text-xs font-medium bg-blue-100 text-blue-800 px-2 py-0.5 rounded">
                                                                {c.name}
                                                            </span>
                                                        ))}
                                                    </div>
                                                )}
                                            </td>
                                            <td className="px-4 py-3 text-right">
                                                <div className="flex items-center justify-end space-x-2">
                                                    {rbac.canManageHolidays && (
                                                        <button onClick={() => handleOpenHolidayModal(h)} className="text-blue-600 hover:text-blue-800 p-1">
                                                            <Edit2 className="w-4 h-4" />
                                                        </button>
                                                    )}
                                                    {rbac.canDeleteHolidays && (
                                                        <button onClick={() => handleDeleteHoliday(h.id)} className="text-red-500 hover:text-red-700 p-1">
                                                            <Trash2 className="w-4 h-4" />
                                                        </button>
                                                    )}
                                                    {!rbac.canManageHolidays && (
                                                        <span className="text-xs text-slate-400 italic">View only</span>
                                                    )}
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                    {holidays.length === 0 && (
                                        <tr><td colSpan={4} className="px-4 py-8 text-center text-gray-500 italic">No holidays declared yet.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            )}

            {/* Holiday Modal */}
            {showHolidayModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm">
                    <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-lg max-h-[90vh] overflow-y-auto">
                        <div className="flex justify-between items-center mb-6 border-b pb-4">
                            <h2 className="text-2xl font-bold text-slate-800">{editingHolidayId ? 'Edit Holiday' : 'Add New Holiday'}</h2>
                            <button
                                onClick={() => setShowHolidayModal(false)}
                                className="text-gray-400 hover:text-gray-600 transition-colors"
                            >
                                <XCircle className="w-6 h-6" />
                            </button>
                        </div>

                        <form onSubmit={handleSaveHoliday} className="space-y-5">
                            <div>
                                <label className="block mb-1.5 text-sm font-semibold text-gray-900">Description</label>
                                <input
                                    type="text"
                                    value={holidayDesc}
                                    onChange={(e) => setHolidayDesc(e.target.value)}
                                    placeholder="e.g. Summer Vacation, Diwali"
                                    className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-sky-500 focus:border-sky-500 block w-full p-2.5"
                                    required
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block mb-1.5 text-sm font-semibold text-gray-900">Start Date</label>
                                    <input
                                        type="date"
                                        value={holidayStart}
                                        onChange={(e) => setHolidayStart(e.target.value)}
                                        className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-sky-500 focus:border-sky-500 block w-full p-2.5"
                                        required
                                    />
                                </div>
                                <div>
                                    <label className="block mb-1.5 text-sm font-semibold text-gray-900">End Date</label>
                                    <input
                                        type="date"
                                        value={holidayEnd}
                                        onChange={(e) => setHolidayEnd(e.target.value)}
                                        className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-sky-500 focus:border-sky-500 block w-full p-2.5"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="pt-2">
                                <label className="flex items-center space-x-3 cursor-pointer p-3 bg-slate-50 border border-slate-200 rounded-lg h-auto hover:bg-slate-100 transition-colors">
                                    <input
                                        type="checkbox"
                                        checked={holidayIsEntireSchool}
                                        onChange={(e) => setHolidayIsEntireSchool(e.target.checked)}
                                        className="w-5 h-5 text-sky-600 bg-white border-gray-300 rounded focus:ring-sky-500"
                                    />
                                    <div>
                                        <span className="text-sm font-bold text-slate-800 block">Is this holiday for the Entire School?</span>
                                        <span className="text-xs text-slate-500 block">Uncheck to select specific classes only.</span>
                                    </div>
                                </label>
                            </div>

                            {!holidayIsEntireSchool && (
                                <div className="mt-4 p-4 border border-gray-200 rounded-lg bg-gray-50">
                                    <div className="flex justify-between items-center mb-3">
                                        <label className="block text-sm font-semibold text-gray-900">Select Classes</label>
                                        <button
                                            type="button"
                                            onClick={handleHolidaySelectAllClasses}
                                            className="text-xs text-sky-600 hover:text-sky-800 font-bold hover:underline"
                                        >
                                            {holidayClassIds.length === classes.length ? 'Deselect All' : 'Select All'}
                                        </button>
                                    </div>
                                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 overflow-y-auto max-h-40">
                                        {classes.map((c: any) => (
                                            <label key={c.id} className="flex items-center space-x-2 cursor-pointer p-2 hover:bg-white rounded-md transition-colors border border-transparent hover:border-gray-200">
                                                <input
                                                    type="checkbox"
                                                    checked={holidayClassIds.includes(c.id)}
                                                    onChange={(e) => {
                                                        if (e.target.checked) setHolidayClassIds([...holidayClassIds, c.id]);
                                                        else setHolidayClassIds(holidayClassIds.filter(id => id !== c.id));
                                                    }}
                                                    className="w-4 h-4 text-sky-600 bg-white border-gray-300 rounded focus:ring-sky-500"
                                                />
                                                <span className="text-sm font-medium text-gray-700">{c.name}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="flex justify-end gap-3 pt-5 border-t mt-6">
                                <button
                                    type="button"
                                    onClick={() => setShowHolidayModal(false)}
                                    className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 focus:ring-4 focus:outline-none focus:ring-gray-200"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    disabled={isSavingHoliday || (!holidayIsEntireSchool && holidayClassIds.length === 0)}
                                    className="px-5 py-2 text-sm font-medium text-white bg-sky-600 rounded-lg hover:bg-sky-700 focus:ring-4 focus:outline-none focus:ring-sky-300 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                                >
                                    {isSavingHoliday ? "Saving..." : (editingHolidayId ? "Update Holiday" : "Create Holiday")}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { API_BASE_URL } from "@/lib/api";
import { Country, State, City } from "country-state-city";
import { authFetch, getUser } from "@/lib/auth";
import toast from "react-hot-toast";

export default function EditStaffPage() {
    const router = useRouter();
    const params = useParams();
    const id = params?.id as string;
    const currentUser = getUser();
    const isAdmin = currentUser?.role === "SUPER_ADMIN" || currentUser?.role === "ADMIN";

    const [formData, setFormData] = useState({
        firstName: "",
        lastName: "",
        email: "",
        mobile: "",
        alternateMobile: "",
        gender: "",
        dateOfBirth: "",
        bloodGroup: "",
        aadhaarNumber: "",
        category: "",
        religion: "",
        fathersName: "",
        mothersName: "",
        staffCategory: "",
        designationId: "",
        isActive: true,
        address: {
            addressLine1: "",
            addressLine2: "",
            landmark: "",
            city: "",
            state: "",
            postalCode: "",
            country: "IN",
        },
    });
    const [assignments, setAssignments] = useState<any[]>([]);

    // Assignment Form State
    const [classes, setClasses] = useState<any[]>([]);
    const [subjects, setSubjects] = useState<any[]>([]);
    const [selectedClass, setSelectedClass] = useState("");
    const [selectedSection, setSelectedSection] = useState("");
    const [selectedSubject, setSelectedSubject] = useState("");
    const [assignLoading, setAssignLoading] = useState(false);
    const [assignError, setAssignError] = useState("");

    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState("");

    // Address cascading
    const countries = Country.getAllCountries();
    const [states, setStates] = useState<any[]>(State.getStatesOfCountry("IN"));
    const [cities, setCities] = useState<any[]>([]);

    useEffect(() => {
        if (formData.address.country) {
            setStates(State.getStatesOfCountry(formData.address.country));
        }
    }, [formData.address.country]);

    useEffect(() => {
        if (formData.address.country && formData.address.state) {
            setCities(City.getCitiesOfState(formData.address.country, formData.address.state));
        } else {
            setCities([]);
        }
    }, [formData.address.country, formData.address.state]);

    // Inline designation creation state
    const [showDesModal, setShowDesModal] = useState(false);
    const [newDesTitle, setNewDesTitle] = useState("");
    const [creatingDes, setCreatingDes] = useState(false);

    const [designations, setDesignations] = useState<any[]>([]);

    const fetchTeacherDetails = async () => {
        try {
            const [teacherRes, classesRes, subjectsRes, desigRes] = await Promise.all([
                authFetch(`${API_BASE_URL}/staff/${id}`),
                authFetch(`${API_BASE_URL}/classes`),
                authFetch(`${API_BASE_URL}/subjects`),
                authFetch(`${API_BASE_URL}/designations`)
            ]);

            if (!teacherRes.ok) throw new Error("Failed to fetch staff details");
            const teacher = await teacherRes.json();

            if (teacher) {
                // Map names to ISO codes for dropdowns
                const countryCode = teacher.address?.country 
                    ? Country.getAllCountries().find(c => 
                        c.name.toLowerCase() === teacher.address.country.toLowerCase() ||
                        c.isoCode === teacher.address.country
                      )?.isoCode || "IN" 
                    : "IN";
                
                const stateCode = teacher.address?.state
                    ? State.getStatesOfCountry(countryCode).find(s => 
                        s.name.toLowerCase() === teacher.address.state.toLowerCase() ||
                        s.isoCode === teacher.address.state
                      )?.isoCode || ""
                    : "";
                
                // Also try to match city name case-insensitively if stateCode is available
                let cityName = teacher.address?.city || "";
                if (stateCode && cityName) {
                    const matchedCity = City.getCitiesOfState(countryCode, stateCode).find(c => 
                        c.name.toLowerCase() === cityName.toLowerCase()
                    );
                    if (matchedCity) cityName = matchedCity.name;
                }

                setFormData({
                    firstName: teacher.firstName || "",
                    lastName: teacher.lastName || "",
                    email: teacher.email || "",
                    mobile: teacher.mobile || "",
                    alternateMobile: teacher.alternateMobile || "",
                    gender: teacher.gender || "",
                    dateOfBirth: teacher.dateOfBirth ? new Date(teacher.dateOfBirth).toISOString().split('T')[0] : "",
                    bloodGroup: teacher.bloodGroup || "",
                    aadhaarNumber: teacher.aadhaarNumber || "",
                    category: teacher.category || "",
                    religion: teacher.religion || "",
                    fathersName: teacher.fathersName || "",
                    mothersName: teacher.mothersName || "",
                    staffCategory: teacher.staffCategory || "",
                    designationId: teacher.designation?.id || "",
                    isActive: teacher.isActive ?? true,
                    address: {
                        addressLine1: teacher.address?.addressLine1 || "",
                        addressLine2: teacher.address?.addressLine2 || "",
                        landmark: teacher.address?.landmark || "",
                        city: cityName,
                        state: stateCode,
                        postalCode: teacher.address?.postalCode || "",
                        country: countryCode,
                    },
                });
                const activeAssignments = teacher.subjectAssignments?.filter((a: any) => a.isActive) || [];
                setAssignments(activeAssignments);
            } else {
                setError("Staff not found");
            }

            if (classesRes.ok) setClasses(await classesRes.json());
            if (subjectsRes.ok) setSubjects(await subjectsRes.json());
            if (desigRes.ok) setDesignations(await desigRes.json());
        } catch (err) {
            setError("Failed to load data");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (!id) return;
        fetchTeacherDetails();
    }, [id]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const target = e.target as HTMLInputElement;
        const value = target.type === 'checkbox' ? target.checked : target.value;

        if (target.name === 'designationId' && value === 'CREATE_NEW') {
            setShowDesModal(true);
            return;
        }

        setFormData({ ...formData, [target.name]: value });
    };

    const handleAddressChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        if (name === "country") {
            setFormData(prev => ({ ...prev, address: { ...prev.address, country: value, state: "", city: "" } }));
        } else if (name === "state") {
            setFormData(prev => ({ ...prev, address: { ...prev.address, state: value, city: "" } }));
        } else {
            setFormData(prev => ({ ...prev, address: { ...prev.address, [name]: value } }));
        }
    };

    const handleCreateDesignation = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newDesTitle.trim()) return;
        setCreatingDes(true);
        try {
            const res = await authFetch(`${API_BASE_URL}/designations`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ title: newDesTitle.trim(), description: "" })
            });
            if (res.ok) {
                const newD = await res.json();
                setDesignations([...designations, newD]);
                setFormData({ ...formData, designationId: newD.id });
                setShowDesModal(false);
                setNewDesTitle("");
                toast.success("Designation created successfully");
            } else {
                toast.error("Failed to create designation");
            }
        } catch (err) {
            toast.error("Failed to create designation");
        }
        setCreatingDes(false);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setError("");

        try {
            const payload = { ...formData };
            
            // Resolve country/state ISO codes ΓåÆ full names
            if (
                payload.address.addressLine1 &&
                payload.address.city &&
                payload.address.state &&
                payload.address.postalCode
            ) {
                const countryObj = Country.getCountryByCode(payload.address.country);
                const stateObj = State.getStateByCodeAndCountry(payload.address.state, payload.address.country);
                payload.address.country = countryObj ? countryObj.name : payload.address.country;
                payload.address.state = stateObj ? stateObj.name : payload.address.state;
            } else {
                delete (payload as any).address;
            }

            if (payload.designationId) {
                payload.designationId = parseInt(payload.designationId as any) as any;
            } else {
                delete (payload as any).designationId;
            }

            const res = await authFetch(`${API_BASE_URL}/staff/${id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload),
            });

            if (!res.ok) {
                const errData = await res.json();
                throw new Error(errData.message || "Failed to update staff");
            }

            router.push("/dashboard/staff");
            router.refresh();
        } catch (err: any) {
            console.error(err);
            setError(err.message || "Failed to update staff. Please try again.");
        } finally {
            setSaving(false);
        }
    };

    const handleAssignSubject = async (e: React.FormEvent) => {
        e.preventDefault();
        setAssignLoading(true);
        setAssignError("");
        try {
            const res = await authFetch(`${API_BASE_URL}/staff/${id}/assign-subject`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    classId: parseInt(selectedClass),
                    sectionId: parseInt(selectedSection),
                    subjectId: parseInt(selectedSubject)
                })
            });

            if (!res.ok) {
                const errData = await res.json();
                throw new Error(errData.message || "Failed to assign subject");
            }

            await fetchTeacherDetails();
            setSelectedClass("");
            setSelectedSection("");
            setSelectedSubject("");
        } catch (err: any) {
            console.error(err);
            setAssignError(err.message || "Failed to assign subject");
        } finally {
            setAssignLoading(false);
        }
    };

    const handleUnassignSubject = async (assignmentId: number) => {
        if (!confirm("Are you sure you want to unassign this subject?")) return;
        try {
            const res = await authFetch(`${API_BASE_URL}/staff/${id}/assignments/${assignmentId}`, {
                method: "DELETE",
            });
            if (!res.ok) throw new Error("Failed to unassign subject");
            await fetchTeacherDetails();
        } catch (err) {
            console.error(err);
            alert("Failed to unassign subject");
        }
    };

    if (loading) return <div className="p-4">Loading...</div>;
    if (error && !formData.firstName) return <div className="p-4 text-red-600">{error}</div>;

    const sectionsForClass = classes.find(c => c.id.toString() === selectedClass)?.sections || [];

    return (
        <main className="p-4 bg-slate-50 min-h-screen space-y-6">
            <div className="max-w-4xl mx-auto bg-white p-8 rounded-lg shadow-sm border border-slate-200">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-slate-800">Edit Staff</h2>
                    <Link href="/dashboard/staff" className="text-blue-600 hover:underline">
                        &larr; Back to Staff
                    </Link>
                </div>

                {error && (
                    <div className="p-4 mb-4 text-sm text-red-800 rounded-lg bg-red-50" role="alert">
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-8">
                    {/* ΓöÇΓöÇ BASIC INFORMATION ΓöÇΓöÇ */}
                    <div>
                        <h3 className="text-sm font-semibold text-slate-600 uppercase tracking-wide border-b border-slate-200 pb-2 mb-4">Basic Information</h3>
                        <div className="grid gap-4 sm:grid-cols-2 md:grid-cols-3">
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">First Name <span className="text-red-500">*</span></label>
                                <input type="text" name="firstName" value={formData.firstName} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Last Name <span className="text-red-500">*</span></label>
                                <input type="text" name="lastName" value={formData.lastName} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Gender</label>
                                <select name="gender" value={formData.gender} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                    <option value="">Select Gender</option>
                                    <option value="Male">Male</option>
                                    <option value="Female">Female</option>
                                    <option value="Others">Others</option>
                                </select>
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Date of Birth</label>
                                <input type="date" name="dateOfBirth" value={formData.dateOfBirth} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Blood Group</label>
                                <select name="bloodGroup" value={formData.bloodGroup} onChange={handleChange}
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                    <option value="">Select Group</option>
                                    <option value="A+">A+</option><option value="A-">A-</option>
                                    <option value="B+">B+</option><option value="B-">B-</option>
                                    <option value="O+">O+</option><option value="O-">O-</option>
                                    <option value="AB+">AB+</option><option value="AB-">AB-</option>
                                </select>
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Aadhaar Number <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" name="aadhaarNumber" value={formData.aadhaarNumber} onChange={handleChange} maxLength={14}
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ CONTACT INFORMATION ΓöÇΓöÇ */}
                    <div>
                        <h3 className="text-sm font-semibold text-slate-600 uppercase tracking-wide border-b border-slate-200 pb-2 mb-4">Contact Information</h3>
                        <div className="grid gap-4 sm:grid-cols-3">
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Email Address <span className="text-red-500">*</span></label>
                                <input type="email" name="email" value={formData.email} onChange={handleChange} required readOnly
                                    className="bg-gray-100 border border-gray-300 text-gray-600 text-sm rounded-lg block w-full p-2.5 cursor-not-allowed" title="Email cannot be changed" />
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Mobile <span className="text-red-500">*</span></label>
                                <input type="tel" name="mobile" value={formData.mobile} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Alternate Mobile <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="tel" name="alternateMobile" value={formData.alternateMobile} onChange={handleChange}
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ ADDRESS INFORMATION ΓöÇΓöÇ */}
                    <div>
                        <h3 className="text-sm font-semibold text-slate-600 uppercase tracking-wide border-b border-slate-200 pb-2 mb-4">Address Information</h3>
                        <div className="grid gap-4 sm:grid-cols-2">
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Country <span className="text-red-500">*</span></label>
                                <select name="country" value={formData.address.country} onChange={handleAddressChange}
                                    className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                    <option value="">Select Country</option>
                                    {countries.map(c => <option key={c.isoCode} value={c.isoCode}>{c.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">State <span className="text-red-500">*</span></label>
                                <select name="state" value={formData.address.state} onChange={handleAddressChange} disabled={!states.length}
                                    className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:opacity-50">
                                    <option value="">Select State</option>
                                    {states.map(s => <option key={s.isoCode} value={s.isoCode}>{s.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">City <span className="text-red-500">*</span></label>
                                {cities.length > 0 ? (
                                    <select name="city" value={formData.address.city} onChange={handleAddressChange}
                                        className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                        <option value="">Select City</option>
                                        {cities.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                                    </select>
                                ) : (
                                    <input type="text" name="city" value={formData.address.city} onChange={handleAddressChange}
                                        placeholder="City name" disabled={!formData.address.state}
                                        className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:opacity-50" />
                                )}
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Postal Code <span className="text-red-500">*</span></label>
                                <input type="text" name="postalCode" value={formData.address.postalCode} onChange={handleAddressChange}
                                    placeholder="PIN code" className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div className="sm:col-span-2">
                                <label className="block mb-1 text-sm font-medium text-gray-900">Address Line 1 <span className="text-red-500">*</span></label>
                                <input type="text" name="addressLine1" value={formData.address.addressLine1} onChange={handleAddressChange}
                                    placeholder="Street address, Flat no, etc." className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div className="sm:col-span-2">
                                <label className="block mb-1 text-sm font-medium text-gray-900">Address Line 2 <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" name="addressLine2" value={formData.address.addressLine2} onChange={handleAddressChange}
                                    placeholder="Apartment, suite, unit, etc." className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div className="sm:col-span-2">
                                <label className="block mb-1 text-sm font-medium text-gray-900">Landmark <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" name="landmark" value={formData.address.landmark} onChange={handleAddressChange}
                                    placeholder="Near..." className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ DEMOGRAPHICS ΓöÇΓöÇ */}
                    <div>
                        <h3 className="text-sm font-semibold text-slate-600 uppercase tracking-wide border-b border-slate-200 pb-2 mb-4">Demographics</h3>
                        <div className="grid gap-4 sm:grid-cols-2 md:grid-cols-4">
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Category</label>
                                <select name="category" value={formData.category} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                    <option value="">Select Category</option>
                                    {["General", "SC", "ST", "OBC", "EWS"].map(c => <option key={c} value={c}>{c}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Religion</label>
                                <select name="religion" value={formData.religion} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                    <option value="">Select Religion</option>
                                    {["HINDU", "MUSLIM", "SIKH", "CHRISTIAN", "PARSI", "OTHERS"].map(r => (
                                        <option key={r} value={r}>{r[0] + r.slice(1).toLowerCase()}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Father&apos;s Name <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" name="fathersName" value={formData.fathersName} onChange={handleChange}
                                    placeholder="Father's name" className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Mother&apos;s Name <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" name="mothersName" value={formData.mothersName} onChange={handleChange}
                                    placeholder="Mother's name" className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ EMPLOYMENT DETAILS ΓöÇΓöÇ */}
                    <div>
                        <h3 className="text-sm font-semibold text-slate-600 uppercase tracking-wide border-b border-slate-200 pb-2 mb-4">Employment Details</h3>
                        <div className="grid gap-4 sm:grid-cols-2 md:grid-cols-3">
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Staff Category <span className="text-red-500">*</span></label>
                                <select name="staffCategory" value={formData.staffCategory} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                    <option value="">Select Category</option>
                                    <option value="Teaching Staff">Teaching Staff</option>
                                    <option value="Management">Management</option>
                                    <option value="Support Staff">Support Staff</option>
                                    <option value="Admin Staff">Admin Staff</option>
                                </select>
                            </div>
                            <div>
                                <label className="block mb-1 text-sm font-medium text-gray-900">Designation <span className="text-red-500">*</span></label>
                                <select name="designationId" value={String(formData.designationId)} onChange={handleChange} required
                                    className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                    <option value="">Select Designation</option>
                                    {designations.map(d => <option key={d.id} value={d.id}>{d.title}</option>)}
                                    {isAdmin && <option value="CREATE_NEW" className="font-bold text-blue-600">+ Create New Designation</option>}
                                </select>
                            </div>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ ACCOUNT STATUS ΓöÇΓöÇ */}
                    <div className="flex items-center">
                        <input id="isActive" name="isActive" type="checkbox" checked={formData.isActive} onChange={handleChange}
                            className="w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500" />
                        <label htmlFor="isActive" className="ml-2 text-sm font-medium text-gray-900">Account Active</label>
                    </div>

                    <div className="flex items-center space-x-4 border-t pt-6">
                        <button type="submit" disabled={saving} className="text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:outline-none focus:ring-blue-300 font-medium rounded-lg text-sm w-full sm:w-auto px-5 py-2.5 text-center disabled:opacity-50">
                            {saving ? 'Saving...' : 'Save Changes'}
                        </button>
                        <Link href="/dashboard/staff" className="text-gray-900 bg-white border border-gray-300 focus:outline-none hover:bg-gray-100 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-2.5">
                            Cancel
                        </Link>
                    </div>
                </form>
            </div>

            {/* Subject Assignments */}
            {formData.staffCategory === 'Teaching Staff' && (
            <div className="max-w-4xl mx-auto bg-white p-8 rounded-lg shadow-sm border border-slate-200">
                <h3 className="text-xl font-bold mb-4 text-slate-800">Subject Assignments</h3>

                <div className="mb-6">
                    <h4 className="font-semibold text-gray-700 mb-2">Current Assignments</h4>
                    {assignments.length === 0 ? (
                        <p className="text-gray-500 italic">No active subject assignments.</p>
                    ) : (
                        <div className="relative overflow-x-auto">
                            <table className="w-full text-sm text-left text-gray-500">
                                <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                                    <tr>
                                        <th scope="col" className="px-6 py-3">Subject</th>
                                        <th scope="col" className="px-6 py-3">Class</th>
                                        <th scope="col" className="px-6 py-3">Section</th>
                                        <th scope="col" className="px-6 py-3">Action</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {assignments.map((assignment: any) => (
                                        <tr key={assignment.id} className="bg-white border-b">
                                            <td className="px-6 py-4 font-medium text-gray-900">{assignment.subject?.name}</td>
                                            <td className="px-6 py-4">{assignment.class?.name}</td>
                                            <td className="px-6 py-4">{assignment.section?.name}</td>
                                            <td className="px-6 py-4">
                                                <button
                                                    type="button"
                                                    onClick={() => handleUnassignSubject(assignment.id)}
                                                    className="text-white bg-red-600 hover:bg-red-700 focus:ring-4 focus:outline-none focus:ring-red-300 font-medium rounded-lg text-xs px-3 py-1.5"
                                                >
                                                    Unassign
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>

                <div className="border-t pt-6">
                    <h4 className="font-semibold text-gray-700 mb-4">Assign New Subject</h4>
                    <form onSubmit={handleAssignSubject} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                        <div>
                            <label className="block mb-2 text-sm font-medium text-gray-900">Class</label>
                            <select value={selectedClass} onChange={(e) => { setSelectedClass(e.target.value); setSelectedSection(""); }} className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                <option value="">Select Class</option>
                                {classes.map((c: any) => (
                                    <option key={c.id} value={c.id}>{c.name}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block mb-2 text-sm font-medium text-gray-900">Section</label>
                            <select value={selectedSection} onChange={(e) => setSelectedSection(e.target.value)} disabled={!selectedClass} className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5 disabled:opacity-50">
                                <option value="">Select Section</option>
                                {sectionsForClass.map((s: any) => (
                                    <option key={s.id} value={s.id}>{s.name}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block mb-2 text-sm font-medium text-gray-900">Subject</label>
                            <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5">
                                <option value="">Select Subject</option>
                                {subjects.map((s: any) => (
                                    <option key={s.id} value={s.id}>{s.name}</option>
                                ))}
                            </select>
                        </div>
                        <button type="submit" disabled={assignLoading || !selectedClass || !selectedSection || !selectedSubject} className="text-white bg-green-600 hover:bg-green-700 focus:ring-4 focus:outline-none focus:ring-green-300 font-medium rounded-lg text-sm px-5 py-2.5 text-center disabled:opacity-50">
                            {assignLoading ? 'Assigning...' : 'Assign'}
                        </button>
                    </form>
                    {assignError && (
                        <div className="mt-3 p-3 text-sm text-red-800 rounded-lg bg-red-50" role="alert">
                            {assignError}
                        </div>
                    )}
                </div>
            </div>
            )}

            {/* Designation Creation Modal */}
            {showDesModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
                    <div className="bg-white p-6 rounded-lg shadow-lg w-full max-w-sm">
                        <h3 className="text-lg font-bold mb-4">Create New Designation</h3>
                        <form onSubmit={handleCreateDesignation}>
                            <input type="text" value={newDesTitle} onChange={e => setNewDesTitle(e.target.value)} placeholder="Designation Title (e.g. Principal)" className="w-full border p-2 rounded mb-4 focus:ring-2 focus:ring-blue-500 focus:outline-none" autoFocus required />
                            <div className="flex justify-end gap-2">
                                <button type="button" onClick={() => { setShowDesModal(false); setNewDesTitle(""); setFormData({...formData, designationId: ""}); }} className="px-4 py-2 text-sm bg-gray-200 rounded hover:bg-gray-300">Cancel</button>
                                <button type="submit" disabled={creatingDes} className="px-4 py-2 text-sm bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50">{creatingDes ? "Creating..." : "Create"}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import Table from "../../../components/Table";
import { API_BASE_URL } from "@/lib/api";
import { useRbac } from "@/lib/rbac";
import { authFetch } from "@/lib/auth";
import Papa from "papaparse";

const PAGE_SIZE_OPTIONS = [10, 25, 50, 100];

export default function TeachersPage() {
    const [teachers, setTeachers] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const rbac = useRbac();

    // Search Params
    const [searchId, setSearchId] = useState("");
    const [searchFirstName, setSearchFirstName] = useState("");
    const [searchLastName, setSearchLastName] = useState("");
    const [searchEmail, setSearchEmail] = useState("");
    const [searchStatus, setSearchStatus] = useState("");
    const [searchCategory, setSearchCategory] = useState("");
    const [searchDesignation, setSearchDesignation] = useState("");

    const [designations, setDesignations] = useState<any[]>([]);

    // Pagination
    // Pagination
    const [page, setPage] = useState(1);
    const [pageSize, setPageSize] = useState(25);
    const [total, setTotal] = useState(0);

    // Bulk Import State
    const [showImportModal, setShowImportModal] = useState(false);
    const [importFile, setImportFile] = useState<File | null>(null);
    const [importLoading, setImportLoading] = useState(false);
    const [importSummary, setImportSummary] = useState<{ successful: number; failed: number; errors: string[] } | null>(null);

    const totalPages = Math.ceil(total / pageSize);

    const buildParams = (overridePage?: number, overrideSize?: number) => {
        const params = new URLSearchParams();
        if (searchId) params.append("id", searchId);
        if (searchFirstName) params.append("firstName", searchFirstName);
        if (searchLastName) params.append("lastName", searchLastName);
        if (searchEmail) params.append("email", searchEmail);
        if (searchStatus !== "") params.append("isActive", searchStatus);
        if (searchCategory) params.append("staffCategory", searchCategory);
        if (searchDesignation) params.append("designationId", searchDesignation);
        params.append("page", String(overridePage ?? page));
        params.append("limit", String(overrideSize ?? pageSize));
        return params;
    };

    const fetchTeachers = async (overridePage?: number, overrideSize?: number) => {
        setLoading(true);
        try {
            const params = buildParams(overridePage, overrideSize);
            const res = await authFetch(`${API_BASE_URL}/staff?${params.toString()}`);
            if (res.ok) {
                const data = await res.json();
                if (data && data.data) {
                    setTeachers(data.data);
                    setTotal(data.total);
                    setPage(data.page);
                } else {
                    setTeachers(Array.isArray(data) ? data : []);
                    setTotal(Array.isArray(data) ? data.length : 0);
                }
            }
        } catch (err) {
            console.error("Failed to fetch teachers", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchTeachers(1, 25);
        authFetch(`${API_BASE_URL}/designations`)
            .then(res => res.ok ? res.json() : [])
            .then(data => setDesignations(data))
            .catch(() => setDesignations([]));
    }, []);

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setPage(1);
        fetchTeachers(1);
    };

    const handleReset = () => {
        setSearchId("");
        setSearchFirstName("");
        setSearchLastName("");
        setSearchEmail("");
        setSearchStatus("");
        setSearchCategory("");
        setSearchDesignation("");
        setPage(1);
        setTimeout(() => fetchTeachers(1), 0);
    };

    const handlePageChange = (newPage: number) => {
        if (newPage < 1 || newPage > totalPages) return;
        setPage(newPage);
        fetchTeachers(newPage);
    };

    const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const newSize = parseInt(e.target.value);
        setPageSize(newSize);
        setPage(1);
        fetchTeachers(1, newSize);
    };

    const handleDownloadTemplate = () => {
        const headers = [
            "firstName", "lastName", "email", "mobile", "alternateMobile", "gender", "dateOfBirth", "bloodGroup", "aadhaarNumber", 
            "category", "religion", "fathersName", "mothersName", "staffCategory", "designationId", "isActive", "role",
            "department", "joiningDate", "qualification",
            "addressLine1", "addressLine2", "landmark", "city", "state", "postalCode", "country"
        ].join(",");
        const dummyRow = "\nJohn,Doe,john.doe@colegios.in,9876543210,,Male,1990-01-01,O+,123412341234,General,HINDU,,,Teaching Staff,4,true,TEACHER,Science,2023-05-01,M.Sc,Street 1,,Near Park,New Delhi,Delhi,110001,INDIA";
        
        const blob = new Blob([headers + dummyRow], { type: 'text/csv' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'staff_import_template.csv';
        a.click();
    };

    const handleImportSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!importFile) return;

        setImportLoading(true);
        setImportSummary(null);

        Papa.parse(importFile, {
            header: true,
            skipEmptyLines: true,
            complete: async (results) => {
                try {
                    const staffData = results.data.map((row: any) => ({
                         ...row,
                         designationId: row.designationId ? parseInt(row.designationId) : undefined,
                         category: row.category || undefined,
                         religion: row.religion || undefined,
                         gender: row.gender || undefined,
                         isActive: row.isActive === 'false' ? false : true,
                         role: row.role || 'TEACHER',
                         address: {
                             addressLine1: row.addressLine1 || undefined,
                             addressLine2: row.addressLine2 || undefined,
                             landmark: row.landmark || undefined,
                             city: row.city || undefined,
                             state: row.state || undefined,
                             postalCode: row.postalCode || undefined,
                             country: row.country || 'INDIA'
                         }
                    }));

                    const res = await authFetch(`${API_BASE_URL}/staff/bulk-import`, {
                        method: "POST",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({ staffData })
                    });

                    if (res.ok) {
                        const data = await res.json();
                        setImportSummary(data);
                        fetchTeachers(1);
                    } else {
                        const err = await res.json();
                        alert("Import failed: " + (err.message || "Unknown error"));
                    }
                } catch (error) {
                    console.error("Bulk import error", error);
                    alert("An error occurred during import.");
                } finally {
                    setImportLoading(false);
                }
            },
            error: (err: any) => {
                alert("Failed to read CSV file: " + err.message);
                setImportLoading(false);
            }
        });
    };

    const columns = [
        { header: "ID", accessor: "id", sortable: true },
        {
            header: "Name",
            sortable: true,
            sortKey: "firstName",
            render: (row: any) => `${row.firstName} ${row.lastName}`
        },
        { header: "Email", accessor: "email", sortable: true },
        {
            header: "Designation",
            render: (row: any) => row.designation?.title || '-'
        },
        {
            header: "Class Teacher Of",
            render: (row: any) => row.classTeacherOf && row.classTeacherOf.length > 0
                ? row.classTeacherOf.map((s: any) => `${s.class?.name || ''}-${s.name}`).filter(Boolean).join(', ')
                : '-'
        },
        {
            header: "Subjects",
            render: (row: any) => row.subjectAssignments && row.subjectAssignments.length > 0
                ? row.subjectAssignments.map((sa: any) => `${sa.subject?.name} (${sa.class?.name}-${sa.section?.name})`).join(', ')
                : '-'
        },
        {
            header: "Status",
            render: (row: any) => (
                <span className={`px-2 py-1 font-semibold leading-tight ${row.isActive ? 'text-green-700 bg-green-100' : 'text-red-700 bg-red-100'} rounded-full`}>
                    {row.isActive ? 'Active' : 'Inactive'}
                </span>
            )
        },
        {
            header: "Actions",
            render: (row: any) => rbac.canManageTeachers ? (
                <Link href={`/dashboard/staff/${row.id}/edit`} className="font-medium text-blue-600 hover:underline">Edit</Link>
            ) : (
                <Link href={`/dashboard/staff/${row.id}/edit`} className="font-medium text-slate-400 text-xs">View</Link>
            )
        }
    ];

    const getPageNumbers = () => {
        const pages: (number | '...')[] = [];
        if (totalPages <= 7) {
            for (let i = 1; i <= totalPages; i++) pages.push(i);
        } else {
            pages.push(1);
            if (page > 3) pages.push('...');
            const start = Math.max(2, page - 1);
            const end = Math.min(totalPages - 1, page + 1);
            for (let i = start; i <= end; i++) pages.push(i);
            if (page < totalPages - 2) pages.push('...');
            pages.push(totalPages);
        }
        return pages;
    };

    return (
        <main className="p-4 bg-slate-50 min-h-screen">
            <div className="max-w-7xl mx-auto">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
                    <h1 className="text-2xl font-bold text-slate-800">Staff Management</h1>
                    {rbac.canManageTeachers && (
                        <div className="flex gap-2 w-full sm:w-auto">
                            <button onClick={() => setShowImportModal(true)} className="text-gray-700 bg-white border border-gray-300 hover:bg-gray-50 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-2.5 focus:outline-none w-full sm:w-auto text-center whitespace-nowrap shadow-sm">
                                Import CSV
                            </button>
                            <Link href="/dashboard/staff/new" className="text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:ring-blue-300 font-medium rounded-lg text-sm px-5 py-2.5 focus:outline-none w-full sm:w-auto text-center whitespace-nowrap shadow-sm">
                                Add Staff
                            </Link>
                        </div>
                    )}
                </div>

                {/* Advanced Search Filter */}
                <div className="bg-white p-5 rounded-lg shadow-sm border border-slate-200 mb-6">
                    <h2 className="text-lg font-semibold text-slate-700 mb-4">Search Staff</h2>
                    <form onSubmit={handleSearch}>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-7 gap-4 mb-4">
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Teacher ID</label>
                                <input type="text" value={searchId} onChange={e => setSearchId(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="e.g. 1" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">First Name</label>
                                <input type="text" value={searchFirstName} onChange={e => setSearchFirstName(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="First Name" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Last Name</label>
                                <input type="text" value={searchLastName} onChange={e => setSearchLastName(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="Last Name" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Email</label>
                                <input type="text" value={searchEmail} onChange={e => setSearchEmail(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="Email Address" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Category</label>
                                <select value={searchCategory} onChange={e => setSearchCategory(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2">
                                    <option value="">All Categories</option>
                                    <option value="Teaching Staff">Teaching Staff</option>
                                    <option value="Management">Management</option>
                                    <option value="Support Staff">Support Staff</option>
                                    <option value="Admin Staff">Admin Staff</option>
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Designation</label>
                                <select value={searchDesignation} onChange={e => setSearchDesignation(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2">
                                    <option value="">All Designations</option>
                                    {designations.map(d => (
                                        <option key={d.id} value={d.id}>{d.title}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Status</label>
                                <select value={searchStatus} onChange={e => setSearchStatus(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2">
                                    <option value="">All Statuses</option>
                                    <option value="true">Active</option>
                                    <option value="false">Inactive</option>
                                </select>
                            </div>
                        </div>
                        <div className="flex justify-end gap-2">
                            <button type="button" onClick={handleReset} className="px-5 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 focus:ring-4 focus:ring-gray-200">
                                Reset
                            </button>
                            <button type="submit" className="px-5 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 focus:ring-4 focus:ring-blue-300">
                                Search
                            </button>
                        </div>
                    </form>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                    <Table
                        columns={columns}
                        data={teachers}
                        loading={loading}
                        defaultSortColumn="id"
                        defaultSortDirection="asc"
                        emptyMessage="No teachers found matching the search criteria."
                    />

                    {/* Pagination Controls */}
                    {!loading && total > 0 && (
                        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mt-4 pt-4 border-t border-slate-200">
                            <div className="flex items-center gap-2 text-sm text-slate-600">
                                <span>Rows per page:</span>
                                <select
                                    value={pageSize}
                                    onChange={handlePageSizeChange}
                                    className="border border-gray-300 rounded-md text-sm p-1"
                                >
                                    {PAGE_SIZE_OPTIONS.map(opt => (
                                        <option key={opt} value={opt}>{opt}</option>
                                    ))}
                                </select>
                                <span className="ml-2">
                                    {Math.min((page - 1) * pageSize + 1, total)}ΓÇô{Math.min(page * pageSize, total)} of {total}
                                </span>
                            </div>

                            <div className="flex items-center gap-1">
                                <button
                                    onClick={() => handlePageChange(page - 1)}
                                    disabled={page === 1}
                                    className="px-3 py-1.5 text-sm rounded-md border border-gray-300 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed"
                                >
                                    ΓåÉ Prev
                                </button>

                                {getPageNumbers().map((p, idx) =>
                                    p === '...' ? (
                                        <span key={`ellipsis-${idx}`} className="px-2 py-1.5 text-sm text-slate-400">ΓÇª</span>
                                    ) : (
                                        <button
                                            key={p}
                                            onClick={() => handlePageChange(p as number)}
                                            className={`px-3 py-1.5 text-sm rounded-md border ${page === p
                                                ? 'bg-blue-600 text-white border-blue-600'
                                                : 'border-gray-300 hover:bg-gray-50'
                                                }`}
                                        >
                                            {p}
                                        </button>
                                    )
                                )}

                                <button
                                    onClick={() => handlePageChange(page + 1)}
                                    disabled={page === totalPages}
                                    className="px-3 py-1.5 text-sm rounded-md border border-gray-300 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed"
                                >
                                    Next ΓåÆ
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Import Modal */}
            {showImportModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50">
                    <div className="bg-white p-6 rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
                        <h2 className="text-xl font-bold mb-4">Bulk Import Staff</h2>
                        
                        <div className="mb-4 p-4 bg-blue-50 text-blue-800 text-sm rounded-lg border border-blue-200 relative">
                            <p className="mb-2"><strong>Instructions:</strong></p>
                            <ol className="list-decimal ml-5 space-y-1">
                                <li>Download the CSV template below.</li>
                                <li>Fill in the staff details. Do NOT delete the header row.</li>
                                <li><strong>designationId</strong>: Must be the numeric ID from the list below.</li>
                                <li><strong>Password</strong>: The default password configured in the `.env` (via SSM) will automatically be assigned. The staff member will be forced to change it on their first login.</li>
                            </ol>
                            <button onClick={handleDownloadTemplate} type="button" className="mt-3 text-white bg-blue-600 hover:bg-blue-700 font-medium rounded text-xs px-3 py-1.5 focus:outline-none">
                                Download CSV Template
                            </button>
                        </div>

                        <div className="mb-6 border border-gray-200 rounded max-h-40 overflow-y-auto w-full">
                            <table className="w-full text-sm text-left text-gray-500">
                                <thead className="text-xs text-gray-700 uppercase bg-gray-50 sticky top-0">
                                    <tr>
                                        <th className="px-4 py-2 border-b">Designation ID</th>
                                        <th className="px-4 py-2 border-b">Title</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {designations.map(d => (
                                        <tr key={d.id} className="border-b">
                                            <td className="px-4 py-2 font-mono font-bold text-gray-900">{d.id}</td>
                                            <td className="px-4 py-2">{d.title}</td>
                                        </tr>
                                    ))}
                                    {designations.length === 0 && (
                                        <tr><td colSpan={2} className="px-4 py-2 text-center">No designations found.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>

                        {importSummary ? (
                            <div className="mb-6 border border-slate-200 rounded-lg p-4 bg-slate-50">
                                <h3 className="font-bold text-lg mb-2 text-slate-800">Import Results</h3>
                                <div className="flex gap-4 mb-4">
                                    <div className="bg-green-100 border border-green-200 text-green-800 p-3 rounded-lg flex-1 text-center">
                                        <div className="text-2xl font-bold">{importSummary.successful}</div>
                                        <div className="text-xs uppercase font-medium mt-1">Successful</div>
                                    </div>
                                    <div className="bg-red-100 border border-red-200 text-red-800 p-3 rounded-lg flex-1 text-center">
                                        <div className="text-2xl font-bold">{importSummary.failed}</div>
                                        <div className="text-xs uppercase font-medium mt-1">Failed</div>
                                    </div>
                                </div>
                                {importSummary.errors.length > 0 && (
                                    <div className="bg-red-50 p-3 rounded-lg max-h-40 overflow-y-auto text-sm border border-red-200">
                                        <p className="font-bold text-red-800 mb-2 mt-1">Errors:</p>
                                        <ul className="list-disc pl-5 text-red-700 space-y-1">
                                            {importSummary.errors.map((e, idx) => <li key={idx}>{e}</li>)}
                                        </ul>
                                    </div>
                                )}
                                <div className="flex justify-end gap-2 pt-4 border-t mt-4 border-slate-200">
                                    <button type="button" onClick={() => { setShowImportModal(false); setImportSummary(null); setImportFile(null); }} className="px-5 py-2.5 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 focus:ring-4 focus:ring-blue-300">
                                        Done
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <form onSubmit={handleImportSubmit} className="space-y-4">
                                <div>
                                    <label className="block mb-2 text-sm font-medium text-gray-900">Upload CSV File <span className="text-red-500">*</span></label>
                                    <input type="file" accept=".csv" required onChange={e => setImportFile(e.target.files?.[0] || null)} className="block w-full text-sm text-gray-900 border border-gray-300 rounded-lg cursor-pointer bg-gray-50 focus:outline-none file:mr-4 file:py-2.5 file:px-4 file:rounded-l-lg file:border-0 file:text-sm file:font-semibold file:bg-slate-100 file:text-slate-700 hover:file:bg-slate-200" />
                                </div>
                                <div className="flex justify-end gap-2 pt-4 border-t border-slate-200">
                                    <button type="button" onClick={() => setShowImportModal(false)} className="px-5 py-2.5 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 focus:ring-4 focus:ring-gray-200">
                                        Cancel
                                    </button>
                                    <button type="submit" disabled={importLoading || !importFile} className="px-5 py-2.5 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 focus:ring-4 focus:ring-blue-300 disabled:opacity-50 flex items-center">
                                        {importLoading ? "Importing..." : "Start Import"}
                                    </button>
                                </div>
                            </form>
                        )}
                    </div>
                </div>
            )}
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import toast from "react-hot-toast";
import { API_BASE_URL } from "@/lib/api";
import { authFetch } from "@/lib/auth";

export default function EditStudentPage() {
    const router = useRouter();
    const params = useParams();
    const id = params?.id as string;
    const [formData, setFormData] = useState({
        firstName: "",
        lastName: "",
        email: "",
        fathersName: "",
        fatherAadhaarNumber: "",
        mothersName: "",
        motherAadhaarNumber: "",
        aadhaarNumber: "",
        mobile: "",
        alternateMobile: "",
        category: "",
        bloodGroup: "",
        religion: "",
        gender: "",
        dateOfBirth: "",
        siblingId: "",
        isActive: true,
    });
    const [availableDiscounts, setAvailableDiscounts] = useState<any[]>([]);
    const [selectedDiscounts, setSelectedDiscounts] = useState<number[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState("");

    // Sibling Modal State
    const [showSiblingModal, setShowSiblingModal] = useState(false);
    const [siblingModalError, setSiblingModalError] = useState("");
    const [siblingSearch, setSiblingSearch] = useState("");
    const [siblingSearchMode, setSiblingSearchMode] = useState<'name' | 'id'>('name');
    const [siblingResults, setSiblingResults] = useState<any[]>([]);
    const [siblingLoading, setSiblingLoading] = useState(false);
    const [selectedSiblingObj, setSelectedSiblingObj] = useState<any>(null);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [discRes] = await Promise.all([
                    authFetch(`${API_BASE_URL}/fees/discounts`)
                ]);

                if (discRes.ok) setAvailableDiscounts(await discRes.json());

                if (!id) return;
                const studRes = await authFetch(`${API_BASE_URL}/students/${id}`);
                if (!studRes.ok) throw new Error("Failed to fetch student");
                const student = await studRes.json();

                if (student) {
                    setFormData({
                        firstName: student.firstName || "",
                        lastName: student.lastName || "",
                        email: student.email || "",
                        fathersName: student.fathersName || "",
                        fatherAadhaarNumber: student.fatherAadhaarNumber || "",
                        mothersName: student.mothersName || "",
                        motherAadhaarNumber: student.motherAadhaarNumber || "",
                        aadhaarNumber: student.aadhaarNumber || "",
                        mobile: student.mobile || "",
                        alternateMobile: student.alternateMobile || "",
                        category: student.category || "",
                        bloodGroup: student.bloodGroup || "",
                        religion: student.religion || "",
                        gender: student.gender || "",
                        dateOfBirth: student.dateOfBirth ? new Date(student.dateOfBirth).toISOString().split('T')[0] : "",
                        siblingId: student.siblingId ? student.siblingId.toString() : "",
                        isActive: student.isActive,
                    });
                    if (student.studentDiscounts) {
                        const activeDiscounts = student.studentDiscounts.filter((sd: any) => sd.isActive);
                        setSelectedDiscounts(activeDiscounts.map((sd: any) => sd.discountCategory?.id || sd.discountCategoryId));
                    }
                    // If a sibling is already set, load the sibling's actual info for display
                    if (student.siblingId) {
                        try {
                            const sibRes = await authFetch(`${API_BASE_URL}/students/${student.siblingId}`);
                            if (sibRes.ok) {
                                const sibData = await sibRes.json();
                                setSelectedSiblingObj(sibData);
                            } else {
                                setSelectedSiblingObj({ id: student.siblingId, firstName: '(sibling ID:', lastName: `${student.siblingId})` });
                            }
                        } catch {
                            setSelectedSiblingObj({ id: student.siblingId, firstName: '(sibling ID:', lastName: `${student.siblingId})` });
                        }
                    }
                } else {
                    setError("Student not found");
                }
            } catch (err) {
                setError("Failed to load data");
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, [id]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const target = e.target as HTMLInputElement;
        const value = target.type === 'checkbox' ? target.checked : target.value;
        const name = target.name;
        setFormData({ ...formData, [name]: value });

        // Auto-suggest Girl discount
        if (name === 'gender' && value === 'Female') {
            const girlDiscount = availableDiscounts.find(d => d.applicationType === 'AUTO' && d.logicReference === 'GIRL');
            if (girlDiscount && !selectedDiscounts.includes(girlDiscount.id)) {
                setSelectedDiscounts(prev => [...prev, girlDiscount.id]);
                toast.success(`Auto-applied: ${girlDiscount.name}`);
            }
        }
    };

    const openSiblingModal = () => {
        if (!formData.fathersName.trim() || !formData.mothersName.trim()) {
            setSiblingModalError("Please fill in Father's Name and Mother's Name before searching for a sibling.");
            return;
        }
        setSiblingModalError("");
        setSiblingSearch("");
        setSiblingResults([]);
        setSiblingSearchMode('name');
        setShowSiblingModal(true);
    };

    const handleSearchSibling = async () => {
        if (!siblingSearch.trim()) return;
        setSiblingLoading(true);
        try {
            let url: string;
            if (siblingSearchMode === 'id') {
                const numericId = parseInt(siblingSearch.trim());
                if (isNaN(numericId)) {
                    setSiblingResults([]);
                    setSiblingLoading(false);
                    return;
                }
                url = `${API_BASE_URL}/students?id=${numericId}`;
            } else {
                url = `${API_BASE_URL}/students?search=${encodeURIComponent(siblingSearch.trim())}`;
            }
            const res = await authFetch(url);
            if (res.ok) {
                const data = await res.json();
                // Exclude the student being edited from results
                setSiblingResults(data.filter((s: any) => s.id.toString() !== id));
            }
        } catch (err) {
            console.error("Failed to fetch sibling", err);
        } finally {
            setSiblingLoading(false);
        }
    };

    const isSiblingMatch = (sibling: any) => {
        const sibFather = (sibling.fathersName || "").trim().toLowerCase();
        const sibMother = (sibling.mothersName || "").trim().toLowerCase();
        const myFather = formData.fathersName.trim().toLowerCase();
        const myMother = formData.mothersName.trim().toLowerCase();
        return sibFather === myFather && sibMother === myMother;
    };

    const selectSibling = (sibling: any) => {
        setSelectedSiblingObj(sibling);
        setFormData({
            ...formData,
            siblingId: sibling.id.toString(),
            fathersName: sibling.fathersName || formData.fathersName,
            mothersName: sibling.mothersName || formData.mothersName
        });
        setShowSiblingModal(false);
        setSiblingSearch("");
        setSiblingResults([]);

        // Auto-suggest Sibling discount
        const siblingDiscount = availableDiscounts.find(d => d.applicationType === 'AUTO' && d.logicReference === 'SIBLING');
        if (siblingDiscount && !selectedDiscounts.includes(siblingDiscount.id)) {
            setSelectedDiscounts(prev => [...prev, siblingDiscount.id]);
            toast.success(`Auto-applied: ${siblingDiscount.name}`);
        }
    };

    const clearSibling = () => {
        setSelectedSiblingObj(null);
        // Only clear the sibling link ΓÇö keep parent names intact
        setFormData({ ...formData, siblingId: "" });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setError("");

        try {
            const payload = {
                ...formData,
                siblingId: formData.siblingId ? parseInt(formData.siblingId) : null,
                discountIds: selectedDiscounts
            };

            // Remove optional empty string fields to prevent validation errors
            const optionalFields = ['email', 'aadhaarNumber', 'mobile', 'alternateMobile', 'category', 'bloodGroup', 'religion', 'dateOfBirth'];
            optionalFields.forEach(field => {
                const key = field as keyof typeof payload;
                if (!(payload as any)[key]) {
                    delete (payload as any)[key];
                }
            });

            const res = await authFetch(`${API_BASE_URL}/students/${id}`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify(payload),
            });

            if (!res.ok) {
                const errData = await res.json();
                throw new Error(errData.message || "Failed to update student");
            }

            router.push("/dashboard/students");
            router.refresh();
        } catch (err: any) {
            console.error(err);
            setError(err.message || "Failed to update student. Please try again.");
        } finally {
            setSaving(false);
        }
    };

    if (loading) return <div className="p-4">Loading...</div>;
    if (error && !formData.firstName) return <div className="p-4 text-red-600">{error}</div>;

    return (
        <main className="p-4 bg-slate-50 min-h-screen">
            <div className="max-w-4xl mx-auto bg-white p-8 rounded-lg shadow-sm border border-slate-200 relative">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-slate-800">Edit Student</h2>
                    <Link href="/dashboard/students" className="text-blue-600 hover:underline">
                        &larr; Back to Students
                    </Link>
                </div>

                {error && (
                    <div className="p-4 mb-4 text-sm text-red-800 rounded-lg bg-red-50" role="alert">
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-8">
                    {/* TODO: For future, we'll make fields compulsory. For now only first name, last name, gender, father's name, mother's name make compulsory. All other are optional. */}
                    {/* Basic Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Basic Information</h3>
                        <div className="grid gap-6 md:grid-cols-3">
                            <div>
                                <label htmlFor="firstName" className="block mb-2 text-sm font-medium text-gray-900">First name <span className="text-red-500">*</span></label>
                                <input type="text" id="firstName" name="firstName" value={formData.firstName} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required />
                            </div>
                            <div>
                                <label htmlFor="lastName" className="block mb-2 text-sm font-medium text-gray-900">Last name <span className="text-red-500">*</span></label>
                                <input type="text" id="lastName" name="lastName" value={formData.lastName} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required />
                            </div>
                            <div>
                                <label htmlFor="gender" className="block mb-2 text-sm font-medium text-gray-900">Gender <span className="text-red-500">*</span></label>
                                <select id="gender" name="gender" value={formData.gender} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required>
                                    <option value="">Select Gender</option>
                                    <option value="Male">Male</option>
                                    <option value="Female">Female</option>
                                    <option value="Others">Others</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="dateOfBirth" className="block mb-2 text-sm font-medium text-gray-900">Date of Birth</label>
                                <input type="date" id="dateOfBirth" name="dateOfBirth" value={formData.dateOfBirth} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div>
                                <label htmlFor="bloodGroup" className="block mb-2 text-sm font-medium text-gray-900">Blood Group</label>
                                <select id="bloodGroup" name="bloodGroup" value={formData.bloodGroup} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                    <option value="">Select Group</option>
                                    <option value="A+">A+</option><option value="A-">A-</option>
                                    <option value="B+">B+</option><option value="B-">B-</option>
                                    <option value="O+">O+</option><option value="O-">O-</option>
                                    <option value="AB+">AB+</option><option value="AB-">AB-</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="aadhaarNumber" className="block mb-2 text-sm font-medium text-gray-900">Aadhaar Number <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" id="aadhaarNumber" name="aadhaarNumber" value={formData.aadhaarNumber} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* Contact Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Contact Information</h3>
                        <div className="grid gap-6 md:grid-cols-3">
                            <div>
                                <label htmlFor="email" className="block mb-2 text-sm font-medium text-gray-900">Email address <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="email" id="email" name="email" value={formData.email} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div>
                                <label htmlFor="mobile" className="block mb-2 text-sm font-medium text-gray-900">Mobile Number</label>
                                <input type="tel" id="mobile" name="mobile" value={formData.mobile} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div>
                                <label htmlFor="alternateMobile" className="block mb-2 text-sm font-medium text-gray-900">Alternate Mobile</label>
                                <input type="tel" id="alternateMobile" name="alternateMobile" value={formData.alternateMobile} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* Parent & Family Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Parent &amp; Family Details</h3>

                        {/* Linked sibling badge */}
                        {selectedSiblingObj && (
                            <div className="flex items-center space-x-2 mb-4">
                                <span className="text-xs font-semibold bg-green-100 text-green-800 px-2 py-1 rounded border border-green-200">
                                    Linked Sibling: {selectedSiblingObj.firstName} {selectedSiblingObj.lastName} (ID: {selectedSiblingObj.id})
                                </span>
                                <button type="button" onClick={clearSibling} className="text-red-600 hover:text-red-800 text-xs font-medium underline">Remove Link</button>
                            </div>
                        )}

                        <div className="grid gap-6 md:grid-cols-2">
                            <div>
                                <label htmlFor="fathersName" className="block mb-2 text-sm font-medium text-gray-900">Father's Name <span className="text-red-500">*</span></label>
                                <input type="text" id="fathersName" name="fathersName" value={formData.fathersName} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" required />
                            </div>
                            <div>
                                <label htmlFor="fatherAadhaarNumber" className="block mb-2 text-sm font-medium text-gray-900">Father's UUID (Aadhaar Number) <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" id="fatherAadhaarNumber" name="fatherAadhaarNumber" value={formData.fatherAadhaarNumber} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" />
                            </div>
                            <div>
                                <label htmlFor="mothersName" className="block mb-2 text-sm font-medium text-gray-900">Mother's Name <span className="text-red-500">*</span></label>
                                <input type="text" id="mothersName" name="mothersName" value={formData.mothersName} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" required />
                            </div>
                            <div>
                                <label htmlFor="motherAadhaarNumber" className="block mb-2 text-sm font-medium text-gray-900">Mother's UUID (Aadhaar Number) <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" id="motherAadhaarNumber" name="motherAadhaarNumber" value={formData.motherAadhaarNumber} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" />
                            </div>
                        </div>

                        {selectedSiblingObj && (
                            <p className="mt-2 text-xs text-blue-600 italic">Parent names are locked and synced with the linked sibling.</p>
                        )}

                        {/* Add Sibling button ΓÇö placed AFTER parent name fields */}
                        {!selectedSiblingObj && (
                            <div className="mt-4">
                                {siblingModalError && (
                                    <p className="text-xs text-red-600 mb-2">{siblingModalError}</p>
                                )}
                                <button
                                    type="button"
                                    onClick={openSiblingModal}
                                    className="text-white bg-green-600 hover:bg-green-700 focus:ring-4 focus:ring-green-300 font-medium rounded-lg text-xs px-3 py-1.5 focus:outline-none"
                                >
                                    + Add Sibling
                                </button>
                                <p className="text-xs text-gray-400 mt-1">Fill in Father&apos;s and Mother&apos;s Name first, then search for a sibling with matching parents.</p>
                            </div>
                        )}
                    </div>

                    {/* Additional Demographics */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Demographics</h3>
                        <div className="grid gap-6 md:grid-cols-2">
                            <div>
                                <label htmlFor="category" className="block mb-2 text-sm font-medium text-gray-900">Category</label>
                                <select id="category" name="category" value={formData.category} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                    <option value="">Select Category</option>
                                    <option value="General">General</option>
                                    <option value="SC">SC</option>
                                    <option value="ST">ST</option>
                                    <option value="OBC">OBC</option>
                                    <option value="EWS">EWS</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="religion" className="block mb-2 text-sm font-medium text-gray-900">Religion</label>
                                <select id="religion" name="religion" value={formData.religion} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                    <option value="">Select Religion</option>
                                    <option value="HINDU">HINDU</option>
                                    <option value="MUSLIM">MUSLIM</option>
                                    <option value="SIKH">SIKH</option>
                                    <option value="CHRISTIAN">CHRISTIAN</option>
                                    <option value="PARSI">PARSI</option>
                                    <option value="OTHERS">OTHERS</option>
                                </select>
                            </div>
                        </div>
                    </div>

                    {/* Administrative Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Administrative Info</h3>
                        <div className="flex items-center mb-6">
                            <input
                                id="isActive"
                                name="isActive"
                                type="checkbox"
                                checked={formData.isActive}
                                onChange={handleChange}
                                className="w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
                            />
                            <label htmlFor="isActive" className="ml-2 text-sm font-medium text-gray-900">Account Active</label>
                        </div>

                        {availableDiscounts.length > 0 && (
                            <div className="mb-6">
                                <label className="block mb-3 text-sm font-medium text-gray-900">Fee Discounts applied to this student</label>
                                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                    {availableDiscounts.map(d => (
                                        <label key={d.id} className="flex flex-col p-3 border border-gray-200 bg-white rounded-lg cursor-pointer hover:bg-gray-50 transition-colors">
                                            <div className="flex items-center">
                                                <input
                                                    type="checkbox"
                                                    checked={selectedDiscounts.includes(d.id)}
                                                    onChange={(e) => {
                                                        if (e.target.checked) setSelectedDiscounts([...selectedDiscounts, d.id]);
                                                        else setSelectedDiscounts(selectedDiscounts.filter(did => did !== d.id));
                                                    }}
                                                    className="w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
                                                />
                                                <span className="ml-2 text-sm font-medium text-gray-900">{d.name}</span>
                                            </div>
                                            <span className="mt-1 ml-6 text-xs text-gray-500">
                                                {d.type === 'PERCENTAGE' ? `${d.value}%` : `$${d.value}`}
                                                {d.applicationType === 'AUTO' && <span className="ml-1 text-[10px] bg-blue-100 text-blue-800 px-1 rounded font-bold">{d.logicReference}</span>}
                                            </span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="flex items-center space-x-4 pt-4 border-t">
                        <button
                            type="submit"
                            disabled={saving}
                            className="text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:outline-none focus:ring-blue-300 font-bold rounded-lg text-lg w-full sm:w-auto px-8 py-3 text-center disabled:opacity-50"
                        >
                            {saving ? 'Saving...' : 'Save Changes'}
                        </button>
                        <Link href="/dashboard/students" className="text-gray-900 bg-white border border-gray-300 focus:outline-none hover:bg-gray-100 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-3">
                            Cancel
                        </Link>
                    </div>
                </form>

                {/* Sibling Search Modal */}
                {showSiblingModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-50">
                        <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] flex flex-col">
                            <div className="flex items-center justify-between p-4 border-b">
                                <div>
                                    <h3 className="text-xl font-semibold text-gray-900">Search Existing Sibling</h3>
                                    <p className="text-xs text-gray-500 mt-0.5">
                                        Searching for siblings of: <span className="font-medium text-gray-700">{formData.fathersName}</span> &amp; <span className="font-medium text-gray-700">{formData.mothersName}</span>
                                    </p>
                                </div>
                                <button type="button" onClick={() => setShowSiblingModal(false)} className="text-gray-400 bg-transparent hover:bg-gray-200 hover:text-gray-900 rounded-lg text-sm w-8 h-8 ml-auto inline-flex justify-center items-center">
                                    <svg className="w-3 h-3" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 14 14"><path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="m1 1 6 6m0 0 6 6M7 7l6-6M7 7l-6 6" /></svg>
                                    <span className="sr-only">Close modal</span>
                                </button>
                            </div>
                            <div className="p-6 flex-1 overflow-y-auto">
                                {/* Search mode toggle */}
                                <div className="flex mb-3 rounded-lg overflow-hidden border border-gray-300 w-fit">
                                    <button
                                        type="button"
                                        onClick={() => { setSiblingSearchMode('name'); setSiblingSearch(''); setSiblingResults([]); }}
                                        className={`px-4 py-1.5 text-sm font-medium transition-colors ${siblingSearchMode === 'name'
                                            ? 'bg-blue-700 text-white'
                                            : 'bg-white text-gray-600 hover:bg-gray-100'
                                            }`}
                                    >
                                        Search by Name
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => { setSiblingSearchMode('id'); setSiblingSearch(''); setSiblingResults([]); }}
                                        className={`px-4 py-1.5 text-sm font-medium transition-colors ${siblingSearchMode === 'id'
                                            ? 'bg-blue-700 text-white'
                                            : 'bg-white text-gray-600 hover:bg-gray-100'
                                            }`}
                                    >
                                        Search by ID
                                    </button>
                                </div>
                                <form className="flex items-center space-x-2 mb-4" onSubmit={(e) => { e.preventDefault(); handleSearchSibling(); }}>
                                    <input
                                        type={siblingSearchMode === 'id' ? 'number' : 'text'}
                                        value={siblingSearch}
                                        onChange={e => setSiblingSearch(e.target.value)}
                                        placeholder={siblingSearchMode === 'id' ? 'Enter student ID (e.g. 42)' : 'Search by first or last name (e.g. Raj)'}
                                        className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                                    />
                                    <button type="submit" className="text-white bg-blue-700 hover:bg-blue-800 font-medium rounded-lg text-sm px-5 py-2.5" disabled={siblingLoading}>{siblingLoading ? '...' : 'Search'}</button>
                                </form>

                                <div className="mt-4">
                                    {siblingResults.length > 0 ? (
                                        <>
                                            <p className="text-xs text-gray-500 mb-2">
                                                <span className="inline-flex items-center mr-3"><span className="w-2 h-2 rounded-full bg-green-500 inline-block mr-1"></span>Names match ΓÇö can be linked</span>
                                                <span className="inline-flex items-center"><span className="w-2 h-2 rounded-full bg-red-400 inline-block mr-1"></span>Names don&apos;t match ΓÇö cannot link</span>
                                            </p>
                                            <ul className="divide-y divide-gray-200 border rounded-lg max-h-64 overflow-y-auto">
                                                {siblingResults.map(s => {
                                                    const match = isSiblingMatch(s);
                                                    return (
                                                        <li key={s.id} className={`p-3 flex justify-between items-center transition-colors ${match ? 'hover:bg-green-50' : 'bg-red-50 opacity-70'}`}>
                                                            <div>
                                                                <div className="flex items-center gap-2">
                                                                    <span className={`w-2 h-2 rounded-full shrink-0 ${match ? 'bg-green-500' : 'bg-red-400'}`}></span>
                                                                    <p className="text-sm font-medium text-gray-900">{s.firstName} {s.lastName}</p>
                                                                </div>
                                                                <p className="text-xs text-gray-500 ml-4">ID: {s.id} | Father: {s.fathersName || 'N/A'} | Mother: {s.mothersName || 'N/A'}</p>
                                                                {!match && (
                                                                    <p className="text-xs text-red-600 ml-4 mt-0.5">ΓÜá Parent names do not match ΓÇö cannot select as sibling</p>
                                                                )}
                                                            </div>
                                                            <button
                                                                type="button"
                                                                onClick={() => match && selectSibling(s)}
                                                                disabled={!match}
                                                                className={`font-medium rounded-lg text-xs px-3 py-1.5 focus:outline-none shrink-0 ml-2 ${match ? 'text-white bg-green-600 hover:bg-green-700' : 'text-gray-400 bg-gray-200 cursor-not-allowed'}`}
                                                            >
                                                                Select
                                                            </button>
                                                        </li>
                                                    );
                                                })}
                                            </ul>
                                        </>
                                    ) : (
                                        <p className="text-sm text-gray-500 italic text-center py-4">Search to find siblings.</p>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { API_BASE_URL } from "@/lib/api";
import { authFetch } from "@/lib/auth";

export default function PromoteStudentPage() {
    const router = useRouter();
    const params = useParams();
    const id = params?.id as string;
    const [student, setStudent] = useState<any>(null);
    const [classes, setClasses] = useState<any[]>([]);
    const [selectedClassId, setSelectedClassId] = useState<number | null>(null);
    const [selectedSectionId, setSelectedSectionId] = useState<number | null>(null);

    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState("");

    useEffect(() => {
        if (!id) return;
        const fetchData = async () => {
            try {
                // Fetch Student
                const resStudent = await authFetch(`${API_BASE_URL}/students/${id}`);

                if (!resStudent.ok) throw new Error("Failed to fetch student");

                const foundStudent = await resStudent.json();

                // Fetch Classes (which should include sections)
                const resClasses = await authFetch(`${API_BASE_URL}/classes`);
                const classesData = await resClasses.json();

                if (foundStudent) {
                    setStudent(foundStudent);
                    // Pre-select current values if needed, or leave blank to force choice
                } else {
                    setError("Student not found");
                }
                setClasses(classesData);
            } catch (err) {
                setError("Failed to load data");
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, [id]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!selectedClassId || !selectedSectionId) {
            setError("Please select both a class and a section.");
            return;
        }

        if (student && student.class?.id === selectedClassId && student.section?.id === selectedSectionId) {
            setError("Student is already in this class and section. Please select a different one to promote/move.");
            return;
        }

        setSaving(true);
        setError("");

        try {
            const res = await authFetch(`${API_BASE_URL}/students/${id}/promote`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({
                    classId: selectedClassId,
                    sectionId: selectedSectionId
                }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.message || "Failed to promote student");
            }

            router.push("/dashboard/students");
            router.refresh();
        } catch (err: any) {
            console.error(err);
            setError(err.message || "Failed to promote student. Please try again.");
        } finally {
            setSaving(false);
        }
    };

    if (loading) return <div className="p-4">Loading...</div>;
    if (error && !student) return <div className="p-4 text-red-600">{error}</div>; // Show error if load failed
    if (!student) return <div className="p-4">Student not found</div>;

    const sections = classes.find(c => c.id === selectedClassId)?.sections || [];

    return (
        <main className="p-4">
            <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-sm border border-slate-200">
                <h2 className="text-2xl font-bold mb-6 text-slate-800">Promote Student</h2>

                {error && student && (
                    <div className="p-4 mb-4 text-sm text-red-800 rounded-lg bg-red-50" role="alert">
                        {error}
                    </div>
                )}

                <div className="mb-6 bg-slate-50 p-4 rounded text-sm text-slate-700 space-y-2">
                    <p><strong>Name:</strong> {student.firstName} {student.lastName}</p>
                    <p><strong>Email:</strong> {student.email}</p>
                    <p><strong>Current Class:</strong> {student.class ? student.class.name : 'N/A'}</p>
                    <p><strong>Current Section:</strong> {student.section ? student.section.name : 'N/A'}</p>
                    <p><strong>Status:</strong> {student.isActive ? 'Active' : 'Inactive'}</p>
                </div>

                <form onSubmit={handleSubmit}>
                    <div className="mb-6">
                        <label htmlFor="class" className="block mb-2 text-sm font-medium text-gray-900">New Class</label>
                        <select
                            id="class"
                            className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            value={selectedClassId || ""}
                            onChange={(e) => {
                                setSelectedClassId(parseInt(e.target.value));
                                setSelectedSectionId(null); // Reset section when class changes
                            }}
                            required
                        >
                            <option value="">Select Class</option>
                            {classes.map((cls) => (
                                <option key={cls.id} value={cls.id}>{cls.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="mb-6">
                        <label htmlFor="section" className="block mb-2 text-sm font-medium text-gray-900">New Section</label>
                        <select
                            id="section"
                            className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            value={selectedSectionId || ""}
                            onChange={(e) => setSelectedSectionId(parseInt(e.target.value))}
                            required
                            disabled={!selectedClassId}
                        >
                            <option value="">Select Section</option>
                            {sections.map((sec: any) => (
                                <option key={sec.id} value={sec.id}>{sec.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="flex items-center space-x-4">
                        <button
                            type="submit"
                            disabled={saving}
                            className="text-white bg-amber-600 hover:bg-amber-700 focus:ring-4 focus:outline-none focus:ring-amber-300 font-medium rounded-lg text-sm w-full sm:w-auto px-5 py-2.5 text-center disabled:opacity-50"
                        >
                            {saving ? 'Promoting...' : 'Promote Student'}
                        </button>
                        <Link href="/dashboard/students" className="text-gray-900 bg-white border border-gray-300 focus:outline-none hover:bg-gray-100 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-2.5">
                            Cancel
                        </Link>
                    </div>
                </form>
            </div>
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import toast from "react-hot-toast";
import { API_BASE_URL } from "@/lib/api";
import { Country, State, City } from "country-state-city";
import { useRbac } from "@/lib/rbac";
import { authFetch } from "@/lib/auth";

export default function AddStudentPage() {
    const router = useRouter();
    const rbac = useRbac();

    // Route guard ΓÇö only SUB_ADMIN and above can add students
    useEffect(() => {
        if (!rbac.canManageStudents) {
            toast.error("You don't have permission to add students.");
            router.replace('/dashboard/students');
        }
    }, [rbac.canManageStudents, router]);

    const [formData, setFormData] = useState({
        firstName: "",
        lastName: "",
        email: "",
        fathersName: "",
        fatherAadhaarNumber: "",
        mothersName: "",
        motherAadhaarNumber: "",
        aadhaarNumber: "",
        mobile: "",
        alternateMobile: "",
        category: "",
        bloodGroup: "",
        religion: "",
        gender: "",
        dateOfBirth: "",
        siblingId: "",
        address: { addressLine1: "", addressLine2: "", landmark: "", city: "", state: "", postalCode: "", country: "IN" }
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [availableDiscounts, setAvailableDiscounts] = useState<any[]>([]);
    const [selectedDiscounts, setSelectedDiscounts] = useState<number[]>([]);

    // Enrollment State
    const [enrollStudent, setEnrollStudent] = useState(false);
    const [classes, setClasses] = useState<any[]>([]);
    const [academicSessions, setAcademicSessions] = useState<any[]>([]);
    const [subjects, setSubjects] = useState<any[]>([]);
    const [sections, setSections] = useState<any[]>([]);
    
    const [selectedClass, setSelectedClass] = useState("");
    const [selectedSection, setSelectedSection] = useState("");
    const [selectedSessionId, setSelectedSessionId] = useState<number | "">("");
    const [selectedSubjects, setSelectedSubjects] = useState<string[]>([]);

    useEffect(() => {
        const fetchInitialData = async () => {
            try {
                const [discountsRes, classesRes, sessionsRes, subjectsRes] = await Promise.all([
                    authFetch(`${API_BASE_URL}/fees/discounts`),
                    authFetch(`${API_BASE_URL}/classes`),
                    authFetch(`${API_BASE_URL}/academic-sessions`),
                    authFetch(`${API_BASE_URL}/subjects`)
                ]);
                
                if (discountsRes.ok) setAvailableDiscounts(await discountsRes.json());
                if (classesRes.ok) setClasses(await classesRes.json());
                if (subjectsRes.ok) setSubjects(await subjectsRes.json());
                if (sessionsRes.ok) {
                    const data = await sessionsRes.json();
                    setAcademicSessions(data);
                    const active = data.find((s: any) => s.isActive);
                    if (active) setSelectedSessionId(active.id);
                }
            } catch (err) {
                console.error("Failed to fetch initial data", err);
            }
        };
        fetchInitialData();
    }, []);

    // Filter sections when class changes (for the Enrollment Form)
    useEffect(() => {
        if (selectedClass) {
            const cls = classes.find((c: any) => c.id === parseInt(selectedClass));
            if (cls) {
                setSections(cls.sections || []);
            } else {
                setSections([]);
            }
        } else {
            setSections([]);
        }
    }, [selectedClass, classes]);

    const handleSubjectToggle = (subjectId: string) => {
        setSelectedSubjects(prev =>
            prev.includes(subjectId)
                ? prev.filter(id => id !== subjectId)
                : [...prev, subjectId]
        );
    };

    const renderSubjectComponents = (subject: any) => (
        <div className="flex gap-1">
            {subject.hasTheory && <span className="bg-blue-100 text-blue-800 text-[10px] font-bold px-1.5 py-0.5 rounded">Th</span>}
            {subject.hasPractical && <span className="bg-purple-100 text-purple-800 text-[10px] font-bold px-1.5 py-0.5 rounded">Pr</span>}
            {!subject.hasTheory && !subject.hasPractical && <span className="text-gray-400 text-[10px]">-</span>}
        </div>
    );

    // Sibling Modal State
    const [showSiblingModal, setShowSiblingModal] = useState(false);
    const [siblingModalError, setSiblingModalError] = useState("");
    const [siblingSearch, setSiblingSearch] = useState("");
    const [siblingSearchMode, setSiblingSearchMode] = useState<'name' | 'id'>('name');
    const [siblingResults, setSiblingResults] = useState<any[]>([]);
    const [siblingLoading, setSiblingLoading] = useState(false);
    const [selectedSiblingObj, setSelectedSiblingObj] = useState<any>(null);



    const countries = Country.getAllCountries();
    const [states, setStates] = useState<any[]>(State.getStatesOfCountry("IN"));
    const [cities, setCities] = useState<any[]>([]);

    useEffect(() => {
        if (formData.address?.country) {
            setStates(State.getStatesOfCountry(formData.address.country));
        }
    }, [formData.address?.country]);

    useEffect(() => {
        if (formData.address?.country && formData.address?.state) {
            setCities(City.getCitiesOfState(formData.address.country, formData.address.state));
        }
    }, [formData.address?.country, formData.address?.state]);

    const handleAddressChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        if (name === "country") {
            setFormData(prev => ({ ...prev, address: { ...prev.address, country: value, state: "", city: "" } }));
        } else if (name === "state") {
            setFormData(prev => ({ ...prev, address: { ...prev.address, state: value, city: "" } }));
        } else {
            setFormData(prev => ({ ...prev, address: { ...prev.address, [name]: value } }));
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });

        // Auto-apply Girl discount
        if (name === 'gender' && value === 'Female') {
            const girlDiscount = availableDiscounts.find(d => d.applicationType === 'AUTO' && d.logicReference === 'GIRL');
            if (girlDiscount && !selectedDiscounts.includes(girlDiscount.id)) {
                setSelectedDiscounts(prev => [...prev, girlDiscount.id]);
                toast.success(`Auto-applied: ${girlDiscount.name}`);
            }
        }
    };

    const openSiblingModal = () => {
        if (!formData.fathersName.trim() || !formData.mothersName.trim()) {
            setSiblingModalError("Please fill in Father's Name and Mother's Name before searching for a sibling.");
            return;
        }
        setSiblingModalError("");
        setSiblingSearch("");
        setSiblingResults([]);
        setSiblingSearchMode('name');
        setShowSiblingModal(true);
    };

    const handleSearchSibling = async () => {
        if (!siblingSearch.trim()) return;
        setSiblingLoading(true);
        try {
            let url: string;
            if (siblingSearchMode === 'id') {
                const numericId = parseInt(siblingSearch.trim());
                if (isNaN(numericId)) {
                    setSiblingResults([]);
                    setSiblingLoading(false);
                    return;
                }
                url = `${API_BASE_URL}/students?id=${numericId}`;
            } else {
                url = `${API_BASE_URL}/students?search=${encodeURIComponent(siblingSearch.trim())}`;
            }
            const res = await authFetch(url);
            if (res.ok) {
                const data = await res.json();
                setSiblingResults(data);
            }
        } catch (err) {
            console.error("Failed to fetch sibling", err);
        } finally {
            setSiblingLoading(false);
        }
    };

    const isSiblingMatch = (sibling: any) => {
        const sibFather = (sibling.fathersName || "").trim().toLowerCase();
        const sibMother = (sibling.mothersName || "").trim().toLowerCase();
        const myFather = formData.fathersName.trim().toLowerCase();
        const myMother = formData.mothersName.trim().toLowerCase();
        return sibFather === myFather && sibMother === myMother;
    };

    const selectSibling = (sibling: any) => {
        setSelectedSiblingObj(sibling);
        setFormData({
            ...formData,
            siblingId: sibling.id.toString(),
            fathersName: sibling.fathersName || "",
            mothersName: sibling.mothersName || ""
        });
        setShowSiblingModal(false);
        setSiblingSearch("");
        setSiblingResults([]);

        // Auto-apply Sibling discount
        const siblingDiscount = availableDiscounts.find(d => d.applicationType === 'AUTO' && d.logicReference === 'SIBLING');
        if (siblingDiscount && !selectedDiscounts.includes(siblingDiscount.id)) {
            setSelectedDiscounts(prev => [...prev, siblingDiscount.id]);
            toast.success(`Auto-applied: ${siblingDiscount.name}`);
        }
    };

    const clearSibling = () => {
        setSelectedSiblingObj(null);
        // Only clear the sibling link ΓÇö keep parent names intact
        setFormData({ ...formData, siblingId: "" });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            const payload = {
                ...formData,
                siblingId: formData.siblingId ? parseInt(formData.siblingId) : undefined,
                discountIds: selectedDiscounts,
            };

            if (!payload.address || !payload.address.addressLine1 || !payload.address.country) {
                delete (payload as any).address;
            } else {
                const countryObj = Country.getCountryByCode(payload.address.country);
                const stateObj = State.getStateByCodeAndCountry(payload.address.state, payload.address.country);
                payload.address.country = countryObj ? countryObj.name : payload.address.country;
                payload.address.state = stateObj ? stateObj.name : payload.address.state;
            }

            // Remove optional empty string fields to prevent validation errors
            const optionalFields = ['email', 'aadhaarNumber', 'alternateMobile', 'bloodGroup'];
            optionalFields.forEach(field => {
                const key = field as keyof typeof payload;
                if (!payload[key]) {
                    delete payload[key];
                }
            });

            if (enrollStudent && (!selectedClass || !selectedSection)) {
                throw new Error("Please select Class and Section to enroll the student.");
            }

            const res = await authFetch(`${API_BASE_URL}/students`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify(payload),
            });

            if (!res.ok) {
                const errData = await res.json();
                throw new Error(errData.message || "Failed to create student");
            }
            
            const newStudent = await res.json();

            // Handle Enrollment if requested
            if (enrollStudent) {
                try {
                    const enrollRes = await authFetch(`${API_BASE_URL}/students/${newStudent.id}/enroll`, {
                        method: "POST",
                        headers: {
                            "Content-Type": "application/json",
                        },
                        body: JSON.stringify({
                            classId: parseInt(selectedClass),
                            sectionId: parseInt(selectedSection),
                            subjectIds: selectedSubjects.map(id => parseInt(id)),
                            academicSessionId: selectedSessionId !== "" ? selectedSessionId : undefined
                        }),
                    });

                    if (!enrollRes.ok) {
                        toast.error("Student created successfully, but enrollment failed.");
                    } else {
                        toast.success("Student created and enrolled successfully!");
                    }
                } catch (enrollErr) {
                    toast.error("Student created successfully, but enrollment failed.");
                }
            } else {
                toast.success("Student created successfully!");
            }

            router.push("/dashboard/students");
            router.refresh();
        } catch (err: any) {
            setError(err.message || "Failed to create student.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <main className="p-4 bg-slate-50 min-h-screen">
            <div className="max-w-4xl mx-auto bg-white p-8 rounded-lg shadow-sm border border-slate-200 relative">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-slate-800">Add New Student</h2>
                    <Link href="/dashboard/students" className="text-blue-600 hover:underline">
                        &larr; Back to Students
                    </Link>
                </div>

                {error && (
                    <div className="p-4 mb-4 text-sm text-red-800 rounded-lg bg-red-50" role="alert">
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-8">
                    {/* TODO: For future, we'll make fields compulsory. For now only first name, last name, gender, father's name, mother's name make compulsory. All other are optional. */}
                    {/* Basic Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Basic Information</h3>
                        <div className="grid gap-6 md:grid-cols-3">
                            <div>
                                <label htmlFor="firstName" className="block mb-2 text-sm font-medium text-gray-900">First name <span className="text-red-500">*</span></label>
                                <input type="text" id="firstName" name="firstName" value={formData.firstName} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required />
                            </div>
                            <div>
                                <label htmlFor="lastName" className="block mb-2 text-sm font-medium text-gray-900">Last name <span className="text-red-500">*</span></label>
                                <input type="text" id="lastName" name="lastName" value={formData.lastName} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required />
                            </div>
                            <div>
                                <label htmlFor="gender" className="block mb-2 text-sm font-medium text-gray-900">Gender <span className="text-red-500">*</span></label>
                                <select id="gender" name="gender" value={formData.gender} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required>
                                    <option value="">Select Gender</option>
                                    <option value="Male">Male</option>
                                    <option value="Female">Female</option>
                                    <option value="Others">Others</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="dateOfBirth" className="block mb-2 text-sm font-medium text-gray-900">Date of Birth <span className="text-red-500">*</span></label>
                                <input type="date" id="dateOfBirth" name="dateOfBirth" value={formData.dateOfBirth} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required />
                            </div>
                            <div>
                                <label htmlFor="bloodGroup" className="block mb-2 text-sm font-medium text-gray-900">Blood Group</label>
                                <select id="bloodGroup" name="bloodGroup" value={formData.bloodGroup} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                    <option value="">Select Group</option>
                                    <option value="A+">A+</option><option value="A-">A-</option>
                                    <option value="B+">B+</option><option value="B-">B-</option>
                                    <option value="O+">O+</option><option value="O-">O-</option>
                                    <option value="AB+">AB+</option><option value="AB-">AB-</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="aadhaarNumber" className="block mb-2 text-sm font-medium text-gray-900">Aadhaar Number <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" id="aadhaarNumber" name="aadhaarNumber" value={formData.aadhaarNumber} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* Contact Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Contact Information</h3>
                        <div className="grid gap-6 md:grid-cols-3">
                            <div>
                                <label htmlFor="email" className="block mb-2 text-sm font-medium text-gray-900">Email address <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="email" id="email" name="email" value={formData.email} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div>
                                <label htmlFor="mobile" className="block mb-2 text-sm font-medium text-gray-900">Mobile Number <span className="text-red-500">*</span></label>
                                <input type="tel" id="mobile" name="mobile" value={formData.mobile} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required />
                            </div>
                            <div>
                                <label htmlFor="alternateMobile" className="block mb-2 text-sm font-medium text-gray-900">Alternate Mobile</label>
                                <input type="tel" id="alternateMobile" name="alternateMobile" value={formData.alternateMobile} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* Address Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Address Information</h3>
                        <div className="grid gap-6 md:grid-cols-2">
                            <div>
                                <label htmlFor="country" className="block mb-2 text-sm font-medium text-gray-900">Country <span className="text-red-500">*</span></label>
                                <select id="country" name="country" value={formData.address?.country} onChange={handleAddressChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                    <option value="">Select Country</option>
                                    {countries.map(c => (
                                        <option key={c.isoCode} value={c.isoCode}>{c.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label htmlFor="state" className="block mb-2 text-sm font-medium text-gray-900">State <span className="text-red-500">*</span></label>
                                <select id="state" name="state" value={formData.address?.state} onChange={handleAddressChange} disabled={!states.length} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:opacity-50">
                                    <option value="">Select State</option>
                                    {states.map(s => (
                                        <option key={s.isoCode} value={s.isoCode}>{s.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label htmlFor="city" className="block mb-2 text-sm font-medium text-gray-900">City <span className="text-red-500">*</span></label>
                                {cities.length > 0 ? (
                                    <select id="city" name="city" value={formData.address?.city} onChange={handleAddressChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5">
                                        <option value="">Select City</option>
                                        {cities.map(c => (
                                            <option key={c.name} value={c.name}>{c.name}</option>
                                        ))}
                                    </select>
                                ) : (
                                    <input type="text" id="city" name="city" value={formData.address?.city} onChange={handleAddressChange} placeholder="City name" disabled={!formData.address?.state} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:opacity-50" />
                                )}
                            </div>
                            <div>
                                <label htmlFor="postalCode" className="block mb-2 text-sm font-medium text-gray-900">Postal Code <span className="text-red-500">*</span></label>
                                <input type="text" id="postalCode" name="postalCode" value={formData.address?.postalCode} onChange={handleAddressChange} placeholder="PIN code" className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div className="md:col-span-2">
                                <label htmlFor="addressLine1" className="block mb-2 text-sm font-medium text-gray-900">Address Line 1 <span className="text-red-500">*</span></label>
                                <input type="text" id="addressLine1" name="addressLine1" value={formData.address?.addressLine1} onChange={handleAddressChange} placeholder="Street address, Flat no, etc." className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div className="md:col-span-2">
                                <label htmlFor="addressLine2" className="block mb-2 text-sm font-medium text-gray-900">Address Line 2 (Optional)</label>
                                <input type="text" id="addressLine2" name="addressLine2" value={formData.address?.addressLine2} onChange={handleAddressChange} placeholder="Apartment, suite, unit, etc." className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                            <div className="md:col-span-2">
                                <label htmlFor="landmark" className="block mb-2 text-sm font-medium text-gray-900">Landmark (Optional)</label>
                                <input type="text" id="landmark" name="landmark" value={formData.address?.landmark} onChange={handleAddressChange} placeholder="Near..." className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" />
                            </div>
                        </div>
                    </div>

                    {/* Parent & Family Info */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Parent &amp; Family Details</h3>

                        {/* Linked sibling badge */}
                        {selectedSiblingObj && (
                            <div className="flex items-center space-x-2 mb-4">
                                <span className="text-xs font-semibold bg-green-100 text-green-800 px-2 py-1 rounded border border-green-200">
                                    Linked Sibling: {selectedSiblingObj.firstName} {selectedSiblingObj.lastName} (ID: {selectedSiblingObj.id})
                                </span>
                                <button type="button" onClick={clearSibling} className="text-red-600 hover:text-red-800 text-xs font-medium underline">Remove Link</button>
                            </div>
                        )}

                        <div className="grid gap-6 md:grid-cols-2">
                            <div>
                                <label htmlFor="fathersName" className="block mb-2 text-sm font-medium text-gray-900">Father's Name <span className="text-red-500">*</span></label>
                                <input type="text" id="fathersName" name="fathersName" value={formData.fathersName} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" required />
                            </div>
                            <div>
                                <label htmlFor="fatherAadhaarNumber" className="block mb-2 text-sm font-medium text-gray-900">Father's UUID (Aadhaar Number) <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" id="fatherAadhaarNumber" name="fatherAadhaarNumber" value={formData.fatherAadhaarNumber} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" />
                            </div>
                            <div>
                                <label htmlFor="mothersName" className="block mb-2 text-sm font-medium text-gray-900">Mother's Name <span className="text-red-500">*</span></label>
                                <input type="text" id="mothersName" name="mothersName" value={formData.mothersName} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" required />
                            </div>
                            <div>
                                <label htmlFor="motherAadhaarNumber" className="block mb-2 text-sm font-medium text-gray-900">Mother's UUID (Aadhaar Number) <span className="text-gray-400 font-normal">(Optional)</span></label>
                                <input type="text" id="motherAadhaarNumber" name="motherAadhaarNumber" value={formData.motherAadhaarNumber} onChange={handleChange} disabled={!!selectedSiblingObj} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5 disabled:bg-gray-200 disabled:text-gray-500 disabled:cursor-not-allowed" />
                            </div>
                        </div>

                        {selectedSiblingObj && (
                            <p className="mt-2 text-xs text-blue-600 italic">Parent names are locked and synced with the linked sibling.</p>
                        )}

                        {/* Add Sibling button ΓÇö placed AFTER parent name fields */}
                        {!selectedSiblingObj && (
                            <div className="mt-4">
                                {siblingModalError && (
                                    <p className="text-xs text-red-600 mb-2">{siblingModalError}</p>
                                )}
                                <button
                                    type="button"
                                    onClick={openSiblingModal}
                                    className="text-white bg-green-600 hover:bg-green-700 focus:ring-4 focus:ring-green-300 font-medium rounded-lg text-xs px-3 py-1.5 focus:outline-none"
                                >
                                    + Add Sibling
                                </button>
                                <p className="text-xs text-gray-400 mt-1">Fill in Father&apos;s and Mother&apos;s Name first, then search for a sibling with matching parents.</p>
                            </div>
                        )}
                    </div>

                    {/* Additional Demographics */}
                    <div>
                        <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Demographics</h3>
                        <div className="grid gap-6 md:grid-cols-2">
                            <div>
                                <label htmlFor="category" className="block mb-2 text-sm font-medium text-gray-900">Category <span className="text-red-500">*</span></label>
                                <select id="category" name="category" value={formData.category} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required>
                                    <option value="">Select Category</option>
                                    <option value="General">General</option>
                                    <option value="SC">SC</option>
                                    <option value="ST">ST</option>
                                    <option value="OBC">OBC</option>
                                    <option value="EWS">EWS</option>
                                </select>
                            </div>
                            <div>
                                <label htmlFor="religion" className="block mb-2 text-sm font-medium text-gray-900">Religion <span className="text-red-500">*</span></label>
                                <select id="religion" name="religion" value={formData.religion} onChange={handleChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg block w-full p-2.5" required>
                                    <option value="">Select Religion</option>
                                    <option value="HINDU">HINDU</option>
                                    <option value="MUSLIM">MUSLIM</option>
                                    <option value="SIKH">SIKH</option>
                                    <option value="CHRISTIAN">CHRISTIAN</option>
                                    <option value="PARSI">PARSI</option>
                                    <option value="OTHERS">OTHERS</option>
                                </select>
                            </div>
                        </div>
                    </div>

                    {/* Fee Discounts */}
                    {availableDiscounts.length > 0 && (
                        <div>
                            <h3 className="text-lg font-bold mb-4 text-slate-700 border-b pb-2">Fee Discounts</h3>
                            <label className="block mb-3 text-sm font-medium text-gray-900">Fee Discounts applied to this student</label>
                            <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                {availableDiscounts.map(d => (
                                    <label key={d.id} className="flex flex-col p-3 border border-gray-200 bg-white rounded-lg cursor-pointer hover:bg-gray-50 transition-colors">
                                        <div className="flex items-center">
                                            <input
                                                type="checkbox"
                                                checked={selectedDiscounts.includes(d.id)}
                                                onChange={(e) => {
                                                    if (e.target.checked) setSelectedDiscounts([...selectedDiscounts, d.id]);
                                                    else setSelectedDiscounts(selectedDiscounts.filter(did => did !== d.id));
                                                }}
                                                className="w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
                                            />
                                            <span className="ml-2 text-sm font-medium text-gray-900">{d.name}</span>
                                        </div>
                                        <span className="mt-1 ml-6 text-xs text-gray-500">
                                            {d.type === 'PERCENTAGE' ? `${d.value}%` : `$${d.value}`}
                                            {d.applicationType === 'AUTO' && <span className="ml-1 text-[10px] bg-blue-100 text-blue-800 px-1 rounded font-bold">{d.logicReference}</span>}
                                        </span>
                                    </label>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Enrollment Section */}
                    <div className="pt-4 border-t mt-8">
                        <label className="flex items-center space-x-3 mb-6 cursor-pointer p-4 bg-blue-50 border border-blue-200 rounded-lg">
                            <input
                                type="checkbox"
                                checked={enrollStudent}
                                onChange={(e) => setEnrollStudent(e.target.checked)}
                                className="w-5 h-5 text-blue-600 bg-white border-gray-300 rounded focus:ring-blue-500"
                            />
                            <span className="text-base font-bold text-blue-900">Enroll this student immediately?</span>
                        </label>

                        {enrollStudent && (
                            <div className="bg-white p-6 rounded-lg border border-slate-200 space-y-6">
                                <h3 className="text-lg font-bold text-slate-700 border-b pb-2">Enrollment Details</h3>
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                    <div>
                                        <label className="block mb-1 text-sm font-medium">Academic Session</label>
                                        <select
                                            className="w-full border p-2 rounded focus:ring-2 focus:ring-blue-500 bg-white"
                                            value={selectedSessionId}
                                            onChange={e => setSelectedSessionId(e.target.value === "" ? "" : parseInt(e.target.value))}
                                        >
                                            <option value="">-- Select Session --</option>
                                            {academicSessions.map((s: any) => (
                                                <option key={s.id} value={s.id}>{s.name} {s.isActive ? '(Active)' : ''}</option>
                                            ))}
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block mb-1 text-sm font-medium">Class <span className="text-red-500">*</span></label>
                                        <select
                                            className="w-full border p-2 rounded focus:ring-2 focus:ring-blue-500 bg-white"
                                            value={selectedClass}
                                            onChange={e => {
                                                setSelectedClass(e.target.value);
                                                setSelectedSection(""); // reset section when class changes
                                            }}
                                            required={enrollStudent}
                                        >
                                            <option value="">-- Select Class --</option>
                                            {classes.map((c: any) => (
                                                <option key={c.id} value={c.id}>{c.name}</option>
                                            ))}
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block mb-1 text-sm font-medium">Section <span className="text-red-500">*</span></label>
                                        <select
                                            className="w-full border p-2 rounded focus:ring-2 focus:ring-blue-500 bg-white disabled:bg-slate-100"
                                            value={selectedSection}
                                            onChange={e => setSelectedSection(e.target.value)}
                                            disabled={!selectedClass || sections.length === 0}
                                            required={enrollStudent}
                                        >
                                            <option value="">-- Select Section --</option>
                                            {sections.map((sec: any) => (
                                                <option key={sec.id} value={sec.id}>{sec.name}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>

                                {/* Subject Selection */}
                                <div>
                                    <label className="block mb-2 text-sm font-medium">Elective/Extra Subjects (Optional)</label>
                                    <div className="p-3 border rounded bg-slate-50 max-h-48 overflow-y-auto">
                                        {subjects.length === 0 ? (
                                            <p className="text-sm text-slate-500">No subjects available.</p>
                                        ) : (
                                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                                                {subjects.map((sub: any) => (
                                                    <label key={sub.id} className="flex items-center space-x-2 text-sm cursor-pointer p-1 hover:bg-slate-200 rounded">
                                                        <input
                                                            type="checkbox"
                                                            checked={selectedSubjects.includes(sub.id.toString())}
                                                            onChange={() => handleSubjectToggle(sub.id.toString())}
                                                            className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                                        />
                                                        <span className="flex flex-col text-sm">
                                                            <span>{sub.name}</span>
                                                            <span className="flex items-center gap-2 mt-1">
                                                                {renderSubjectComponents(sub)}
                                                                {sub.code && <span className="text-xs text-slate-400">{sub.code}</span>}
                                                            </span>
                                                        </span>
                                                    </label>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                    <p className="text-xs text-slate-500 mt-1">Core subjects for the selected class are assigned automatically.</p>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="flex items-center space-x-4 pt-4 border-t">
                        <button type="submit" disabled={loading} className="text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:outline-none focus:ring-blue-300 font-bold rounded-lg text-lg w-full sm:w-auto px-8 py-3 text-center disabled:opacity-50">
                            {loading ? 'Registering...' : 'Register Student'}
                        </button>
                        <Link href="/dashboard/students" className="text-gray-900 bg-white border border-gray-300 focus:outline-none hover:bg-gray-100 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-3">
                            Cancel
                        </Link>
                    </div>
                </form>

                {/* Sibling Search Modal */}
                {showSiblingModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-50">
                        <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] flex flex-col">
                            <div className="flex items-center justify-between p-4 border-b">
                                <div>
                                    <h3 className="text-xl font-semibold text-gray-900">Search Existing Sibling</h3>
                                    <p className="text-xs text-gray-500 mt-0.5">
                                        Searching for siblings of: <span className="font-medium text-gray-700">{formData.fathersName}</span> &amp; <span className="font-medium text-gray-700">{formData.mothersName}</span>
                                    </p>
                                </div>
                                <button type="button" onClick={() => setShowSiblingModal(false)} className="text-gray-400 bg-transparent hover:bg-gray-200 hover:text-gray-900 rounded-lg text-sm w-8 h-8 ml-auto inline-flex justify-center items-center">
                                    <svg className="w-3 h-3" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 14 14"><path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="m1 1 6 6m0 0 6 6M7 7l6-6M7 7l-6 6" /></svg>
                                    <span className="sr-only">Close modal</span>
                                </button>
                            </div>
                            <div className="p-6 flex-1 overflow-y-auto">
                                {/* Search mode toggle */}
                                <div className="flex mb-3 rounded-lg overflow-hidden border border-gray-300 w-fit">
                                    <button
                                        type="button"
                                        onClick={() => { setSiblingSearchMode('name'); setSiblingSearch(''); setSiblingResults([]); }}
                                        className={`px-4 py-1.5 text-sm font-medium transition-colors ${siblingSearchMode === 'name'
                                            ? 'bg-blue-700 text-white'
                                            : 'bg-white text-gray-600 hover:bg-gray-100'
                                            }`}
                                    >
                                        Search by Name
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => { setSiblingSearchMode('id'); setSiblingSearch(''); setSiblingResults([]); }}
                                        className={`px-4 py-1.5 text-sm font-medium transition-colors ${siblingSearchMode === 'id'
                                            ? 'bg-blue-700 text-white'
                                            : 'bg-white text-gray-600 hover:bg-gray-100'
                                            }`}
                                    >
                                        Search by ID
                                    </button>
                                </div>
                                <form className="flex items-center space-x-2 mb-4" onSubmit={(e) => { e.preventDefault(); handleSearchSibling(); }}>
                                    <input
                                        type={siblingSearchMode === 'id' ? 'number' : 'text'}
                                        value={siblingSearch}
                                        onChange={e => setSiblingSearch(e.target.value)}
                                        placeholder={siblingSearchMode === 'id' ? 'Enter student ID (e.g. 42)' : 'Search by first or last name (e.g. Raj)'}
                                        className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                                    />
                                    <button type="submit" className="text-white bg-blue-700 hover:bg-blue-800 font-medium rounded-lg text-sm px-5 py-2.5" disabled={siblingLoading}>{siblingLoading ? '...' : 'Search'}</button>
                                </form>

                                <div className="mt-4">
                                    {siblingResults.length > 0 ? (
                                        <>
                                            <p className="text-xs text-gray-500 mb-2">
                                                <span className="inline-flex items-center mr-3"><span className="w-2 h-2 rounded-full bg-green-500 inline-block mr-1"></span>Names match ΓÇö can be linked</span>
                                                <span className="inline-flex items-center"><span className="w-2 h-2 rounded-full bg-red-400 inline-block mr-1"></span>Names don&apos;t match ΓÇö cannot link</span>
                                            </p>
                                            <ul className="divide-y divide-gray-200 border rounded-lg max-h-64 overflow-y-auto">
                                                {siblingResults.map(s => {
                                                    const match = isSiblingMatch(s);
                                                    return (
                                                        <li key={s.id} className={`p-3 flex justify-between items-center transition-colors ${match ? 'hover:bg-green-50' : 'bg-red-50 opacity-70'}`}>
                                                            <div>
                                                                <div className="flex items-center gap-2">
                                                                    <span className={`w-2 h-2 rounded-full shrink-0 ${match ? 'bg-green-500' : 'bg-red-400'}`}></span>
                                                                    <p className="text-sm font-medium text-gray-900">{s.firstName} {s.lastName}</p>
                                                                </div>
                                                                <p className="text-xs text-gray-500 ml-4">ID: {s.id} | Father: {s.fathersName || 'N/A'} | Mother: {s.mothersName || 'N/A'}</p>
                                                                {!match && (
                                                                    <p className="text-xs text-red-600 ml-4 mt-0.5">ΓÜá Parent names do not match ΓÇö cannot select as sibling</p>
                                                                )}
                                                            </div>
                                                            <button
                                                                type="button"
                                                                onClick={() => match && selectSibling(s)}
                                                                disabled={!match}
                                                                className={`font-medium rounded-lg text-xs px-3 py-1.5 focus:outline-none shrink-0 ml-2 ${match ? 'text-white bg-green-600 hover:bg-green-700' : 'text-gray-400 bg-gray-200 cursor-not-allowed'}`}
                                                            >
                                                                Select
                                                            </button>
                                                        </li>
                                                    );
                                                })}
                                            </ul>
                                        </>
                                    ) : (
                                        <p className="text-sm text-gray-500 italic text-center py-4">Search to find siblings.</p>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import Table from "../../../components/Table";
import { API_BASE_URL } from "@/lib/api";
import { toast } from "react-hot-toast";
import { useRbac } from "@/lib/rbac";
import { authFetch } from "@/lib/auth";

const PAGE_SIZE_OPTIONS = [10, 25, 50, 100];

export default function StudentsPage() {
    const [students, setStudents] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [classes, setClasses] = useState<any[]>([]);
    const [sections, setSections] = useState<any[]>([]);
    const [sessions, setSessions] = useState<any[]>([]);
    const rbac = useRbac();

    // Search Params
    const [searchSessionId, setSearchSessionId] = useState("");
    const [searchId, setSearchId] = useState("");
    const [searchFirstName, setSearchFirstName] = useState("");
    const [searchLastName, setSearchLastName] = useState("");
    const [searchEmail, setSearchEmail] = useState("");
    const [searchMobile, setSearchMobile] = useState("");
    const [searchParents, setSearchParents] = useState("");
    const [searchStatus, setSearchStatus] = useState("");
    const [searchClassId, setSearchClassId] = useState("");
    const [searchSectionId, setSearchSectionId] = useState("");

    const [hasSearched, setHasSearched] = useState(false);

    // Committed params ΓÇö only updated when Search is clicked, used by column renders
    const [committedSessionId, setCommittedSessionId] = useState("");
    const [committedStatus, setCommittedStatus] = useState("");

    // Pagination
    const [page, setPage] = useState(1);
    const [pageSize, setPageSize] = useState(25);
    const [total, setTotal] = useState(0);

    const totalPages = Math.ceil(total / pageSize);

    // Bulk Import Modal State
    const [showBulkModal, setShowBulkModal] = useState(false);
    const [bulkFile, setBulkFile] = useState<File | null>(null);
    const [bulkUploading, setBulkUploading] = useState(false);
    const [bulkResult, setBulkResult] = useState<{ successful: number; failed: number; errors: string[] } | null>(null);

    const buildParams = (overridePage?: number) => {
        const params = new URLSearchParams();
        if (searchId) params.append("id", searchId);
        if (searchFirstName) params.append("firstName", searchFirstName);
        if (searchLastName) params.append("lastName", searchLastName);
        if (searchEmail) params.append("email", searchEmail);
        if (searchMobile) params.append("mobile", searchMobile);
        if (searchParents) params.append("parentsName", searchParents);
        if (searchStatus !== "") params.append("enrollmentStatus", searchStatus);
        if (searchClassId) params.append("classId", searchClassId);
        if (searchSectionId) params.append("sectionId", searchSectionId);
        if (searchSessionId) params.append("academicSessionId", searchSessionId);
        params.append("page", String(overridePage ?? page));
        params.append("limit", String(pageSize));
        return params;
    };

    const fetchStudents = async (overridePage?: number) => {
        setLoading(true);
        try {
            const params = buildParams(overridePage);
            const res = await authFetch(`${API_BASE_URL}/students?${params.toString()}`);
            if (res.ok) {
                const data = await res.json();
                if (data && data.data) {
                    setStudents(data.data);
                    setTotal(data.total);
                    setPage(data.page);
                } else {
                    setStudents(Array.isArray(data) ? data : []);
                    setTotal(Array.isArray(data) ? data.length : 0);
                }
                setHasSearched(true);
                setCommittedSessionId(searchSessionId);
                setCommittedStatus(searchStatus);
            }
        } catch (err) {
            toast.error("Failed to fetch students");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        Promise.all([
            authFetch(`${API_BASE_URL}/classes`).then(r => r.json()),
            authFetch(`${API_BASE_URL}/academic-sessions`).then(r => r.json())
        ]).then(([classesData, sessionsData]) => {
            setClasses(Array.isArray(classesData) ? classesData : []);
            setSessions(Array.isArray(sessionsData) ? sessionsData : []);
            const activeSession = sessionsData.find((s: any) => s.isActive);
            if (activeSession) setSearchSessionId(activeSession.id.toString());
        }).catch(() => { });
    }, []);

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setPage(1);
        fetchStudents(1);
    };

    const handleClassChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const val = e.target.value;
        setSearchClassId(val);
        setSearchSectionId("");
        if (val) {
            const cls = classes.find((c: any) => c.id === parseInt(val));
            setSections(cls?.sections || []);
        } else {
            setSections([]);
        }
    };

    const handleReset = () => {
        setSearchId("");
        setSearchFirstName("");
        setSearchLastName("");
        setSearchEmail("");
        setSearchMobile("");
        setSearchParents("");
        setSearchStatus("");
        setSearchClassId("");
        setSearchSectionId("");
        const activeSession = sessions.find((s: any) => s.isActive);
        setSearchSessionId(activeSession ? activeSession.id.toString() : "");
        setSections([]);
        setStudents([]);
        setHasSearched(false);
        setCommittedSessionId("");
        setCommittedStatus("");
        setPage(1);
        setTotal(0);
    };

    const handlePageChange = (newPage: number) => {
        if (newPage < 1 || newPage > totalPages) return;
        setPage(newPage);
        fetchStudents(newPage);
    };

    const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const newSize = parseInt(e.target.value);
        setPageSize(newSize);
        setPage(1);
        // Re-fetch with new page size ΓÇö use setTimeout to let state settle
        setTimeout(() => fetchStudents(1), 0);
    };

    const handleBulkUpload = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!bulkFile) return;

        setBulkUploading(true);
        setBulkResult(null);
        try {
            const formData = new FormData();
            formData.append("file", bulkFile);

            const res = await authFetch(`${API_BASE_URL}/students/bulk-import`, {
                method: "POST",
                body: formData, // No Content-Type header here, browser sets it with boundary for multipart/form-data
            });

            if (!res.ok) {
                const err = await res.json();
                toast.error(err.message || "Failed to upload file");
            } else {
                const result = await res.json();
                setBulkResult(result);
                
                if (result.successful > 0 && result.failed === 0) {
                    toast.success(`Successfully imported ${result.successful} students`);
                    fetchStudents(1); // Refresh list
                    setTimeout(() => setShowBulkModal(false), 2000);
                } else if (result.successful > 0) {
                    toast.success(`Partially imported ${result.successful} students. Check errors.`);
                    fetchStudents(1); // Refresh list
                }
            }
        } catch (error) {
            toast.error("An error occurred during bulk import");
        } finally {
            setBulkUploading(false);
        }
    };

    const columns = [
        { header: "ID", accessor: "id", sortable: true },
        {
            header: "Roll No",
            sortable: true,
            render: (row: any) => {
                const enrollment = row.enrollments?.find((e: any) => e.academicSession?.id === parseInt(committedSessionId))
                    ?? (committedStatus ? row.enrollments?.find((e: any) => e.status === committedStatus) : undefined)
                    ?? row.enrollments?.find((e: any) => e.status === 'ACTIVE');
                const rollNo = enrollment?.rollNo ?? row.rollNo;
                return (rollNo && rollNo !== 0) ? rollNo : 'N/A';
            }
        },
        { header: "First Name", accessor: "firstName", sortable: true },
        { header: "Last Name", accessor: "lastName", sortable: true },
        {
            header: "Class / Section",
            render: (row: any) => {
                const enrollment = row.enrollments?.find((e: any) => e.academicSession?.id === parseInt(searchSessionId))
                    ?? (committedStatus ? row.enrollments?.find((e: any) => e.status === committedStatus) : undefined);
                if (enrollment) {
                    return `${enrollment.class?.name || '-'} ${enrollment.section ? '- ' + enrollment.section.name : ''}`;
                }
                return row.class ? `${row.class.name} ${row.section ? '- ' + row.section.name : ''}` : '-';
            }
        },
        {
            header: "Subjects",
            render: (row: any) => row.studentSubjects && row.studentSubjects.length > 0
                ? row.studentSubjects.map((ss: any) => (ss.subject || ss.extraSubject)?.name).filter(Boolean).join(', ')
                : '-'
        },
        {
            header: "Status",
            render: (row: any) => {
                const enrollment = row.enrollments?.find((e: any) => e.academicSession?.id === parseInt(committedSessionId))
                    ?? (committedStatus ? row.enrollments?.find((e: any) => e.status === committedStatus) : undefined)
                    ?? row.enrollments?.find((e: any) => e.status === 'ACTIVE');
                const displayStatus = enrollment ? enrollment.status : (row.isActive ? 'ACTIVE' : 'INACTIVE');

                let colorClass = 'bg-slate-100 text-slate-800';
                if (displayStatus === 'ACTIVE') colorClass = 'bg-green-100 text-green-800';
                else if (displayStatus === 'PROMOTED') colorClass = 'bg-blue-100 text-blue-800';
                else if (displayStatus === 'ALUMNI') colorClass = 'bg-purple-100 text-purple-800';
                else if (displayStatus === 'WITHDRAWN' || displayStatus === 'INACTIVE') colorClass = 'bg-red-100 text-red-800';

                return (
                    <span className={`px-2.5 py-1 text-xs font-semibold rounded-full ${colorClass}`}>
                        {displayStatus}
                    </span>
                );
            }
        },
        {
            header: "Actions",
            render: (row: any) => rbac.canManageStudents ? (
                <Link href={`/dashboard/students/${row.id}/edit`} className="font-medium text-blue-600 hover:underline">Edit</Link>
            ) : (
                <Link href={`/dashboard/students/${row.id}/edit`} className="font-medium text-slate-400 text-xs">View</Link>
            )
        }
    ];

    const getPageNumbers = () => {
        const pages: (number | '...')[] = [];
        if (totalPages <= 7) {
            for (let i = 1; i <= totalPages; i++) pages.push(i);
        } else {
            pages.push(1);
            if (page > 3) pages.push('...');
            const start = Math.max(2, page - 1);
            const end = Math.min(totalPages - 1, page + 1);
            for (let i = start; i <= end; i++) pages.push(i);
            if (page < totalPages - 2) pages.push('...');
            pages.push(totalPages);
        }
        return pages;
    };

    return (
        <main className="p-4 bg-slate-50 min-h-screen">
            <div className="max-w-7xl mx-auto">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
                    <h1 className="text-2xl font-bold text-slate-800">Students Management</h1>
                    <div className="flex flex-wrap gap-2 w-full sm:w-auto">
                        {rbac.canManageStudents && (
                            <button
                                onClick={() => {
                                    setBulkFile(null);
                                    setBulkResult(null);
                                    setShowBulkModal(true);
                                }}
                                className="flex-1 sm:flex-none text-center text-gray-700 bg-white border border-gray-300 hover:bg-gray-50 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-2.5 focus:outline-none whitespace-nowrap"
                            >
                                Bulk Import
                            </button>
                        )}
                        {rbac.canBulkOperateStudents && (
                            <Link href="/dashboard/students/promotions" className="flex-1 sm:flex-none text-center text-white bg-amber-600 hover:bg-amber-700 focus:ring-4 focus:ring-amber-300 font-medium rounded-lg text-sm px-5 py-2.5 focus:outline-none whitespace-nowrap">
                                Bulk Promotions
                            </Link>
                        )}
                        {rbac.canManageStudents && (
                            <Link href="/dashboard/students/new" className="flex-1 sm:flex-none text-center text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:ring-blue-300 font-medium rounded-lg text-sm px-5 py-2.5 focus:outline-none whitespace-nowrap">
                                Add Student
                            </Link>
                        )}
                    </div>
                </div>

                {/* Advanced Search Filter */}
                <div className="bg-white p-5 rounded-lg shadow-sm border border-slate-200 mb-6">
                    <h2 className="text-lg font-semibold text-slate-700 mb-4">Search Students</h2>
                    <form onSubmit={handleSearch}>
                        <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-4">
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Student ID</label>
                                <input type="text" value={searchId} onChange={e => setSearchId(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="e.g. 1" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">First Name</label>
                                <input type="text" value={searchFirstName} onChange={e => setSearchFirstName(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="First Name" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Last Name</label>
                                <input type="text" value={searchLastName} onChange={e => setSearchLastName(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="Last Name" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Email</label>
                                <input type="text" value={searchEmail} onChange={e => setSearchEmail(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="Email Address" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Mobile Number</label>
                                <input type="text" value={searchMobile} onChange={e => setSearchMobile(e.target.value.replace(/\D/g, ''))} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="Exact Mobile No." />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Parent's Name</label>
                                <input type="text" value={searchParents} onChange={e => setSearchParents(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2" placeholder="Mother or Father" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Status</label>
                                <select value={searchStatus} onChange={e => setSearchStatus(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2">
                                    <option value="">All</option>
                                    <option value="ACTIVE">Active</option>
                                    <option value="PROMOTED">Promoted</option>
                                    <option value="ALUMNI">Alumni</option>
                                    <option value="WITHDRAWN">Withdrawn</option>
                                    <option value="GRADUATED">Graduated</option>
                                </select>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-4">
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Academic Year</label>
                                <select value={searchSessionId} onChange={e => setSearchSessionId(e.target.value)} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2">
                                    <option value="">All Sessions</option>
                                    {sessions.map((s: any) => (
                                        <option key={s.id} value={s.id}>{s.name} {s.isActive ? '(Active)' : ''}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Class</label>
                                <select value={searchClassId} onChange={handleClassChange} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2">
                                    <option value="">All Classes</option>
                                    {classes.map((c: any) => (
                                        <option key={c.id} value={c.id}>{c.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-gray-700 mb-1">Section</label>
                                <select value={searchSectionId} onChange={e => setSearchSectionId(e.target.value)} disabled={!searchClassId} className="bg-gray-50 border border-gray-300 text-sm rounded-lg w-full p-2 disabled:opacity-50 disabled:cursor-not-allowed">
                                    <option value="">All Sections</option>
                                    {sections.map((s: any) => (
                                        <option key={s.id} value={s.id}>{s.name}</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="flex justify-end gap-2">
                            <button type="button" onClick={handleReset} className="px-5 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 focus:ring-4 focus:ring-gray-200">
                                Reset
                            </button>
                            <button type="submit" className="px-5 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 focus:ring-4 focus:ring-blue-300">
                                Search
                            </button>
                        </div>
                    </form>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200">
                    {!hasSearched ? (
                        <div className="text-center py-12 text-slate-500">
                            <svg className="mx-auto h-12 w-12 text-slate-400 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                            </svg>
                            <h3 className="text-lg font-medium text-slate-900 mb-1">Find Students</h3>
                            <p className="text-sm">Please apply filters and click Search to view the student list.</p>
                        </div>
                    ) : (
                        <>
                            <Table
                                columns={columns}
                                data={students}
                                loading={loading}
                                defaultSortColumn="id"
                                defaultSortDirection="asc"
                                emptyMessage="No students found matching the search criteria."
                            />

                            {/* Pagination Controls */}
                            {!loading && total > 0 && (
                                <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mt-4 pt-4 border-t border-slate-200">
                                    <div className="flex items-center gap-2 text-sm text-slate-600">
                                        <span>Rows per page:</span>
                                        <select
                                            value={pageSize}
                                            onChange={handlePageSizeChange}
                                            className="border border-gray-300 rounded-md text-sm p-1"
                                        >
                                            {PAGE_SIZE_OPTIONS.map(opt => (
                                                <option key={opt} value={opt}>{opt}</option>
                                            ))}
                                        </select>
                                        <span className="ml-2">
                                            {Math.min((page - 1) * pageSize + 1, total)}ΓÇô{Math.min(page * pageSize, total)} of {total}
                                        </span>
                                    </div>

                                    <div className="flex items-center gap-1">
                                        <button
                                            onClick={() => handlePageChange(page - 1)}
                                            disabled={page === 1}
                                            className="px-3 py-1.5 text-sm rounded-md border border-gray-300 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed"
                                        >
                                            ΓåÉ Prev
                                        </button>

                                        {getPageNumbers().map((p, idx) =>
                                            p === '...' ? (
                                                <span key={`ellipsis-${idx}`} className="px-2 py-1.5 text-sm text-slate-400">ΓÇª</span>
                                            ) : (
                                                <button
                                                    key={p}
                                                    onClick={() => handlePageChange(p as number)}
                                                    className={`px-3 py-1.5 text-sm rounded-md border ${page === p
                                                        ? 'bg-blue-600 text-white border-blue-600'
                                                        : 'border-gray-300 hover:bg-gray-50'
                                                        }`}
                                                >
                                                    {p}
                                                </button>
                                            )
                                        )}

                                        <button
                                            onClick={() => handlePageChange(page + 1)}
                                            disabled={page === totalPages}
                                            className="px-3 py-1.5 text-sm rounded-md border border-gray-300 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed"
                                        >
                                            Next ΓåÆ
                                        </button>
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </div>

                {/* Bulk Import Modal */}
                {showBulkModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-50">
                        <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] flex flex-col">
                            <div className="flex items-center justify-between p-4 border-b">
                                <h3 className="text-xl font-semibold text-gray-900">Bulk Import Students</h3>
                                <button onClick={() => setShowBulkModal(false)} className="text-gray-400 bg-transparent hover:bg-gray-200 hover:text-gray-900 rounded-lg text-sm w-8 h-8 ms-auto inline-flex justify-center items-center">
                                    <svg className="w-3 h-3" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 14 14">
                                        <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="m1 1 6 6m0 0 6 6M7 7l6-6M7 7l-6 6" />
                                    </svg>
                                </button>
                            </div>
                            <div className="p-4 overflow-y-auto">
                                <div className="mb-4 text-sm text-gray-600 bg-blue-50 p-4 rounded-lg border border-blue-100">
                                    <p className="font-semibold mb-2">CSV Format Requirements:</p>
                                    <ul className="list-disc pl-5 space-y-1">
                                        <li>Must contain headers exactly as shown below (order matters):</li>
                                        <li className="font-mono text-xs bg-gray-100 p-1 rounded overflow-x-auto whitespace-nowrap">firstName,lastName,gender,dateOfBirth,mobile,email,alternateMobile,category,religion,bloodGroup,aadhaarNumber,fathersName,fatherAadhaarNumber,mothersName,motherAadhaarNumber,addressLine1,addressLine2,landmark,city,state,postalCode,country,classId,sectionId,academicSessionId,subjectIds</li>
                                        <li><span className="font-semibold text-red-600">Required:</span> firstName, lastName, gender, dateOfBirth, mobile, fathersName, mothersName, category, religion</li>
                                        <li><span className="font-semibold">Optional fields</span> can be left empty, but the column must still be present.</li>
                                        <li><span className="font-semibold">dateOfBirth:</span> Use format YYYY-MM-DD</li>
                                        <li><span className="font-semibold">subjectIds:</span> Pipe-separated values e.g. <code className="bg-gray-200 px-1 rounded">1|3|4</code></li>
                                        <li><span className="font-semibold">country:</span> Full country name e.g. <code className="bg-gray-200 px-1 rounded">INDIA</code> (leave blank to default to INDIA)</li>
                                    </ul>
                                    <button
                                        type="button"
                                        onClick={() => {
                                            const headers = "firstName,lastName,gender,dateOfBirth,mobile,email,alternateMobile,category,religion,bloodGroup,aadhaarNumber,fathersName,fatherAadhaarNumber,mothersName,motherAadhaarNumber,addressLine1,addressLine2,landmark,city,state,postalCode,country,classId,sectionId,academicSessionId,subjectIds";
                                            const sample = "John,Doe,Male,2010-05-15,9876543210,john.doe@example.com,,General,HINDU,O+,,Ramesh Doe,,Sunita Doe,,12 Main Street,,Near Park,Delhi,DL,110001,INDIA,1,1,1,1|2";
                                            const blob = new Blob([headers + "\n" + sample], { type: "text/csv" });
                                            const url = URL.createObjectURL(blob);
                                            const a = document.createElement("a");
                                            a.href = url;
                                            a.download = "students-import-template.csv";
                                            a.click();
                                            URL.revokeObjectURL(url);
                                        }}
                                        className="mt-3 inline-flex items-center gap-1 text-xs text-blue-700 hover:text-blue-900 font-medium underline"
                                    >
                                        Γ¼ç Download CSV Template
                                    </button>
                                </div>

                                <form onSubmit={handleBulkUpload}>
                                    <label className="block mb-2 text-sm font-medium text-gray-900">Upload CSV File</label>
                                    <input 
                                        type="file" 
                                        accept=".csv"
                                        onChange={(e) => setBulkFile(e.target.files?.[0] || null)}
                                        className="block w-full text-sm text-gray-900 border border-gray-300 rounded-lg cursor-pointer bg-gray-50 focus:outline-none p-2 mb-4" 
                                        required
                                    />

                                    {bulkResult && (
                                        <div className={`p-4 mb-4 text-sm rounded-lg ${bulkResult.failed > 0 ? 'bg-orange-50 text-orange-800 border border-orange-200' : 'bg-green-50 text-green-800 border border-green-200'}`}>
                                            <p className="font-bold mb-2">Import Results:</p>
                                            <p>Γ£à {bulkResult.successful} students successfully created and enrolled.</p>
                                            {bulkResult.failed > 0 && <p>Γ¥î {bulkResult.failed} failed.</p>}
                                            {bulkResult.errors?.length > 0 && (
                                                <div className="mt-2 max-h-32 overflow-y-auto text-xs bg-white p-2 rounded border border-orange-100">
                                                    {bulkResult.errors.map((err, i) => (
                                                        <div key={i} className="mb-1 text-red-600 font-mono">{err}</div>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    )}

                                    <div className="flex justify-end gap-2 mt-6">
                                        <button 
                                            type="button" 
                                            onClick={() => setShowBulkModal(false)} 
                                            className="text-gray-700 bg-white border border-gray-300 hover:bg-gray-50 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-2.5"
                                        >
                                            Close
                                        </button>
                                        <button 
                                            type="submit" 
                                            disabled={!bulkFile || bulkUploading}
                                            className="text-white bg-blue-600 hover:bg-blue-700 focus:ring-4 focus:ring-blue-300 font-medium rounded-lg text-sm px-5 py-2.5 disabled:opacity-50"
                                        >
                                            {bulkUploading ? 'Importing...' : 'Upload & Import'}
                                        </button>
                                    </div>
                                </form>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { API_BASE_URL } from "@/lib/api";
import { authFetch } from "@/lib/auth";

export default function EditSubjectPage() {
    const router = useRouter();
    const params = useParams();
    const id = params?.id as string;
    const [formData, setFormData] = useState({
        name: "",
        subjectCategory: "BASE",
        hasTheory: true,
        hasPractical: false,
        feeCategoryId: ""
    });
    const [feeCategories, setFeeCategories] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState("");

    useEffect(() => {
        // Fetch fee categories
        authFetch(`${API_BASE_URL}/fees/categories`)
            .then(res => res.json())
            .then(data => setFeeCategories(data))
            .catch(err => console.error("Failed to fetch fee categories", err));

        if (!id) return;
        const fetchSubject = async () => {
            try {
                const res = await authFetch(`${API_BASE_URL}/subjects`); // Ideally fetch single subject
                if (!res.ok) throw new Error("Failed to fetch subjects");
                const subjects = await res.json();
                const subject = subjects.find((s: any) => s.id === parseInt(id));

                if (subject) {
                    setFormData({
                        name: subject.name,
                        subjectCategory: subject.subjectCategory || "BASE",
                        hasTheory: subject.hasTheory !== undefined ? subject.hasTheory : true,
                        hasPractical: subject.hasPractical || false,
                        feeCategoryId: subject.feeCategory ? subject.feeCategory.id.toString() : ""
                    });
                } else {
                    setError("Subject not found");
                }
            } catch (err) {
                setError("Failed to load subject data");
            } finally {
                setLoading(false);
            }
        };

        fetchSubject();
    }, [id]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const value = e.target.type === 'checkbox' ? (e.target as HTMLInputElement).checked : e.target.value;
        setFormData({ ...formData, [e.target.name]: value });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setError("");
        try {
            const payload: any = {
                name: formData.name,
                subjectCategory: formData.subjectCategory,
                hasTheory: formData.hasTheory,
                hasPractical: formData.hasPractical
            };
            if (formData.feeCategoryId) {
                payload.feeCategoryId = parseInt(formData.feeCategoryId);
            } else {
                payload.feeCategoryId = null;
            }

            const res = await authFetch(`${API_BASE_URL}/subjects/${id}`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify(payload),
            });

            if (!res.ok) {
                const errData = await res.json().catch(() => ({}));
                throw new Error(errData.message || "Failed to update subject");
            }

            router.push("/dashboard/subjects");
            router.refresh();
        } catch (err) {
            console.error(err);
            setError("Failed to update subject. Please try again.");
        } finally {
            setSaving(false);
        }
    };

    if (loading) return <div className="p-4">Loading...</div>;
    if (error) return <div className="p-4 text-red-600">{error}</div>;

    return (
        <main className="p-4">
            <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-sm border border-slate-200">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold text-slate-800">Edit Subject</h2>
                    <Link href="/dashboard/subjects" className="text-blue-600 hover:underline">
                        &larr; Back to Subjects
                    </Link>
                </div>

                <form onSubmit={handleSubmit}>
                    <div className="mb-6">
                        <label htmlFor="name" className="block mb-2 text-sm font-medium text-gray-900">Subject Name</label>
                        <input
                            type="text"
                            id="name"
                            name="name"
                            value={formData.name}
                            onChange={handleChange}
                            className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            required
                        />
                    </div>

                    <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block mb-2 text-sm font-medium text-gray-900">Subject Category</label>
                            <select
                                name="subjectCategory"
                                value={formData.subjectCategory}
                                onChange={handleChange}
                                className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            >
                                <option value="BASE">Base / Compulsory</option>
                                <option value="OPTIONAL">Optional</option>
                                <option value="VOCATIONAL">Vocational</option>
                                <option value="ACTIVITY">Activity</option>
                            </select>
                        </div>

                        <div>
                            <label className="block mb-2 text-sm font-medium text-gray-900">Linked Fee Category (Optional)</label>
                            <select
                                name="feeCategoryId"
                                value={formData.feeCategoryId}
                                onChange={handleChange}
                                className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            >
                                <option value="">-- None (Implicit) --</option>
                                {feeCategories.map(c => (
                                    <option key={c.id} value={c.id}>{c.name}</option>
                                ))}
                            </select>
                            <p className="mt-1 text-xs text-gray-500">If mapped, opting into this subject will auto-apply this fee type dynamically.</p>
                        </div>
                    </div>

                    <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-6 bg-gray-50 p-4 rounded-lg border border-gray-200">
                        <div className="flex items-center space-x-2">
                            <input
                                type="checkbox"
                                id="hasTheory"
                                name="hasTheory"
                                checked={formData.hasTheory}
                                onChange={handleChange}
                                className="w-4 h-4 text-blue-600 bg-white border-gray-300 rounded focus:ring-blue-500"
                            />
                            <label htmlFor="hasTheory" className="text-sm font-medium text-gray-900">Has Theory Component?</label>
                        </div>
                        <div className="flex items-center space-x-2">
                            <input
                                type="checkbox"
                                id="hasPractical"
                                name="hasPractical"
                                checked={formData.hasPractical}
                                onChange={handleChange}
                                className="w-4 h-4 text-blue-600 bg-white border-gray-300 rounded focus:ring-blue-500"
                            />
                            <label htmlFor="hasPractical" className="text-sm font-medium text-gray-900">Has Practical Component?</label>
                        </div>
                        <div className="col-span-1 md:col-span-2">
                            <p className="text-xs text-gray-500">If both are checked, exam data entry will provide separate fields for Theory and Practical marks which auto-sum to the total.</p>
                        </div>
                    </div>

                    <div className="flex items-center space-x-4">
                        <button
                            type="submit"
                            disabled={saving}
                            className="text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:outline-none focus:ring-blue-300 font-medium rounded-lg text-sm w-full sm:w-auto px-5 py-2.5 text-center disabled:opacity-50"
                        >
                            {saving ? 'Saving...' : 'Save Changes'}
                        </button>
                        <Link href="/dashboard/subjects" className="text-gray-900 bg-white border border-gray-300 focus:outline-none hover:bg-gray-100 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-2.5">
                            Cancel
                        </Link>
                    </div>
                </form>
            </div>
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import useSWR from "swr";
import { fetcher, API_BASE_URL } from "@/lib/api";
import toast from "react-hot-toast";
import { useRbac } from "@/lib/rbac";
import { authFetch } from "@/lib/auth";

export default function AddSubjectPage() {
    const router = useRouter();
    const rbac = useRbac();

    // Route guard ΓÇö only SUB_ADMIN and above can add subjects
    useEffect(() => {
        if (!rbac.canManageSubjects) {
            toast.error("You don't have permission to add subjects.");
            router.replace('/dashboard/subjects');
        }
    }, [rbac.canManageSubjects, router]);

    const [name, setName] = useState("");
    const [subjectCategory, setSubjectCategory] = useState("BASE");
    const [hasTheory, setHasTheory] = useState(true);
    const [hasPractical, setHasPractical] = useState(false);
    const [feeCategoryId, setFeeCategoryId] = useState("");
    const { data: feeCategories = [] } = useSWR('/fees/categories', fetcher);

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            const res = await authFetch(`${API_BASE_URL}/subjects`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({
                    name,
                    subjectCategory,
                    hasTheory,
                    hasPractical,
                    feeCategoryId: feeCategoryId ? parseInt(feeCategoryId) : undefined
                }),
            });

            if (!res.ok) {
                throw new Error("Failed to create subject");
            }

            router.push("/dashboard/subjects");
            router.refresh();
        } catch (err) {
            setError("Failed to create subject. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <main className="p-4">
            <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-sm border border-slate-200">
                <h2 className="text-2xl font-bold mb-6 text-slate-800">Add New Subject</h2>

                {error && (
                    <div className="p-4 mb-4 text-sm text-red-800 rounded-lg bg-red-50" role="alert">
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    <div className="mb-6">
                        <label htmlFor="name" className="block mb-2 text-sm font-medium text-gray-900">Subject Name</label>
                        <input
                            type="text"
                            id="name"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            placeholder="Mathematics"
                            required
                        />
                    </div>

                    <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block mb-2 text-sm font-medium text-gray-900">Subject Category</label>
                            <select
                                value={subjectCategory}
                                onChange={(e) => setSubjectCategory(e.target.value)}
                                className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            >
                                <option value="BASE">Base / Compulsory</option>
                                <option value="OPTIONAL">Optional</option>
                                <option value="VOCATIONAL">Vocational</option>
                                <option value="ACTIVITY">Activity</option>
                            </select>
                        </div>

                        <div>
                            <label className="block mb-2 text-sm font-medium text-gray-900">Linked Fee Category (Optional)</label>
                            <select
                                value={feeCategoryId}
                                onChange={(e) => setFeeCategoryId(e.target.value)}
                                className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5"
                            >
                                <option value="">-- None (Implicit) --</option>
                                {feeCategories.map((c: any) => (
                                    <option key={c.id} value={c.id}>{c.name}</option>
                                ))}
                            </select>
                            <p className="mt-1 text-xs text-gray-500">If mapped, opting into this subject will auto-apply this fee type dynamically.</p>
                        </div>
                    </div>

                    <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-6 bg-gray-50 p-4 rounded-lg border border-gray-200">
                        <div className="flex items-center space-x-2">
                            <input
                                type="checkbox"
                                id="hasTheory"
                                checked={hasTheory}
                                onChange={(e) => setHasTheory(e.target.checked)}
                                className="w-4 h-4 text-blue-600 bg-white border-gray-300 rounded focus:ring-blue-500"
                            />
                            <label htmlFor="hasTheory" className="text-sm font-medium text-gray-900">Has Theory Component?</label>
                        </div>
                        <div className="flex items-center space-x-2">
                            <input
                                type="checkbox"
                                id="hasPractical"
                                checked={hasPractical}
                                onChange={(e) => setHasPractical(e.target.checked)}
                                className="w-4 h-4 text-blue-600 bg-white border-gray-300 rounded focus:ring-blue-500"
                            />
                            <label htmlFor="hasPractical" className="text-sm font-medium text-gray-900">Has Practical Component?</label>
                        </div>
                        <div className="col-span-1 md:col-span-2">
                            <p className="text-xs text-gray-500">If both are checked, exam data entry will provide separate fields for Theory and Practical marks which auto-sum to the total.</p>
                        </div>
                    </div>

                    <div className="flex items-center space-x-4">
                        <button
                            type="submit"
                            disabled={loading}
                            className="text-white bg-blue-700 hover:bg-blue-800 focus:ring-4 focus:outline-none focus:ring-blue-300 font-medium rounded-lg text-sm w-full sm:w-auto px-5 py-2.5 text-center disabled:opacity-50"
                        >
                            {loading ? 'Creating...' : 'Create Subject'}
                        </button>
                        <Link href="/dashboard/subjects" className="text-gray-900 bg-white border border-gray-300 focus:outline-none hover:bg-gray-100 focus:ring-4 focus:ring-gray-200 font-medium rounded-lg text-sm px-5 py-2.5">
                            Cancel
                        </Link>
                    </div>
                </form>
            </div>
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { API_BASE_URL } from "@/lib/api";
import { setTokens, getDashboardRoute, getUser, markMustChangePasswordFlow } from "@/lib/auth";
import SplashScreen from "@/components/SplashScreen";

type Tab = "parent" | "staff";

export default function LoginPage() {
  const router = useRouter();
  const [activeTab, setActiveTab] = useState<Tab>("staff");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showSplash, setShowSplash] = useState(false);

  // Parent form
  const [mobile, setMobile] = useState("");
  // Staff form
  const [emailPrefix, setEmailPrefix] = useState("");
  const [password, setPassword] = useState("");

  // Redirect if already logged in
  useEffect(() => {
    const user = getUser();
    if (user) {
      setShowSplash(true);
      setTimeout(() => {
        if (user.mustChangePassword) {
          markMustChangePasswordFlow();
          router.replace("/change-password");
        } else {
          router.replace(getDashboardRoute(user.role));
        }
      }, 1500);
    }
  }, [router]);

  const handleParentLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);
    try {
      const res = await fetch(`${API_BASE_URL}/auth/login/parent`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ mobile, password }),
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(data.message || "Invalid mobile number or password");
      setTokens(data.access_token, data.refresh_token);
      setShowSplash(true);
      setTimeout(() => {
        if (data.user.mustChangePassword) {
          markMustChangePasswordFlow();
          router.push("/change-password");
        } else {
          router.push("/parent-dashboard");
        }
      }, 1500);
