"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { API_BASE_URL } from "@/lib/api";
import { getToken, authFetch } from "@/lib/auth";

export default function ParentDashboardPage() {
    const router = useRouter();
    const [students, setStudents] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    useEffect(() => {
        const fetchStudents = async () => {
            try {
                const res = await authFetch(`${API_BASE_URL}/parent/my-students`, {
                    headers: { Authorization: `Bearer ${getToken()}` },
                });
                if (!res.ok) throw new Error("Failed to load students");
                const data = await res.json();
                setStudents(data);
            } catch (err: any) {
                setError(err.message || "Failed to load students");
            } finally {
                setLoading(false);
            }
        };
        fetchStudents();
    }, []);

    const avatarColors = [
        "from-violet-500 to-purple-600",
        "from-indigo-500 to-blue-600",
        "from-pink-500 to-rose-600",
        "from-emerald-500 to-teal-600",
        "from-amber-500 to-orange-600",
    ];

    if (loading) return (
        <div className="flex flex-col items-center justify-center py-24 gap-4">
            <div className="w-10 h-10 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin" />
            <p className="text-slate-400 text-sm">Loading your students...</p>
        </div>
    );

    return (
        <div className="max-w-6xl mx-auto space-y-6">
            {/* Header */}
            <div className="mb-8 animate-fade-in">
                <div className="flex items-center gap-3 mb-2">
                    <div className="w-10 h-10 rounded-xl bg-indigo-500/20 flex items-center justify-center text-indigo-400 border border-indigo-500/30 shadow-inner">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                        </svg>
                    </div>
                    <h1 className="text-white text-3xl sm:text-4xl font-extrabold tracking-tight">Enrolled Students</h1>
                </div>
                <p className="text-slate-400 text-sm sm:text-base">Select a student to view their dashboard and track their progress.</p>
            </div>

            {error && (
                <div className="flex items-center gap-3 p-4 bg-red-500/10 border border-red-500/30 rounded-2xl text-red-400 mb-6 animate-slide-up">
                    <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    {error}
                </div>
            )}

            {!loading && students.length === 0 && !error && (
                <div className="text-center py-24 bg-slate-900/50 border border-slate-800 rounded-3xl animate-scale-in">
                    <div className="w-20 h-20 mx-auto rounded-full bg-slate-800/80 flex items-center justify-center mb-5 ring-4 ring-slate-800/30">
                        <svg className="w-8 h-8 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                        </svg>
                    </div>
                    <p className="text-slate-400 text-lg font-medium mb-2">No students found</p>
                    <p className="text-slate-500 text-sm max-w-sm mx-auto">
                        Your mobile number is not linked to any student record. Please contact the school administration.
                    </p>
                </div>
            )}

            {/* Student Cards Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
                {students.map((student, idx) => (
                    <Link
                        key={student.id}
                        href={`/parent-dashboard/student/${student.id}`}
                        className="group relative bg-slate-900 border border-slate-800 rounded-3xl p-6 sm:p-7 hover:bg-slate-800/50 hover:border-indigo-500/50 hover:shadow-2xl hover:shadow-indigo-500/10 transition-all duration-300 overflow-hidden animate-slide-up"
                        style={{ animationDelay: `${idx * 100}ms` }}
                    >
                        {/* Background glow on hover */}
                        <div className="absolute inset-0 bg-linear-to-br from-indigo-500/5 to-purple-500/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

                        <div className="relative">
                            {/* Header Section of Card */}
                            <div className="flex items-center gap-4 mb-6">
                                {/* Avatar */}
                                <div className={`w-16 h-16 rounded-2xl bg-linear-to-br ${avatarColors[idx % avatarColors.length]} flex items-center justify-center text-white text-2xl font-bold shadow-lg shrink-0 group-hover:scale-105 transition-transform duration-300`}>
                                    {student.firstName?.[0]}{student.lastName?.[0]}
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h3 className="text-white text-xl font-bold truncate group-hover:text-indigo-300 transition-colors">
                                        {student.firstName} {student.lastName}
                                    </h3>
                                    <div className="flex flex-col items-start gap-2 mt-2">
                                        <div className="flex items-center gap-1.5 px-2.5 py-1 bg-indigo-500/10 text-indigo-300 text-xs rounded-lg font-medium border border-indigo-500/20 whitespace-nowrap">
                                            <svg className="w-3.5 h-3.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
                                            </svg>
                                            {student.className || 'N/A'}
                                        </div>
                                        <div className="flex items-center gap-1.5 px-2.5 py-1 bg-purple-500/10 text-purple-300 text-xs rounded-lg font-medium border border-purple-500/20 whitespace-nowrap">
                                            <svg className="w-3.5 h-3.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
                                            </svg>
                                            Section {student.sectionName || 'N/A'}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* Details */}
                            <div className="flex flex-wrap gap-2 mb-6 bg-slate-950/50 rounded-2xl p-4 border border-slate-800/50">
                                <div className="flex items-center gap-1.5 px-3 py-1.5 bg-sky-500/10 text-sky-300 text-xs rounded-lg font-medium border border-sky-500/20 w-fit whitespace-nowrap">
                                    <svg className="w-3.5 h-3.5 opacity-80 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V8a2 2 0 00-2-2h-5m-4 0V5a2 2 0 114 0v1m-4 0a2 2 0 104 0m-5 8a2 2 0 100-4 2 2 0 000 4zm0 0c1.306 0 2.417.835 2.83 2M9 14a3.001 3.001 0 00-2.83 2M15 11h3m-3 4h3" />
                                    </svg>
                                    Roll No: {student.rollNo || 'N/A'}
                                </div>
                                <div className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-500/10 text-emerald-300 text-xs rounded-lg font-medium border border-emerald-500/20 w-fit whitespace-nowrap">
                                    <svg className="w-3.5 h-3.5 opacity-80 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                                    </svg>
                                    {student.academicSession || 'N/A'}
                                </div>
                            </div>

                            {/* View button */}
                            <div className="flex items-center justify-center w-full py-3 bg-indigo-500/10 text-indigo-400 group-hover:bg-indigo-500 group-hover:text-white text-sm font-semibold rounded-xl transition-all duration-300 gap-2 border border-indigo-500/20 group-hover:border-indigo-500 shadow-sm">
                                View Dashboard
                                <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                                </svg>
                            </div>
                        </div>
                    </Link>
                ))}
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { getUser, getRefreshToken, setTokens, removeToken, authFetch } from "@/lib/auth";
import { API_BASE_URL } from "@/lib/api";

type Session = {
    id: string;
    deviceInfo: string;
    ipAddress: string;
    lastActive: string;
    expiresAt: string;
    isCurrent?: boolean;
};

export default function ParentProfilePage() {
    const [user, setUser] = useState<any>(null);
    const [activeTab, setActiveTab] = useState<"general" | "security">("general");

    // Session State
    const [sessions, setSessions] = useState<Session[]>([]);
    const [loadingSessions, setLoadingSessions] = useState(false);
    const [sessionError, setSessionError] = useState("");
    const [logoutError, setLogoutError] = useState("");
    const [logoutingDevices, setLogoutingDevices] = useState<Set<string>>(new Set());
    const [logoutingAll, setLogoutingAll] = useState(false);
    // Ref held across renders so we can abort stale fetchSessions calls
    const fetchAbortRef = useRef<AbortController | null>(null);

    // Password State
    const [currentPassword, setCurrentPassword] = useState("");
    const [newPassword, setNewPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [pwLoading, setPwLoading] = useState(false);
    const [pwError, setPwError] = useState("");
    const [pwSuccess, setPwSuccess] = useState("");
    const [showCurrent, setShowCurrent] = useState(false);
    const [showNew, setShowNew] = useState(false);

    useEffect(() => {
        const u = getUser();
        if (u) setUser(u);
    }, []);

    const fetchSessions = useCallback(async () => {
        // Abort any in-flight request before starting a new one
        fetchAbortRef.current?.abort();
        fetchAbortRef.current = new AbortController();
        const signal = fetchAbortRef.current.signal;

        setLoadingSessions(true);
        setSessionError("");
        try {
            const refresh = getRefreshToken();
            const res = await authFetch(
                `${API_BASE_URL}/auth/sessions?currentRefreshToken=${refresh || ''}`,
                { signal } as RequestInit,
            );
            if (signal.aborted) return;
            if (res.ok) {
                const data = await res.json();
                setSessions(data);
            } else {
                setSessionError("Failed to load sessions. Pull down to retry.");
            }
        } catch (err: any) {
            if (err?.name === 'AbortError') return;
            console.error("Failed to fetch sessions", err);
            setSessionError("Failed to load sessions. Pull down to retry.");
        } finally {
            if (!signal.aborted) setLoadingSessions(false);
        }
    }, []);

    // Fetch sessions when switching to security tab
    useEffect(() => {
        if (activeTab === "security") {
            fetchSessions();
        }
    }, [activeTab, fetchSessions]);

    // PWA fix: re-fetch sessions when user returns to the tab/app from background
    useEffect(() => {
        if (activeTab !== "security") return;
        const handleVisibility = () => {
            if (document.visibilityState === "visible") {
                fetchSessions();
            }
        };
        document.addEventListener("visibilitychange", handleVisibility);
        return () => document.removeEventListener("visibilitychange", handleVisibility);
    }, [activeTab, fetchSessions]);

    const handleChangePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setPwError("");
        setPwSuccess("");

        if (newPassword !== confirmPassword) {
            setPwError("New passwords do not match");
            return;
        }
        if (newPassword.length < 6) {
            setPwError("Password must be at least 6 characters");
            return;
        }
        if (newPassword === currentPassword) {
            setPwError("New password must be different from current password");
            return;
        }

        setPwLoading(true);
        try {
            const res = await authFetch(`${API_BASE_URL}/auth/change-password`, {
                method: "POST",
                body: JSON.stringify({ currentPassword, newPassword }),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.message || "Failed to change password");

            if (data.refresh_token) {
                setTokens(data.access_token, data.refresh_token);
            }

            setPwSuccess("Password changed successfully!");
            setCurrentPassword("");
            setNewPassword("");
            setConfirmPassword("");
        } catch (err: any) {
            setPwError(err.message || "Failed to change password");
        } finally {
            setPwLoading(false);
        }
    };

    const handleLogoutDevice = async (sessionId: string) => {
        setLogoutError("");
        setLogoutingDevices(prev => new Set(prev).add(sessionId));
        try {
            const res = await authFetch(`${API_BASE_URL}/auth/logout-device/${sessionId}`, {
                method: "POST",
            });
            if (res.ok) {
                setSessions(prev => prev.filter(s => s.id !== sessionId));
            } else {
                const data = await res.json().catch(() => ({}));
                setLogoutError(data.message || "Failed to log out device. Please try again.");
            }
        } catch (err: any) {
            setLogoutError("Network error. Please check your connection and try again.");
        } finally {
            setLogoutingDevices(prev => { const s = new Set(prev); s.delete(sessionId); return s; });
        }
    };

    const handleLogoutAll = async () => {
        setLogoutError("");
        setLogoutingAll(true);
        try {
            const res = await authFetch(`${API_BASE_URL}/auth/logout-all`, {
                method: "POST",
            });
            if (res.ok) {
                // Clear local tokens immediately so this device is logged out right away
                removeToken();
                window.location.href = "/";
            } else {
                const data = await res.json().catch(() => ({}));
                setLogoutError(data.message || "Failed to log out of all devices. Please try again.");
                setLogoutingAll(false);
            }
        } catch (err: any) {
            setLogoutError("Network error. Please check your connection and try again.");
            setLogoutingAll(false);
        }
    };

    if (!user) return null;

    return (
        <div className="max-w-4xl mx-auto">
            <h1 className="text-2xl font-bold text-white mb-6">Account Settings</h1>

            {/* Tabs */}
            <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1.5 flex gap-1.5 mb-6">
                <button
                    onClick={() => setActiveTab("general")}
                    className={`flex-1 flex items-center justify-center gap-2 py-2.5 px-4 rounded-xl text-sm font-semibold transition-all duration-200 ${activeTab === "general"
                        ? "bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-lg shadow-indigo-500/20"
                        : "text-slate-500 hover:text-slate-300"
                    }`}
                >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                    </svg>
                    General Information
                </button>
                <button
                    onClick={() => setActiveTab("security")}
                    className={`flex-1 flex items-center justify-center gap-2 py-2.5 px-4 rounded-xl text-sm font-semibold transition-all duration-200 ${activeTab === "security"
                        ? "bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-lg shadow-indigo-500/20"
                        : "text-slate-500 hover:text-slate-300"
                    }`}
                >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                    </svg>
                    Security &amp; Login
                </button>
            </div>

            {/* General Tab */}
            {activeTab === "general" && (
                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6">
                    <div className="flex items-center gap-5 mb-8">
                        <div className="h-20 w-20 rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white text-3xl font-bold shadow-lg shadow-indigo-500/20 flex-shrink-0">
                            {user.firstName[0]}{user.lastName[0]}
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-white">{user.firstName} {user.lastName}</h2>
                            <p className="text-slate-400 text-sm mt-0.5">Linked Parent Account</p>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                        <div>
                            <label className="block text-xs font-medium text-slate-500 uppercase tracking-wider mb-1.5">First Name</label>
                            <div className="px-4 py-2.5 bg-slate-800 border border-slate-700 rounded-lg text-white min-h-11">
                                {user.firstName || '\u00A0'}
                            </div>
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-500 uppercase tracking-wider mb-1.5">Last Name</label>
                            <div className="px-4 py-2.5 bg-slate-800 border border-slate-700 rounded-lg text-white min-h-11">
                                {user.lastName || '\u00A0'}
                            </div>
                        </div>
                        {user.mobile && (
                            <div className="sm:col-span-2">
                                <label className="block text-xs font-medium text-slate-500 uppercase tracking-wider mb-1.5">Registered Mobile Number</label>
                                <div className="px-4 py-2.5 bg-slate-800 border border-slate-700 rounded-lg text-white">
                                    +91 {user.mobile}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Security Tab */}
            {activeTab === "security" && (
                <div className="space-y-6">
                    {/* Change Password */}
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6">
                        <h3 className="text-lg font-bold text-white mb-1">Change Password</h3>
                        <p className="text-sm text-slate-400 mb-6">Update your account password to stay secure.</p>

                        <form onSubmit={handleChangePassword} className="space-y-4 max-w-md">
                            <div>
                                <label className="block text-sm font-medium text-slate-400 mb-1.5">Current Password</label>
                                <div className="relative">
                                    <input
                                        type={showCurrent ? "text" : "password"}
                                        value={currentPassword}
                                        onChange={e => setCurrentPassword(e.target.value)}
                                        required
                                        className="w-full bg-slate-800 border border-slate-700 text-white rounded-lg px-4 py-2.5 pr-10 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none placeholder-slate-500 transition-colors"
                                        placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                    />
                                    <button type="button" onClick={() => setShowCurrent(!showCurrent)} className="absolute right-3 top-2.5 text-slate-500 hover:text-slate-300 transition-colors">
                                        ≡ƒæü∩╕ÅΓÇì≡ƒù¿∩╕Å
                                    </button>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-400 mb-1.5">New Password</label>
                                <div className="relative">
                                    <input
                                        type={showNew ? "text" : "password"}
                                        value={newPassword}
                                        onChange={e => setNewPassword(e.target.value)}
                                        required minLength={6}
                                        className="w-full bg-slate-800 border border-slate-700 text-white rounded-lg px-4 py-2.5 pr-10 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none placeholder-slate-500 transition-colors"
                                        placeholder="Min. 6 characters"
                                    />
                                    <button type="button" onClick={() => setShowNew(!showNew)} className="absolute right-3 top-2.5 text-slate-500 hover:text-slate-300 transition-colors">
                                        ≡ƒæü∩╕ÅΓÇì≡ƒù¿∩╕Å
                                    </button>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-400 mb-1.5">Confirm Password</label>
                                <input
                                    type="password"
                                    value={confirmPassword}
                                    onChange={e => setConfirmPassword(e.target.value)}
                                    required
                                    className="w-full bg-slate-800 border border-slate-700 text-white rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none placeholder-slate-500 transition-colors"
                                    placeholder="Re-enter password"
                                />
                            </div>

                            {pwError && (
                                <div className="flex items-start gap-2.5 text-sm text-red-400 bg-red-500/10 p-3 rounded-lg border border-red-500/30">
                                    <svg className="w-4 h-4 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                    {pwError}
                                </div>
                            )}
                            {pwSuccess && (
                                <div className="flex items-start gap-2.5 text-sm text-green-400 bg-green-500/10 p-3 rounded-lg border border-green-500/30">
                                    <svg className="w-4 h-4 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                    {pwSuccess}
                                </div>
                            )}

                            <button
                                type="submit"
                                disabled={pwLoading}
                                className="px-5 py-2.5 bg-indigo-600 text-white font-medium rounded-lg hover:bg-indigo-500 disabled:opacity-50 transition-colors"
                            >
                                {pwLoading ? "UpdatingΓÇª" : "Update Password"}
                            </button>
                        </form>
                    </div>

                    {/* Active Sessions Block */}
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden">
                        <div className="p-6 border-b border-slate-800">
                            <h3 className="text-lg font-bold text-white mb-1">Active Sessions</h3>
