"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { API_BASE_URL } from "@/lib/api";
import { setToken, setTokens } from "@/lib/auth";

type Step = "mobile" | "otp" | "students" | "details";

export default function RegisterParentPage() {
    const router = useRouter();

    const [step, setStep] = useState<Step>("mobile");

    // Step 1 ΓÇö Mobile
    const [mobile, setMobile] = useState("");
    const [mobileCheck, setMobileCheck] = useState<{ status: "idle" | "checking" | "found" | "not_found"; students: any[] }>({ status: "idle", students: [] });
    const [sendingOtp, setSendingOtp] = useState(false);
    const [otpSendError, setOtpSendError] = useState("");

    // Step 2 ΓÇö OTP
    const [otp, setOtp] = useState("");
    const [otpError, setOtpError] = useState("");
    const [verifying, setVerifying] = useState(false);
    const [countdown, setCountdown] = useState(0);

    // After OTP verified
    const [registrationToken, setRegistrationToken] = useState("");
    const [linkedStudents, setLinkedStudents] = useState<any[]>([]);

    // Step 4 ΓÇö Details
    const [form, setForm] = useState({ firstName: "", lastName: "", email: "", password: "", confirmPassword: "", parentType: "", fatherAadhaarNumber: "", motherAadhaarNumber: "" });
    const [showPw, setShowPw] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [submitError, setSubmitError] = useState("");
    const [namesLocked, setNamesLocked] = useState(false);

    // Helper: Split name into First and Last according to logic
    const parseName = (fullName: string) => {
        if (!fullName) return { first: "", last: "" };
        const parts = fullName.trim().split(/\s+/);
        if (parts.length === 1) return { first: parts[0], last: "" };
        if (parts.length === 2) return { first: parts[0], last: parts[1] };
        // 3 or more words: First Name = word1 + word2, Last Name = rest
        const first = parts.slice(0, 2).join(' ');
        const last = parts.slice(2).join(' ');
        return { first, last };
    };

    const handleRoleSelection = (role: string) => {
        if (role === 'GUARDIAN') {
            setNamesLocked(false);
            setForm(prev => ({ ...prev, parentType: role, firstName: "", lastName: "" }));
            return;
        }

        // FATHER or MOTHER
        if (linkedStudents.length > 0) {
            const student = linkedStudents[0]; // Assuming we fetch from the first linked student
            let nameToParse = "";

            if (role === 'FATHER') {
                nameToParse = student.fathersName || "";
            } else if (role === 'MOTHER') {
                nameToParse = student.mothersName || "";
            }

            const { first, last } = parseName(nameToParse);

            setForm(prev => ({
                ...prev,
                parentType: role,
                firstName: first,
                lastName: last
            }));

            // Only lock names if we actually found a name to auto-fill
            if (first) {
                setNamesLocked(true);
            } else {
                setNamesLocked(false);
            }

        } else {
            setForm(prev => ({ ...prev, parentType: role }));
        }
    };

    // ΓöÇΓöÇ Debounced mobile check ΓöÇΓöÇ
    const checkMobile = useCallback(async (num: string) => {
        if (num.length < 10) { setMobileCheck({ status: "idle", students: [] }); return; }
        setMobileCheck({ status: "checking", students: [] });
        try {
            const res = await fetch(`${API_BASE_URL}/auth/parent/check-mobile?mobile=${encodeURIComponent(num)}`);
            const data = await res.json();
            setMobileCheck({ status: data.found ? "found" : "not_found", students: data.students || [] });
        } catch {
            setMobileCheck({ status: "idle", students: [] });
        }
    }, []);

    useEffect(() => {
        setOtpSendError("");
        const t = setTimeout(() => checkMobile(mobile), 500);
        return () => clearTimeout(t);
    }, [mobile, checkMobile]);

    // ΓöÇΓöÇ Countdown timer for OTP ΓöÇΓöÇ
    useEffect(() => {
        if (countdown <= 0) return;
        const t = setInterval(() => setCountdown(c => c - 1), 1000);
        return () => clearInterval(t);
    }, [countdown]);

    // ΓöÇΓöÇ Step 1: Send OTP ΓöÇΓöÇ
    const handleSendOtp = async () => {
        setSendingOtp(true);
        setOtpSendError("");
        try {
            const res = await fetch(`${API_BASE_URL}/auth/parent/request-otp`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ mobile }),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.message || "Failed to send OTP");
            setStep("otp");
            setCountdown(600); // 10 min countdown display
        } catch (err: any) {
            setOtpSendError(err.message || "Failed to send OTP. Please try again.");
        } finally {
            setSendingOtp(false);
        }
    };

    // ΓöÇΓöÇ Step 2: Verify OTP ΓöÇΓöÇ
    const handleVerifyOtp = async (e: React.FormEvent) => {
        e.preventDefault();
        setOtpError("");
        setVerifying(true);
        try {
            const res = await fetch(`${API_BASE_URL}/auth/parent/verify-otp`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ mobile, otp }),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.message || "Invalid OTP");
            setRegistrationToken(data.registrationToken);
            setLinkedStudents(data.students || []);
            setStep("students");
        } catch (err: any) {
            setOtpError(err.message || "Invalid OTP");
        } finally {
            setVerifying(false);
        }
    };

    // ΓöÇΓöÇ Step 4: Complete Registration ΓöÇΓöÇ
    const handleRegister = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitError("");
        if (form.password !== form.confirmPassword) { setSubmitError("Passwords do not match"); return; }
        if (!form.parentType) { setSubmitError("Please select a registration role"); return; }
        setSubmitting(true);
        try {
            const res = await fetch(`${API_BASE_URL}/auth/parent/register`, {
                method: "POST",
                headers: { "Content-Type": "application/json", Authorization: `Bearer ${registrationToken}` },
                body: JSON.stringify({
                    firstName: form.firstName,
                    lastName: form.lastName,
                    email: form.email || undefined,
                    password: form.password,
                    parentType: form.parentType
                }),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.message || "Registration failed");
            setTokens(data.access_token, data.refresh_token);
            router.push("/parent-dashboard");
        } catch (err: any) {
            setSubmitError(err.message || "Registration failed");
            // If it's a duplicate role error, unlock fields to let them change it
            if (err.message && err.message.includes('already registered as')) {
                setNamesLocked(false);
            }
        } finally {
            setSubmitting(false);
        }
    };

    const avatarColors = ["from-violet-500 to-purple-600", "from-indigo-500 to-blue-600", "from-pink-500 to-rose-600", "from-emerald-500 to-teal-600"];

    return (
        <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
            <div className="w-full max-w-md">
                {/* Header */}
                <div className="flex flex-col items-center mb-8">
                    <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/30 mb-4">
                        <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                        </svg>
                    </div>
                    <h1 className="text-white text-2xl font-bold">Register as Parent</h1>
                    <p className="text-slate-400 text-sm mt-1">Access your child&apos;s school information</p>
                </div>

                {/* Progress Steps */}
                <div className="flex items-center justify-center gap-2 mb-8">
                    {(["mobile", "otp", "students", "details"] as Step[]).map((s, i) => {
                        const stepIndex = ["mobile", "otp", "students", "details"].indexOf(step);
                        const thisIndex = i;
                        const done = thisIndex < stepIndex;
                        const active = thisIndex === stepIndex;
                        return (
                            <div key={s} className="flex items-center gap-2">
                                <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold transition-all ${done ? "bg-green-500 text-white" : active ? "bg-indigo-600 text-white" : "bg-slate-800 text-slate-500"}`}>
                                    {done ? "Γ£ô" : i + 1}
                                </div>
                                {i < 3 && <div className={`w-8 h-0.5 ${done ? "bg-green-500" : "bg-slate-800"}`} />}
                            </div>
                        );
                    })}
                </div>

                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-2xl">

                    {/* ΓöÇΓöÇΓöÇ STEP 1: Mobile ΓöÇΓöÇΓöÇ */}
                    {step === "mobile" && (
                        <div className="space-y-5">
                            <div>
                                <h2 className="text-white font-bold text-lg mb-1">Enter your mobile number</h2>
                                <p className="text-slate-400 text-sm">Use the number registered at school for your child</p>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-2">Mobile Number</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                                        <svg className="w-4 h-4 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" />
                                        </svg>
                                    </div>
                                    <input
                                        type="tel" value={mobile} onChange={e => setMobile(e.target.value.replace(/\D/, '').slice(0, 10))}
                                        maxLength={10} placeholder="9876543210"
                                        className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl px-4 py-3 pl-10 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                    />
                                    {mobileCheck.status === "checking" && (
                                        <div className="absolute inset-y-0 right-3 flex items-center">
                                            <svg className="animate-spin w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg>
                                        </div>
                                    )}
                                </div>

                                {/* Feedback */}
                                {mobileCheck.status === "found" && (
                                    <div className="mt-2 flex items-center gap-2 text-green-400 text-sm">
                                        <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                                        {mobileCheck.students.length} student{mobileCheck.students.length > 1 ? "s" : ""} found linked to this number
                                    </div>
                                )}
                                {mobileCheck.status === "not_found" && (
                                    <div className="mt-2 flex items-start gap-2 text-red-400 text-sm">
                                        <svg className="w-4 h-4 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                        <span>This number is not linked to any student. Please ask the school to update your mobile number in the student record first.</span>
                                    </div>
                                )}
                            </div>

                            {otpSendError && (
                                <div className="flex items-start gap-2 text-red-400 text-sm p-3 bg-red-500/10 border border-red-500/20 rounded-xl">
                                    <svg className="w-4 h-4 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                    <span>{otpSendError}</span>
                                </div>
                            )}

                            <button
                                onClick={handleSendOtp}
                                disabled={mobileCheck.status !== "found" || sendingOtp}
                                className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 disabled:opacity-40 disabled:cursor-not-allowed transition-all flex items-center justify-center gap-2"
                            >
                                {sendingOtp ? <><svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg> Sending...</> : "Send OTP via WhatsApp ΓåÆ"}
                            </button>
                        </div>
                    )}

                    {/* ΓöÇΓöÇΓöÇ STEP 2: OTP ΓöÇΓöÇΓöÇ */}
                    {step === "otp" && (
                        <form onSubmit={handleVerifyOtp} className="space-y-5">
                            <div>
                                <h2 className="text-white font-bold text-lg mb-1">Enter OTP</h2>
                                <p className="text-slate-400 text-sm">
                                    OTP sent to <span className="text-white font-medium">{mobile}</span>
                                </p>
                                <p className="text-slate-500 text-xs mt-1">
                                    {countdown > 0 ? `Expires in ${Math.floor(countdown / 60)}:${String(countdown % 60).padStart(2, "0")}` : "OTP expired"}
                                </p>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-2">One-Time Password</label>
                                <input
                                    type="text" value={otp} onChange={e => setOtp(e.target.value.replace(/\D/, "").slice(0, 6))}
                                    placeholder="Enter OTP" maxLength={6} autoFocus
                                    className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl px-4 py-3 text-2xl tracking-widest text-center font-mono focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                />
                                {otpError && (
                                    <p className="mt-2 text-red-400 text-sm flex items-center gap-1">
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                        {otpError}
                                    </p>
                                )}
                            </div>

                            <div className="flex gap-3">
                                <button type="button" onClick={() => setStep("mobile")} className="px-4 py-3 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl text-sm transition-colors">ΓåÉ Back</button>
                                <button type="submit" disabled={otp.length < 4 || verifying}
                                    className="flex-1 py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 disabled:opacity-40 transition-all flex items-center justify-center gap-2">
                                    {verifying ? <><svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg> Verifying...</> : "Verify OTP"}
                                </button>
                            </div>
                            <button type="button" onClick={handleSendOtp} disabled={sendingOtp}
                                className="w-full text-center text-slate-500 hover:text-slate-300 text-sm transition-colors">
                                Didn&apos;t receive? Resend OTP
                            </button>
                        </form>
                    )}

                    {/* ΓöÇΓöÇΓöÇ STEP 3: Confirm Students ΓöÇΓöÇΓöÇ */}
                    {step === "students" && (
                        <div className="space-y-5">
                            <div>
                                <h2 className="text-white font-bold text-lg mb-1">
                                    {linkedStudents.length > 0 ? "Confirm your children" : "No students found"}
                                </h2>
                                <p className="text-slate-400 text-sm">
                                    {linkedStudents.length > 0
                                        ? "These students are linked to your mobile number"
                                        : "Your mobile is verified, but no active students are found"}
                                </p>
                            </div>

                            {linkedStudents.length > 0 ? (
                                <div className="space-y-2">
                                    {linkedStudents.map((s, i) => (
                                        <div key={s.id} className={`flex items-center gap-3 p-3 bg-gradient-to-r ${avatarColors[i % avatarColors.length]} rounded-xl bg-opacity-10`}>
                                            <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${avatarColors[i % avatarColors.length]} flex items-center justify-center text-white text-sm font-bold`}>
                                                {s.firstName?.[0]}{s.lastName?.[0]}
                                            </div>
                                            <div>
                                                <p className="text-white font-semibold text-sm">{s.firstName} {s.lastName}</p>
                                                <p className="text-slate-400 text-xs">{s.className ? `Enrolled in ${s.className}${s.sectionName ? ` ΓÇô ${s.sectionName}` : ""}` : "Details pending"}</p>
                                            </div>
                                            <svg className="w-5 h-5 text-green-400 ml-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="p-4 bg-amber-500/10 border border-amber-500/20 rounded-xl text-amber-300 text-sm">
                                    Contact the school to link students to your mobile number.
                                </div>
                            )}

                            <div className="flex gap-3">
                                <button onClick={() => setStep("otp")} className="px-4 py-3 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl text-sm transition-colors">ΓåÉ Back</button>
                                <button onClick={() => setStep("details")}
                                    className="flex-1 py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 transition-all">
                                    {linkedStudents.length > 0 ? "Looks Good, Continue ΓåÆ" : "Continue Anyway ΓåÆ"}
                                </button>
                            </div>
                        </div>
                    )}

                    {/* ΓöÇΓöÇΓöÇ STEP 4: Fill Details ΓöÇΓöÇΓöÇ */}
                    {step === "details" && (
                        <form onSubmit={handleRegister} className="space-y-4">
                            <div>
                                <h2 className="text-white font-bold text-lg mb-1">Create your account</h2>
                                <p className="text-slate-400 text-sm">Almost done! Fill in your details.</p>
                            </div>

                            <div className="grid grid-cols-2 gap-3 mb-4">
                                <div className="col-span-2">
                                    <label className="block text-sm font-medium text-slate-300 mb-1">Register As <span className="text-red-500">*</span></label>
                                    <select
                                        value={form.parentType}
                                        onChange={e => handleRoleSelection(e.target.value)}
                                        required
                                        className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                    >
                                        <option value="" disabled>Select Role</option>
                                        <option value="FATHER">Father</option>
                                        <option value="MOTHER">Mother</option>
                                        <option value="GUARDIAN">Guardian</option>
                                    </select>
                                    {namesLocked && <p className="text-xs text-green-400 mt-1">Name auto-filled from student records.</p>}
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-1">First Name <span className="text-red-500">*</span></label>
                                    <input value={form.firstName} onChange={e => setForm({ ...form, firstName: e.target.value })} disabled={namesLocked} required placeholder="Raj"
                                        className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-1">Last Name</label>
                                    <input value={form.lastName} onChange={e => setForm({ ...form, lastName: e.target.value })} disabled={namesLocked} placeholder="Patel"
                                        className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50" />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-1">Email (optional)</label>
                                <input type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} placeholder="raj@example.com"
                                    className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-1">Password <span className="text-red-500">*</span></label>
                                <div className="relative">
                                    <input type={showPw ? "text" : "password"} value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required minLength={6} placeholder="Min. 6 characters"
                                        className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl px-3 py-2.5 pr-10 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                                    <button type="button" onClick={() => setShowPw(!showPw)} className="absolute inset-y-0 right-3 flex items-center text-slate-500 hover:text-slate-300">
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={showPw ? "M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" : "M15 12a3 3 0 11-6 0 3 3 0 016 0zM2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"} /></svg>
                                    </button>
                                </div>
                                {/* Strength bar */}
                                {form.password && (
                                    <div className="flex gap-1 mt-1.5">
                                        {[1, 2, 3, 4].map(i => (
                                            <div key={i} className={`h-1 flex-1 rounded-full ${form.password.length >= i * 2 ? i <= 1 ? "bg-red-500" : i <= 2 ? "bg-yellow-500" : i <= 3 ? "bg-blue-500" : "bg-green-500" : "bg-slate-700"}`} />
                                        ))}
                                    </div>
                                )}
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-1">Confirm Password <span className="text-red-500">*</span></label>
                                <input type="password" value={form.confirmPassword} onChange={e => setForm({ ...form, confirmPassword: e.target.value })} required placeholder="Re-enter password"
                                    className={`w-full bg-slate-800 border text-white placeholder-slate-500 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:border-transparent transition-all ${form.confirmPassword && form.confirmPassword !== form.password ? "border-red-500/70 focus:ring-red-500" : "border-slate-700 focus:ring-indigo-500"}`} />
                            </div>

                            {submitError && (
                                <div className="flex items-center gap-2 px-4 py-3 bg-red-500/10 border border-red-500/30 rounded-xl text-red-400 text-sm">
                                    <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                    {submitError}
                                </div>
                            )}

                            <div className="flex gap-3">
                                <button type="button" onClick={() => setStep("students")} className="px-4 py-3 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl text-sm transition-colors">ΓåÉ Back</button>
                                <button type="submit" disabled={submitting}
                                    className="flex-1 py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 disabled:opacity-50 transition-all flex items-center justify-center gap-2">
                                    {submitting ? <><svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg> Creating...</> : "Γ£ô Create Account"}
                                </button>
                            </div>
                        </form>
                    )}
                </div>

                <p className="text-center text-slate-600 text-sm mt-6">
                    Already have an account?{" "}
                    <Link href="/" className="text-indigo-400 hover:text-indigo-300 font-medium transition-colors">Sign In</Link>
                </p>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import useSWR from "swr";
import { API_BASE_URL, fetcher } from "@/lib/api";
import { authFetch } from "@/lib/auth";
import { Loader } from "@/components/ui/Loader";
import toast from "react-hot-toast";

interface Props {
    studentId: number | null;
    sessionId: number | null;
    onClose: () => void;
    onSave?: () => void;
}

export default function StudentResultModal({ studentId, sessionId, onClose, onSave }: Props) {
    const { data: categories = [], isLoading: catsLoading } = useSWR(
        sessionId ? `${API_BASE_URL}/exams/categories/active?sessionId=${sessionId}` : null, 
        fetcher
    );
    // Fetch marks for student
    const { data: marks = [], isLoading: marksLoading, mutate: mutateMarks } = useSWR(
        studentId && sessionId ? `${API_BASE_URL}/exams/marks/${sessionId}/${studentId}` : null,
        fetcher
    );
    const { data: student, isLoading: studentLoading } = useSWR(
        studentId ? `${API_BASE_URL}/students/${studentId}` : null,
        fetcher
    );

    // Fetch Exam Settings to know the target category
    const { data: examSettings, isLoading: settingsLoading } = useSWR(
        sessionId ? `${API_BASE_URL}/exams/settings?sessionId=${sessionId}` : null,
        fetcher
    );

    // Fetch Grading Systems to calculate overall grades dynamically
    const { data: gradingSystems = [], isLoading: gradingLoading } = useSWR(
        sessionId ? `${API_BASE_URL}/exams/grading-system/session/${sessionId}` : null,
        fetcher
    );

    const [isEditMode, setIsEditMode] = useState(false);
    // We'll store editable marks in a local state
    const [editedMarks, setEditedMarks] = useState<any[]>([]);

    useEffect(() => {
        if (marks.length && student) {
            // copy from fetched data
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setEditedMarks(JSON.parse(JSON.stringify(marks)));
        } else if (student && student.studentSubjects) {
            // Initialize empty marks map if none exists
            const initialMarks: any[] = [];
            student.studentSubjects.forEach((ss: any) => {
                const subject = ss.subject || ss.extraSubject;
                categories.forEach((cat: any) => {
                    initialMarks.push({
                        subjectId: subject.id,
                        subjectName: subject.name,
                        examCategoryId: cat.id,
                        examCategoryName: cat.name,
                        totalMarks: '',
                        obtainedMarks: '',
                        grade: '',
                        isPass: null
                    });
                });
            });
            setEditedMarks(initialMarks);
        }
    }, [marks, student, categories]);

    if (!studentId || !sessionId) return null;

    const isLoading = catsLoading || marksLoading || studentLoading || gradingLoading || settingsLoading;

    // Helper to get mark for a subject + category
    const getMark = (subjectId: number, catId: number) => {
        return editedMarks.find(m => m.subjectId === subjectId && m.examCategoryId === catId) || {};
    };

    const handleMarkChange = (subjectId: number, catId: number, field: string, value: any) => {
        setEditedMarks(prev => {
            const next = [...prev];
            const idx = next.findIndex(m => m.subjectId === subjectId && m.examCategoryId === catId);
            if (idx !== -1) {
                next[idx] = { ...next[idx], [field]: value };
            } else {
                // Should not happen if initialized properly, but safely push
                next.push({
                    subjectId, examCategoryId: catId,
                    theoryTotalMarks: '', theoryObtainedMarks: '', practicalTotalMarks: '', practicalObtainedMarks: '', totalMarks: '', obtainedMarks: '', grade: '', isPass: null,
                    [field]: value
                });
            }
            return next;
        });
    };

    const handleSave = async () => {
        try {
            const invalidMark = editedMarks.find(m => {
                const subject = student?.studentSubjects?.find((s:any) => (s.subject?.id || s.extraSubject?.id) === m.subjectId);
                const isSplit = subject?.subject?.hasTheory && subject?.subject?.hasPractical;

                if (isSplit) {
                    const invalidTh = m.theoryTotalMarks != null && m.theoryTotalMarks !== '' && m.theoryObtainedMarks != null && m.theoryObtainedMarks !== '' && Number(m.theoryObtainedMarks) > Number(m.theoryTotalMarks);
                    const invalidPr = m.practicalTotalMarks != null && m.practicalTotalMarks !== '' && m.practicalObtainedMarks != null && m.practicalObtainedMarks !== '' && Number(m.practicalObtainedMarks) > Number(m.practicalTotalMarks);
                    return invalidTh || invalidPr;
                } else {
                    if (m.totalMarks == null || m.totalMarks === '' || m.obtainedMarks == null || m.obtainedMarks === '') return false;
                    return Number(m.obtainedMarks) > Number(m.totalMarks);
                }
            });

            if (invalidMark) {
                toast.error("Obtained marks cannot exceed Total marks.");
                return;
            }

            for (const mark of editedMarks) {
                if ((mark.totalMarks ?? '') !== '' || (mark.obtainedMarks ?? '') !== '' || (mark.theoryTotalMarks ?? '') !== '' || (mark.theoryObtainedMarks ?? '') !== '' || (mark.practicalTotalMarks ?? '') !== '' || (mark.practicalObtainedMarks ?? '') !== '' || (mark.grade ?? '') !== '' || mark.isPass !== null) {
                    await authFetch(`${API_BASE_URL}/exams/marks/student/${studentId}`, {
                        method: "PATCH",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({
                            classId: student.class?.id,
                            sectionId: student.section?.id,
                            sessionId: sessionId,
                            subjectId: mark.subjectId,
                            examCategoryId: mark.examCategoryId,
                            totalMarks: mark.totalMarks !== '' && mark.totalMarks !== null ? Number(mark.totalMarks) : undefined,
                            obtainedMarks: mark.obtainedMarks !== '' && mark.obtainedMarks !== null ? Number(mark.obtainedMarks) : undefined,
                            theoryTotalMarks: mark.theoryTotalMarks !== '' && mark.theoryTotalMarks !== null ? Number(mark.theoryTotalMarks) : undefined,
                            theoryObtainedMarks: mark.theoryObtainedMarks !== '' && mark.theoryObtainedMarks !== null ? Number(mark.theoryObtainedMarks) : undefined,
                            practicalTotalMarks: mark.practicalTotalMarks !== '' && mark.practicalTotalMarks !== null ? Number(mark.practicalTotalMarks) : undefined,
                            practicalObtainedMarks: mark.practicalObtainedMarks !== '' && mark.practicalObtainedMarks !== null ? Number(mark.practicalObtainedMarks) : undefined,
                            grade: mark.grade || null,
                            isPass: mark.isPass
                        })
                    });
                }
            }
            toast.success("Marks updated successfully!");
            setIsEditMode(false);
            mutateMarks();
            onSave?.();
        } catch (err) {
            toast.error("Failed to update marks");
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-2 sm:p-4 bg-slate-900/50 backdrop-blur-sm">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-6xl max-h-[95vh] flex flex-col overflow-hidden">
                <div className="px-4 sm:px-6 py-4 border-b border-slate-200 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 sm:gap-0 bg-slate-50">
                    <h3 className="text-lg sm:text-xl font-bold text-slate-800 wrap-break-word w-full sm:w-auto">
                        Exam Results {student ? ` - ${student.firstName} ${student.lastName}` : ''}
                    </h3>
                    <div className="flex items-center gap-2 sm:gap-3 self-end sm:self-auto">
                        {!isEditMode ? (
                            <button onClick={() => setIsEditMode(true)} className="px-3 sm:px-4 py-1.5 sm:py-2 bg-blue-600 text-white rounded text-sm font-medium hover:bg-blue-700">
                                Edit Marks
                            </button>
                        ) : (
                            <button onClick={handleSave} className="px-3 sm:px-4 py-1.5 sm:py-2 bg-green-600 text-white rounded text-sm font-medium hover:bg-green-700">
                                Save Changes
                            </button>
                        )}
                        <button onClick={onClose} className="text-slate-500 hover:text-slate-800 p-1 sm:p-2">
                            <span className="sr-only">Close</span>
                            <svg className="w-5 h-5 sm:w-6 sm:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>
                </div>

                <div className="p-4 sm:p-6 overflow-y-auto flex-1">
                    {isLoading ? (
                        <div className="py-12"><Loader text="Loading result data..." /></div>
                    ) : (
                        <div className="relative overflow-x-auto rounded-lg border border-gray-200 shadow-sm">
                            <table className="w-full text-sm text-left text-gray-500 min-w-[600px] md:min-w-max">
                                <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b">
                                    <tr>
                                        <th className="px-4 py-3 bg-gray-100 sticky left-0 z-10 w-48 align-bottom" rowSpan={2}>Subject</th>
                                        {categories.map((cat: any) => (
                                            <th key={cat.id} className="px-4 py-3 text-center border-l border-gray-300 bg-gray-100" colSpan={6}>
                                                {cat.name}
                                            </th>
                                        ))}
                                    </tr>
                                    <tr>
                                        {categories.map((cat: any) => (
                                            <React.Fragment key={`sub-${cat.id}`}>
                                                <th className="px-2 py-2 text-center text-[10px] text-gray-500 border-l border-gray-300 bg-gray-50">Th. Marks</th>
                                                <th className="px-2 py-2 text-center text-[10px] text-gray-500 border-l border-gray-200 bg-purple-50">Pr. Marks</th>
                                                <th className="px-2 py-2 text-center text-[10px] text-gray-500 border-l border-gray-200 bg-gray-50">Total</th>
                                                <th className="px-2 py-2 text-center text-[10px] text-gray-500 border-l border-gray-200 bg-gray-50">Obtained</th>
                                                <th className="px-2 py-2 text-center text-[10px] text-blue-600 border-l border-gray-200 bg-blue-50/50">Percentage</th>
                                                <th className="px-2 py-2 text-center text-[10px] text-gray-500 border-l border-gray-200 bg-gray-50">Grade / Status</th>
                                            </React.Fragment>
                                        ))}
                                    </tr>
                                </thead>
                                <tbody>
                                    {student?.studentSubjects?.map((ss: any) => {
                                        const subject = ss.subject || ss.extraSubject;
                                        if (!subject) return null;
                                        return (
                                            <tr key={subject.id} className="bg-white border-b hover:bg-gray-50">
                                                <td className="px-4 py-3 font-semibold text-slate-800 bg-white sticky left-0 z-10">
                                                    {subject.name}
                                                </td>
                                                {categories.map((cat: any) => {
                                                    const m = getMark(subject.id, cat.id);
                                                    const isTargetCategory = examSettings?.finalTargetCategoryId === cat.id;
                                                    const isSplit = subject.hasTheory && subject.hasPractical;

                                                    const isInvalidTh = isSplit && m.theoryTotalMarks != null && m.theoryTotalMarks !== '' && m.theoryObtainedMarks != null && m.theoryObtainedMarks !== '' && Number(m.theoryObtainedMarks) > Number(m.theoryTotalMarks);
                                                    const isInvalidPr = isSplit && m.practicalTotalMarks != null && m.practicalTotalMarks !== '' && m.practicalObtainedMarks != null && m.practicalObtainedMarks !== '' && Number(m.practicalObtainedMarks) > Number(m.practicalTotalMarks);
                                                    const isInvalidBase = !isSplit && m.totalMarks != null && m.totalMarks !== '' && m.obtainedMarks != null && m.obtainedMarks !== '' && Number(m.obtainedMarks) > Number(m.totalMarks);
                                                    const isInvalid = isInvalidTh || isInvalidPr || isInvalidBase;
                                                    
                                                    const calculatedTotal = isSplit ? (Number(m.theoryTotalMarks || 0) + Number(m.practicalTotalMarks || 0)) : Number(m.totalMarks || 0);
                                                    const calculatedObtained = isSplit ? (Number(m.theoryObtainedMarks || 0) + Number(m.practicalObtainedMarks || 0)) : Number(m.obtainedMarks || 0);

                                                    return (
                                                        <React.Fragment key={`td-${cat.id}`}>
                                                            <td className="px-2 py-2 border-l border-gray-300 text-center">
                                                                {isSplit ? (
                                                                    isEditMode ? (
                                                                        <div className="flex flex-col items-center gap-1">
                                                                            <input type="number" min="0" placeholder="Tot"
                                                                                className={`w-14 p-1 text-center border rounded text-[10px] focus:ring-blue-500 focus:border-blue-500 ${isTargetCategory ? 'bg-gray-200 cursor-not-allowed text-gray-500 border-gray-300' : 'border-gray-300'}`}
                                                                                value={m.theoryTotalMarks ?? ''}
                                                                                onChange={e => handleMarkChange(subject.id, cat.id, 'theoryTotalMarks', e.target.value)} disabled={isTargetCategory} />
                                                                            <input type="number" min="0" max={m.theoryTotalMarks ?? ''} placeholder="Obt"
                                                                                className={`w-14 p-1 text-center border rounded text-[10px] ${isTargetCategory ? 'bg-gray-200 cursor-not-allowed text-gray-500 border-gray-300' : (isInvalidTh ? 'border-red-500 bg-red-50 text-red-700' : 'border-gray-300')}`}
                                                                                value={m.theoryObtainedMarks ?? ''}
                                                                                onChange={e => handleMarkChange(subject.id, cat.id, 'theoryObtainedMarks', e.target.value)} disabled={isTargetCategory} />
                                                                        </div>
                                                                    ) : (m.theoryTotalMarks ? <div className="text-[10px]">Obt: <span className="font-bold">{m.theoryObtainedMarks ?? '-'}</span><br/>Tot: {m.theoryTotalMarks ?? '-'}</div> : '-')
                                                                ) : <span className="text-gray-300">-</span>}
                                                            </td>
                                                            <td className="px-2 py-2 border-l border-gray-300 text-center bg-purple-50/50">
                                                                {isSplit ? (
                                                                    isEditMode ? (
                                                                        <div className="flex flex-col items-center gap-1">
                                                                            <input type="number" min="0" placeholder="Tot"
                                                                                className={`w-14 p-1 text-center border rounded text-[10px] focus:ring-purple-500 focus:border-purple-500 ${isTargetCategory ? 'bg-gray-200 cursor-not-allowed text-gray-500 border-gray-300' : 'border-gray-300'}`}
                                                                                value={m.practicalTotalMarks ?? ''}
                                                                                onChange={e => handleMarkChange(subject.id, cat.id, 'practicalTotalMarks', e.target.value)} disabled={isTargetCategory} />
                                                                            <input type="number" min="0" max={m.practicalTotalMarks ?? ''} placeholder="Obt"
                                                                                className={`w-14 p-1 text-center border rounded text-[10px] ${isTargetCategory ? 'bg-gray-200 cursor-not-allowed text-gray-500 border-gray-300' : (isInvalidPr ? 'border-red-500 bg-red-50 text-red-700' : 'border-gray-300')}`}
                                                                                value={m.practicalObtainedMarks ?? ''}
                                                                                onChange={e => handleMarkChange(subject.id, cat.id, 'practicalObtainedMarks', e.target.value)} disabled={isTargetCategory} />
                                                                        </div>
                                                                    ) : (m.practicalTotalMarks ? <div className="text-[10px] text-purple-900">Obt: <span className="font-bold">{m.practicalObtainedMarks ?? '-'}</span><br/>Tot: {m.practicalTotalMarks ?? '-'}</div> : '-')
                                                                ) : <span className="text-gray-300">-</span>}
                                                            </td>
                                                            <td className="px-2 py-2 border-l border-gray-300 text-center">
                                                                {isSplit ? (
                                                                    <span className="font-bold text-slate-600">{calculatedTotal > 0 ? calculatedTotal : '-'}</span>
                                                                ) : (
                                                                    isEditMode ? (
                                                                        <input type="number" min="0"
                                                                            className={`w-16 p-1 text-center border rounded text-xs focus:ring-blue-500 focus:border-blue-500 ${isTargetCategory ? 'bg-gray-200 cursor-not-allowed text-gray-500 border-gray-300' : 'border-gray-300'}`}
                                                                            value={m.totalMarks ?? ''}
                                                                            onChange={e => handleMarkChange(subject.id, cat.id, 'totalMarks', e.target.value)}
                                                                            disabled={isTargetCategory}
                                                                        />
                                                                    ) : (m.totalMarks ?? '-')
                                                                )}
                                                            </td>
                                                            <td className={`px-2 py-2 border-l border-gray-200 text-center ${isInvalid ? 'bg-red-50' : ''}`}>
                                                                {isSplit ? (
                                                                    <span className={`font-bold ${isInvalid ? 'text-red-600' : 'text-slate-800'}`}>{calculatedTotal > 0 ? calculatedObtained : '-'}</span>
                                                                ) : (
                                                                    isEditMode ? (
                                                                        <div className="flex flex-col items-center">
                                                                            <input type="number" min="0" max={m.totalMarks ?? ''}
                                                                                className={`w-16 p-1 text-center border rounded text-xs ${isTargetCategory ? 'bg-gray-200 cursor-not-allowed text-gray-500 border-gray-300' : (isInvalidBase ? 'border-red-500 ring-1 ring-red-500 focus:ring-red-500 focus:border-red-500 bg-red-50 text-red-700' : 'border-gray-300 focus:ring-blue-500 focus:border-blue-500')}`}
                                                                                value={m.obtainedMarks ?? ''}
                                                                                onChange={e => handleMarkChange(subject.id, cat.id, 'obtainedMarks', e.target.value)}
                                                                                disabled={isTargetCategory}
                                                                            />
                                                                        </div>
                                                                    ) : (
                                                                        <span className={isInvalidBase ? 'text-red-600 font-bold' : ''}>{m.obtainedMarks ?? '-'}</span>
                                                                    )
                                                                )}
                                                            </td>
                                                            <td className="px-2 py-2 border-l border-gray-200 text-center font-bold text-slate-700 bg-blue-50/10">
                                                                {calculatedTotal > 0 ?
                                                                    `${((Number(calculatedObtained) * 100) / Number(calculatedTotal)).toFixed(1)}%`
                                                                    : '-'}
                                                            </td>
                                                            <td className="px-2 py-2 border-l border-gray-200 text-center font-bold text-slate-600">
                                                                <div className="flex flex-col items-center gap-1">
                                                                    <span>{m.grade || '-'}</span>
                                                                    {m.isPass === true ? (
                                                                        <span className="px-2 py-0.5 text-[9px] font-bold rounded uppercase bg-green-100 text-green-700">Pass</span>
                                                                    ) : m.isPass === false ? (
                                                                        <span className="px-2 py-0.5 text-[9px] font-bold rounded uppercase bg-red-100 text-red-700">Fail</span>
                                                                    ) : null}
                                                                </div>
                                                            </td>
                                                        </React.Fragment>
                                                    );
                                                })}
                                            </tr>
                                        );
                                    })}
                                    {(!student?.studentSubjects || student.studentSubjects.length === 0) && (
                                        <tr><td colSpan={categories.length * 4 + 1} className="p-6 text-center text-gray-500 italic">No subjects enrolled for this student.</td></tr>
                                    )}
                                </tbody>
                                <tfoot className="bg-gray-100 font-bold border-t-2 border-gray-300 shadow-inner">
                                    <tr>
                                        <td className="px-4 py-4 sticky left-0 z-10 bg-slate-200 text-slate-800 uppercase tracking-wider">Overall / Total</td>
                                        {categories.map((cat: any) => {
                                            let sumTotal = 0;
                                            let sumObtained = 0;

                                            student?.studentSubjects?.forEach((ss: any) => {
                                                const subject = ss.subject || ss.extraSubject;
                                                const m = getMark(subject?.id, cat.id);
                                                if (m.totalMarks) sumTotal += Number(m.totalMarks);
                                                if (m.obtainedMarks) sumObtained += Number(m.obtainedMarks);
                                            });

                                            let perc = 0;
                                            let percStr = '-';
                                            let overallGrade = '-';
                                            let isPassText = '-';
                                            let isPassColor = 'text-gray-500 bg-gray-50';

                                            if (sumTotal > 0) {
                                                perc = (sumObtained * 100) / sumTotal;
                                                percStr = `${perc.toFixed(2)}%`;

                                                let assignedGrade: any = null;
                                                for (const g of gradingSystems) {
                                                    if (perc >= g.minPercentage && (perc < g.maxPercentage || (g.maxPercentage === 100 && perc <= 100))) {
                                                        assignedGrade = g;
                                                        break;
                                                    }
                                                }

                                                if (assignedGrade) {
                                                    overallGrade = assignedGrade.gradeName;
                                                    if (assignedGrade.isFailGrade) {
                                                        isPassText = 'FAIL';
                                                        isPassColor = 'text-red-800 bg-red-200';
                                                    } else {
                                                        isPassText = 'PASS';
                                                        isPassColor = 'text-green-800 bg-green-200';
                                                    }
                                                }
                                            }

                                            return (
                                                <React.Fragment key={`tfoot-${cat.id}`}>
                                                    <td className="px-2 py-3 border-l border-gray-300 text-center text-slate-700">{sumTotal || '-'}</td>
                                                    <td className="px-2 py-3 border-l border-gray-200 text-center text-slate-700">{sumObtained || '-'}</td>
                                                    <td className="px-2 py-3 border-l border-gray-200 text-center text-blue-800 bg-blue-100">{percStr}</td>
                                                    <td className="px-2 py-3 border-l border-gray-200 text-center text-slate-700">{overallGrade}</td>
                                                    <td className={`px-2 py-3 border-l border-gray-200 text-center text-[10px] uppercase ${isPassColor}`}>{isPassText}</td>
                                                </React.Fragment>
                                            );
                                        })}
                                    </tr>
                                </tfoot>
                            </table>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { X, Download, Share } from 'lucide-react';
import { getEnv } from "@/lib/env";

const schoolName = getEnv('SCHOOL_NAME') || 'School Management System';

interface BeforeInstallPromptEvent extends Event {
    prompt: () => Promise<void>;
    userChoice: Promise<{ outcome: 'accepted' | 'dismissed'; platform: string }>;
}

export default function PWAInstallBanner() {
    const [installPrompt, setInstallPrompt] = useState<BeforeInstallPromptEvent | null>(null);
    const [showBanner, setShowBanner] = useState(false);
    const [showMiniButton, setShowMiniButton] = useState(false);
    const [isIOS] = useState(() => typeof window !== 'undefined' && /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as unknown as { MSStream: unknown }).MSStream);
    const [isEdgeFallback, setIsEdgeFallback] = useState(false);
    const [isInstalled] = useState(() => typeof window !== 'undefined' && window.matchMedia('(display-mode: standalone)').matches);

    // Ref so async callbacks always see the live "prompt received" state without stale closures
    const installPromptReceived = useRef(false);

    useEffect(() => {
        // Suppress banner on desktop/laptop ΓÇö the browser URL bar install icon is sufficient there
        if (window.matchMedia('(hover: hover) and (pointer: fine)').matches) {
            return;
        }

        // ΓöÇΓöÇ Dismissal check FIRST, before any timeout is scheduled ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        // This prevents the async setTimeout from overriding a prior dismissal.
        const dismissed = localStorage.getItem('pwa-banner-dismissed');
        const sevenDays = 7 * 24 * 60 * 60 * 1000;
        const recentlyDismissed = !!dismissed && (Date.now() - parseInt(dismissed, 10) < sevenDays);

        // iOS: no beforeinstallprompt ΓÇö show static "Add to Home Screen" instructions
        if (isIOS) {
            if (!recentlyDismissed) {
                setTimeout(() => setShowBanner(true), 3000);
            }
            return; // no further event handlers needed for iOS
        }

        // ΓöÇΓöÇ beforeinstallprompt handler (Chrome, Edge, Samsung Internet, Firefox) ΓöÇΓöÇ
        const handleBeforeInstallPrompt = (e: Event) => {
            e.preventDefault();
            installPromptReceived.current = true;
            // Clear the Edge fallback timer if it hasn't fired yet
            if (edgeTimeoutId) clearTimeout(edgeTimeoutId);
            setInstallPrompt(e as BeforeInstallPromptEvent);
            if (!recentlyDismissed) {
                setTimeout(() => setShowBanner(true), 3000);
            } else {
                // Banner suppressed by recent dismissal, but keep prompt for mini-button
                setShowMiniButton(true);
            }
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

        // ΓöÇΓöÇ Edge / other Chromium-based browser fallback ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        //
        // Edge on Android uses stricter engagement heuristics than Chrome and may
        // never fire beforeinstallprompt on a first visit. After 5 seconds, if the
        // event still hasn't arrived, we show manual install instructions specific
        // to the detected browser so the user is never left without guidance.
        let edgeTimeoutId: ReturnType<typeof setTimeout> | null = null;

        if (!recentlyDismissed) {
            const ua = navigator.userAgent;
            const isEdge = /Edg\//.test(ua);
            // Samsung Internet, Firefox for Android, etc. also may not fire the event
            const isOtherBrowser = !isEdge && !/Chrome\//.test(ua);

            if (isEdge || isOtherBrowser) {
                edgeTimeoutId = setTimeout(() => {
                    if (!installPromptReceived.current) {
                        setIsEdgeFallback(true);
                        setShowBanner(true);
                    }
                }, 5000);
            }
        }

        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
            if (edgeTimeoutId) clearTimeout(edgeTimeoutId);
        };
    }, []);

    const handleInstallClick = async () => {
        if (!installPrompt) return;
        await installPrompt.prompt();
        const { outcome } = await installPrompt.userChoice;
        if (outcome === 'accepted') {
            setShowBanner(false);
            setShowMiniButton(false);
            setInstallPrompt(null);
        }
    };

    const handleDismiss = () => {
        setShowBanner(false);
        localStorage.setItem('pwa-banner-dismissed', Date.now().toString());
        // If a native install prompt is still available, surface a persistent mini-button
        // so the user can still install later without having to know about the address-bar icon.
        if (installPrompt) {
            setShowMiniButton(true);
        }
    };

    if (isInstalled) return null;

    // ΓöÇΓöÇ Mini install button ΓÇö shown after the main banner is dismissed ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (!showBanner && showMiniButton && installPrompt) {
        return (
            <button
                onClick={handleInstallClick}
                title={`Install ${schoolName}`}
                style={{
                    position: 'fixed',
                    bottom: '1.25rem',
                    right: '1.25rem',
                    zIndex: 9999,
                    width: '48px',
                    height: '48px',
                    borderRadius: '50%',
                    background: 'linear-gradient(135deg, #1e3a5f 0%, #2d5a8e 100%)',
                    border: 'none',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    boxShadow: '0 4px 16px rgba(30, 58, 95, 0.45)',
                    color: 'white',
                }}
                aria-label={`Install ${schoolName}`}
            >
                <Download size={20} />
            </button>
        );
    }

    if (!showBanner) return null;

    return (
        <div
            style={{
                position: 'fixed',
                bottom: '1rem',
                left: '50%',
                transform: 'translateX(-50%)',
                zIndex: 9999,
                width: 'calc(100% - 2rem)',
                maxWidth: '480px',
                background: 'linear-gradient(135deg, #1e3a5f 0%, #2d5a8e 100%)',
                borderRadius: '16px',
                padding: '16px',
                boxShadow: '0 8px 32px rgba(30, 58, 95, 0.4)',
                display: 'flex',
                alignItems: 'center',
                gap: '12px',
                animation: 'slideUp 0.4s ease-out',
                color: 'white',
            }}
        >
            <style>{`
        @keyframes slideUp {
          from { transform: translateX(-50%) translateY(100px); opacity: 0; }
          to { transform: translateX(-50%) translateY(0); opacity: 1; }
        }
      `}</style>

            {/* App Icon */}
            <img
                src={'/colegios/logo.png'}
                alt={schoolName}
                style={{ width: '48px', height: '48px', borderRadius: '12px', flexShrink: 0 }}
            />

            {/* Text */}
            <div style={{ flex: 1, minWidth: 0 }}>
                <p style={{ margin: 0, fontWeight: 700, fontSize: '14px', lineHeight: 1.3 }}>
                    Install {schoolName}
                </p>
                {isIOS ? (
                    <p style={{ margin: '4px 0 0', fontSize: '12px', opacity: 0.85, lineHeight: 1.4 }}>
                        Tap <Share size={12} style={{ display: 'inline', verticalAlign: 'middle' }} /> then &ldquo;Add to Home Screen&rdquo;
                    </p>
                ) : isEdgeFallback ? (
                    <p style={{ margin: '4px 0 0', fontSize: '12px', opacity: 0.85, lineHeight: 1.4 }}>
                        Tap <span style={{ fontWeight: 700 }}>Γï»</span> menu &rarr; &ldquo;Add to phone&rdquo; to install
                    </p>
                ) : (
                    <p style={{ margin: '4px 0 0', fontSize: '12px', opacity: 0.85 }}>
                        Install app for quick access, offline support
                    </p>
                )}
            </div>

            {/* Install button (only on non-iOS where we have the prompt) */}
            {!isIOS && installPrompt && (
                <button
                    onClick={handleInstallClick}
                    style={{
                        background: 'white',
                        color: '#1e3a5f',
                        border: 'none',
                        borderRadius: '8px',
                        padding: '8px 12px',
                        fontSize: '13px',
                        fontWeight: 700,
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '4px',
                        flexShrink: 0,
                        whiteSpace: 'nowrap',
                    }}
                >
                    <Download size={14} />
                    Install
                </button>
            )}

            {/* Dismiss */}
            <button
                onClick={handleDismiss}
                style={{
                    background: 'rgba(255,255,255,0.15)',
                    border: 'none',
                    borderRadius: '8px',
                    padding: '8px',
                    cursor: 'pointer',
                    color: 'white',
                    display: 'flex',
                    flexShrink: 0,
                }}
                aria-label="Dismiss install banner"
            >
                <X size={16} />
            </button>
        </div>
    );
}

"use client";

/**
 * ReceiptModal ΓÇô shared across admin fee-collection and parent portal.
 *
 * Features:
 *  ΓÇó Responsive: scrollable body, always-visible header + footer buttons.
 *  ΓÇó Print: prints ONLY the receipt, formatted for A5 paper.
 */

import React, { useRef, useState } from "react";
import { CheckCircle2, School, CreditCard, CalendarDays, User, Hash } from "lucide-react";
import { jsPDF } from "jspdf";
import { toPng } from "html-to-image";
import { getEnv } from "@/lib/env";

export interface ReceiptData {
    receiptNumber?: string;
    paymentDate?: string;
    studentName?: string;
    academicYear?: string;
    studentClass?: string;
    studentSection?: string;
    /** Months label shown on the receipt */
    monthsPaid?: string;
    /** Used as fallback for monthsPaid on parent portal */
    feeMonth?: string;
    paymentMethod?: string;
    /** Normalised component breakdown (new API) */
    components?: Array<{
        type: "FEE_CATEGORY" | "DISCOUNT" | "LATE_FEE";
        feeCategoryName?: string;
        discountName?: string;
        amount: number;
    }>;
    /** Legacy category breakdown */
    categoryBreakdown?: Array<{ name: string; amount: number }>;
    /** Legacy applied-discounts breakdown */
    appliedDiscounts?: Array<{ name: string; amount: number }>;
    /** Legacy feeBreakdown object (parent portal older payments) */
    feeBreakdown?: {
        categories?: Array<{ name: string; amount: number }>;
        discounts?: Array<{ name: string; amount: number }>;
        lateFee?: number;
    };
    /** Fallback when no category rows exist */
    feeCategory?: string;
    totalBaseFee?: number;
    totalLateFee?: number;
    baseFeeAmount?: number;
    discountAmount?: number;
    otherFeeAmount?: number;
    /** Total payable before payment (admin + parent portal) */
    totalPayable?: number | null;
    amountPaid: number;
    /** Admin portal: balance still owed after this payment */
    balanceAfterPayment?: number;
    /** Parent portal: balance remaining for partial payments */
    balanceRemaining?: number;
    excess?: number;
    adjustments?: Array<{
        type: "REFUND" | "WAIVE_OFF";
        amount: number;
        paymentMethod?: string;
        adjustedAt?: string;
        reason?: string;
        createdByName?: string;
    }>;
    collectedByName?: string;
    gatewayPaymentId?: string;
    gatewayOrderId?: string;
    remarks?: string;
    /** Admin portal: used to pass month key for collect-remaining / waive-off actions */
    monthKey?: string;
}

interface AdminExtraProps {
    /** Whether the logged-in user is an admin (for waive-off / refund actions) */
    isAdmin?: boolean;
    onCollectRemaining?: () => void;
    onWaiveOff?: () => void;
    onIssueRefund?: () => void;
}

interface ReceiptModalProps extends AdminExtraProps {
    receiptData: ReceiptData;
    onClose: () => void;
}

export default function ReceiptModal({
    receiptData,
    onClose,
    isAdmin,
    onCollectRemaining,
    onWaiveOff,
    onIssueRefund,
}: ReceiptModalProps) {
    const schoolName = getEnv('SCHOOL_NAME') || "EduSphere";

    const monthLabel =
        receiptData.monthsPaid || receiptData.feeMonth || "ΓÇö";

    // Ref to the receipt card ΓÇö used by handlePrint to grab exact HTML without
    // risk of querySelector matching another .receipt-print-area on the page.
    const receiptRef = useRef<HTMLDivElement>(null);
    const [isDownloading, setIsDownloading] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);

    // ΓöÇΓöÇ Print handler (A5)
    // Uses html-to-image to capture the receipt as a PNG, then injects a single
    // <img> into a print container and calls window.print().
    //
    // Why image-based instead of HTML injection?
    // The previous HTML-injection approach relied on @media print CSS to hide
    // siblings and let the receipt flow across pages. This is fragile on mobile
    // PWA (Android/iOS standalone mode): the browser computes print page count
    // from the live DOM height BEFORE the @media print rules are applied, which
    // causes the receipt to repeat on every generated page (duplication bug).
    //
    // Injecting a single <img> instead means:
    //   ΓÇó One element ΓåÆ browser always produces exactly one page
    //   ΓÇó No CSS color/class parsing ΓÇö just a flat image
    //   ΓÇó Works identically on desktop Chrome, Android PWA, and iOS standalone
    const handlePrint = async () => {
        if (!receiptRef.current) return;
        setIsPrinting(true);

        const element = receiptRef.current;
        const originalMaxHeight = element.style.maxHeight;
        element.style.maxHeight = 'none';

        const scrollBody = element.querySelector('.receipt-scroll-body') as HTMLElement;
        const sbOriginalMaxHeight = scrollBody ? scrollBody.style.maxHeight : '';
        const sbOriginalOverflow = scrollBody ? scrollBody.style.overflow : '';
        if (scrollBody) {
            scrollBody.style.maxHeight = 'none';
            scrollBody.style.overflow = 'visible';
        }

        try {
            const imgData = await toPng(element, {
                pixelRatio: 2,
                filter: (node: Node) => {
                    const el = node as HTMLElement;
                    if (!el.classList) return true;
                    return (
                        !el.classList.contains('no-print') &&
                        !el.hasAttribute('data-html2canvas-ignore')
                    );
                },
            });

            // Restore constraints before opening print dialog
            element.style.maxHeight = originalMaxHeight;
            if (scrollBody) {
                scrollBody.style.maxHeight = sbOriginalMaxHeight;
                scrollBody.style.overflow = sbOriginalOverflow;
            }

            // Inject a single <img> ΓÇö one element = exactly one print page,
            // no page-count computation issues on mobile.
            // The container is locked to the exact A5 page dimensions and
            // object-fit:contain scales the image to fit ΓÇö so regardless of
            // the receipt's aspect ratio it always renders on a single page.
            const printContainer = document.createElement('div');
            printContainer.id = '__receipt-print-root__';
            printContainer.innerHTML = `<img src="${imgData}" style="display:block;width:148mm;height:210mm;object-fit:contain;object-position:top center;" />`;
            document.body.appendChild(printContainer);

            const printStyle = document.createElement('style');
            printStyle.id = '__receipt-print-style__';
            printStyle.textContent = `
@media print {
  @page { size: A5 portrait; margin: 0; }
  html, body {
    margin: 0 !important; padding: 0 !important; background: white !important;
    -webkit-print-color-adjust: exact !important;
    print-color-adjust: exact !important;
  }
  body > *:not(#__receipt-print-root__) { display: none !important; }
  #__receipt-print-root__ {
    display: block !important;
    width: 148mm !important;
    height: 210mm !important;
    overflow: hidden !important;
    page-break-after: avoid !important;
    break-after: avoid !important;
  }
  #__receipt-print-root__ img {
    display: block !important;
    width: 148mm !important;
    height: 210mm !important;
    object-fit: contain !important;
    object-position: top center !important;
    page-break-inside: avoid !important;
    break-inside: avoid !important;
  }
}`;
            document.head.appendChild(printStyle);

            setTimeout(() => {
                setIsPrinting(false);
                window.print();
                setTimeout(() => {
                    document.getElementById('__receipt-print-root__') && document.body.removeChild(printContainer);
                    document.getElementById('__receipt-print-style__') && document.head.removeChild(printStyle);
                }, 1500);
            }, 150);

        } catch {
            element.style.maxHeight = originalMaxHeight;
            if (scrollBody) {
                scrollBody.style.maxHeight = sbOriginalMaxHeight;
                scrollBody.style.overflow = sbOriginalOverflow;
            }
            setIsPrinting(false);
        }
    };

    // ΓöÇΓöÇ PDF Download handler (A4, uses html-to-image + jsPDF)
    // html-to-image renders via SVG foreignObject so the browser handles ALL
    // CSS natively ΓÇö including modern color functions like oklch()/lab() used
    // by Tailwind v4, which legacy html2canvas cannot parse.
    const handleDownloadPDF = async () => {
        if (!receiptRef.current) return;
        setIsDownloading(true);

        const element = receiptRef.current;
        const originalMaxHeight = element.style.maxHeight;
        element.style.maxHeight = 'none';

        const scrollBody = element.querySelector('.receipt-scroll-body') as HTMLElement;
        const sbOriginalMaxHeight = scrollBody ? scrollBody.style.maxHeight : '';
        const sbOriginalOverflow = scrollBody ? scrollBody.style.overflow : '';
        if (scrollBody) {
            scrollBody.style.maxHeight = 'none';
            scrollBody.style.overflow = 'visible';
        }

        try {
            const imgData = await toPng(element, {
                pixelRatio: 2,
                filter: (node: Node) => {
                    const el = node as HTMLElement;
                    if (!el.classList) return true;
                    return (
                        !el.classList.contains('no-print') &&
                        !el.hasAttribute('data-html2canvas-ignore')
                    );
                },
            });

            // Measure the rendered image dimensions to compute mmHeight
            const img = new Image();
            await new Promise<void>((resolve) => { img.onload = () => resolve(); img.src = imgData; });

            const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a5' });
            // Available area with 8mm margins on all sides (A5 = 148├ù210mm)
            const margin = 8;
            const availW = 148 - margin * 2;
            const availH = 210 - margin * 2;
            const imgRatio = img.naturalHeight / img.naturalWidth;
            const availRatio = availH / availW;

            // Scale to fit entirely within the page, maintaining aspect ratio
            let fitW: number, fitH: number;
            if (imgRatio > availRatio) {
                fitH = availH;
                fitW = availH / imgRatio;
            } else {
                fitW = availW;
                fitH = availW * imgRatio;
            }
            const x = margin + (availW - fitW) / 2;
            pdf.addImage(imgData, 'PNG', x, margin, fitW, fitH);

            pdf.save(`receipt-${receiptData.receiptNumber || 'download'}.pdf`);
        } finally {
            element.style.maxHeight = originalMaxHeight;
            if (scrollBody) {
                scrollBody.style.maxHeight = sbOriginalMaxHeight;
                scrollBody.style.overflow = sbOriginalOverflow;
            }
            setIsDownloading(false);
        }
    };


    // ΓöÇΓöÇ Compute late fee from normalised components or legacy fields
    const lateFeeComp = receiptData.components?.find(
        (c) => c.type === "LATE_FEE"
    );
    const lateFeeAmt = lateFeeComp
        ? Number(lateFeeComp.amount)
        : Number(
              receiptData.totalLateFee ??
                  receiptData.otherFeeAmount ??
                  receiptData.feeBreakdown?.lateFee ??
                  0
          );

    // ΓöÇΓöÇ Category rows
    const feeCategories =
        (receiptData.components?.filter((c) => c.type === "FEE_CATEGORY") ?? []).length > 0
            ? receiptData.components!
                  .filter((c) => c.type === "FEE_CATEGORY")
                  .map((c, i) => (
                      <tr key={`cat-${i}`} className="border-b border-gray-100">
                          <td className="py-2 pl-4 pr-2">{c.feeCategoryName}</td>
                          <td className="py-2 text-right whitespace-nowrap">
                              Γé╣{Number(c.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                          </td>
                      </tr>
                  ))
            : receiptData.categoryBreakdown && receiptData.categoryBreakdown.length > 0
            ? receiptData.categoryBreakdown.map((c, i) => (
                  <tr key={`cat-${i}`} className="border-b border-gray-100">
                      <td className="py-2 pl-4 pr-2">{c.name}</td>
                      <td className="py-2 text-right whitespace-nowrap">
                          Γé╣{Number(c.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                      </td>
                  </tr>
              ))
            : receiptData.feeBreakdown?.categories && receiptData.feeBreakdown.categories.length > 0
            ? receiptData.feeBreakdown.categories.map((c, i) => (
                  <tr key={`cat-${i}`} className="border-b border-gray-100">
                      <td className="py-2 pl-4 pr-2">{c.name}</td>
                      <td className="py-2 text-right whitespace-nowrap">
                          Γé╣{Number(c.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                      </td>
                  </tr>
              ))
            : (receiptData.baseFeeAmount ?? receiptData.totalBaseFee ?? 0) > 0
            ? [
                  <tr key="base" className="border-b border-gray-100">
                      <td className="py-2 pl-4 pr-2">
                          Base Tuition
                          {receiptData.feeCategory ? ` / ${receiptData.feeCategory} Fee` : ""}
                      </td>
                      <td className="py-2 text-right whitespace-nowrap">
                          Γé╣{Number(
                              receiptData.baseFeeAmount ?? receiptData.totalBaseFee
                          ).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                      </td>
                  </tr>,
              ]
            : [];

    // ΓöÇΓöÇ Discount rows
    const discountRows =
        (receiptData.components?.filter((c) => c.type === "DISCOUNT") ?? []).length > 0
            ? receiptData.components!
                  .filter((c) => c.type === "DISCOUNT")
                  .map((c, i) => (
                      <tr key={`disc-${i}`} className="border-b border-gray-100 text-green-600">
                          <td className="py-2 pl-4 pr-2">Discount ({c.discountName})</td>
                          <td className="py-2 text-right whitespace-nowrap">
                              -Γé╣{Number(c.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                          </td>
                      </tr>
                  ))
            : receiptData.appliedDiscounts && receiptData.appliedDiscounts.length > 0
            ? receiptData.appliedDiscounts.map((d, i) => (
                  <tr key={`disc-${i}`} className="border-b border-gray-100 text-green-600">
                      <td className="py-2 pl-4 pr-2">Discount ({d.name})</td>
                      <td className="py-2 text-right whitespace-nowrap">
                          -Γé╣{Number(d.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                      </td>
                  </tr>
              ))
            : receiptData.feeBreakdown?.discounts && receiptData.feeBreakdown.discounts.length > 0
            ? receiptData.feeBreakdown.discounts.map((d, i) => (
                  <tr key={`disc-${i}`} className="border-b border-gray-100 text-green-600">
                      <td className="py-2 pl-4 pr-2">Discount ({d.name})</td>
                      <td className="py-2 text-right whitespace-nowrap">
                          -Γé╣{Number(d.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                      </td>
                  </tr>
              ))
            : !receiptData.feeBreakdown?.discounts &&
              (receiptData.discountAmount ?? 0) > 0
            ? [
                  <tr key="disc-legacy" className="border-b border-gray-100 text-green-600">
                      <td className="py-2 pl-4 pr-2">Discount</td>
                      <td className="py-2 text-right whitespace-nowrap">
                          -Γé╣{Number(receiptData.discountAmount).toLocaleString("en-IN", {
                              minimumFractionDigits: 2,
                          })}
                      </td>
                  </tr>,
              ]
            : [];

    const balanceDue =
        receiptData.balanceAfterPayment ?? receiptData.balanceRemaining ?? 0;

    return (
        <>
            {/* ΓöÇΓöÇ Print styles (Removed since we do direct PDF generation) ΓöÇΓöÇ */}

            {/* ΓöÇΓöÇ Backdrop ΓöÇΓöÇ */}
            {/*
             * NOTE: no `no-print` class on this div intentionally.
             * When printing, the receipt HTML is captured and injected into a separate
             * #__receipt-print-root__ node directly in <body>. The backdrop (and everything
             * else on the page) is hidden via `body > *:not(#__receipt-print-root__){ display:none }`,
             * so the backdrop/modal are simply not in the print render path at all.
             */}
            <div
                className="fixed inset-0 z-200 flex items-center justify-center p-3 sm:p-4 bg-black/60 backdrop-blur-sm"
                onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
            >
                {/*
                 * ΓöÇΓöÇ Modal card ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
                 * The receipt acts as the canvas for the PDF.
                 * overflow-hidden keeps the backgrounds locked in.
                 */}
                <div ref={receiptRef} className="receipt-print-area bg-white rounded-2xl shadow-2xl w-full max-w-md flex flex-col relative overflow-hidden"
                    style={{ maxHeight: "92vh" }}>
                    
                    {/* Optional: 'PAID' Watermark effect visible in the background */}
                    <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none opacity-[0.03] rotate-[-30deg]">
                        <span className="text-[120px] font-black tracking-widest text-emerald-600">PAID</span>
                    </div>

                    {/* ΓöÇΓöÇ Premium Header ΓöÇΓöÇ */}
                    <div className="relative z-10 shrink-0 bg-slate-900 border-b-4 border-emerald-500 px-6 py-6 text-center print:rounded-none overflow-hidden">
                        {/* Subtle background pattern */}
                        <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_center,var(--tw-gradient-stops))] from-white to-transparent" />
                        
                        <div className="relative z-10 flex flex-col items-center justify-center">
                            <div className="bg-white/10 p-2 rounded-full mb-3 inline-flex">
                                <School className="w-6 h-6 text-emerald-400" />
                            </div>
                            <h2 className="text-white font-black text-xl tracking-wide">
                                {schoolName}
                            </h2>
                            <p className="text-slate-300 text-xs mt-1 uppercase tracking-widest font-medium">Official Fee Receipt</p>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ Scrollable body ΓöÇΓöÇ */}
                    <div className="receipt-scroll-body relative z-10 flex-1 overflow-y-auto px-6 py-6 bg-slate-50">

                        {/* Beautiful Meta Info Cards */}
                        <div className="grid grid-cols-2 gap-4 text-sm mb-6">
                            <div className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex items-start gap-3">
                                <div className="p-1.5 bg-slate-100 rounded-lg text-slate-500">
                                    <Hash className="w-4 h-4" />
                                </div>
                                <div>
                                    <p className="text-slate-400 text-[10px] uppercase font-bold tracking-wider mb-0.5">Receipt No.</p>
                                    <p className="font-bold font-mono text-slate-800 break-all text-sm leading-tight">
                                        {receiptData.receiptNumber || "ΓÇö"}
                                    </p>
                                </div>
                            </div>

                            <div className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex items-start justify-end gap-3 text-right pr-6">
                                <div>
                                    <p className="text-slate-400 text-[10px] uppercase font-bold tracking-wider mb-0.5 mt-0.5">Date</p>
                                    <p className="font-semibold text-slate-800 text-sm leading-tight">
                                        {receiptData.paymentDate
                                            ? new Date(receiptData.paymentDate).toLocaleDateString("en-IN", {
                                                  day: "2-digit",
                                                  month: "short",
                                                  year: "numeric",
                                              })
                                            : "ΓÇö"}
                                    </p>
                                </div>
                                <div className="p-1.5 bg-emerald-50 rounded-lg text-emerald-600 shadow-sm">
                                    <CalendarDays className="w-4 h-4" />
                                </div>
                            </div>

                            {receiptData.studentName && (
                                <div className="col-span-2 bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex items-start gap-3">
                                    <div className="p-1.5 bg-blue-50 rounded-lg text-blue-600">
                                        <User className="w-4 h-4" />
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-slate-400 text-[10px] uppercase font-bold tracking-wider mb-0.5">Student Details</p>
                                        <div className="flex justify-between items-end">
                                            <p className="font-bold text-slate-800 text-base">{receiptData.studentName}</p>
                                            <p className="font-medium text-slate-500 text-xs">
                                                {[receiptData.studentClass, receiptData.studentSection].filter(Boolean).join(" ΓÇô ")}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            )}

                            <div className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm col-span-2 flex justify-between items-center">
                                <div>
                                    <p className="text-slate-400 text-[10px] uppercase font-bold tracking-wider mb-0.5">Fee Month(s)</p>
                                    <p className="font-semibold text-slate-800 text-sm">{monthLabel}</p>
                                </div>
                                {receiptData.paymentMethod && (
                                    <div className="text-right">
                                        <p className="text-slate-400 text-[10px] uppercase font-bold tracking-wider mb-0.5">Payment Method</p>
                                        <div className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-slate-100 border border-slate-200 text-slate-700 text-xs font-medium">
                                            <CreditCard className="w-3 h-3" />
                                            {receiptData.paymentMethod}
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Breakdown table ΓÇö Redesigned as a modern card */}
                        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden mb-6">
                            <table className="w-full text-sm text-left">
                                <thead className="bg-slate-50 border-b border-slate-200">
                                    <tr>
                                        <th className="py-2.5 px-4 text-slate-500 font-bold text-xs uppercase tracking-wider">Description</th>
                                        <th className="py-2.5 px-4 text-right text-slate-500 font-bold text-xs uppercase tracking-wider">Amount</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {feeCategories}
                                    {discountRows}

                                {/* Late Fee */}
                                {lateFeeAmt > 0 && (
                                    <tr className="border-b border-gray-100 text-red-600">
                                        <td className="py-2 pl-4 pr-2">Late Fee</td>
                                        <td className="py-2 text-right whitespace-nowrap">
                                            +Γé╣{lateFeeAmt.toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                                        </td>
                                    </tr>
                                )}

                                {/* Total Payable */}
                                {receiptData.totalPayable != null && (
                                    <tr className="border-b border-gray-200 text-gray-600">
                                        <td className="py-2 pl-4 pr-2 text-sm">Total Payable</td>
                                        <td className="py-2 text-right text-sm whitespace-nowrap">
                                            Γé╣{Number(receiptData.totalPayable).toLocaleString("en-IN", {
                                                minimumFractionDigits: 2,
                                            })}
                                        </td>
                                    </tr>
                                )}

                                {/* Total Paid ΓÇö Emphasized */}
                                <tr className="bg-emerald-50 border-t-2 border-slate-200">
                                    <td className="py-3.5 px-4 font-bold text-slate-800 flex items-center gap-2">
                                        <CheckCircle2 className="w-4 h-4 text-emerald-600" />
                                        Total Paid
                                    </td>
                                    <td className="py-3.5 px-4 text-right font-bold text-emerald-700 text-base whitespace-nowrap">
                                        Γé╣{Number(receiptData.amountPaid).toLocaleString("en-IN", {
                                            minimumFractionDigits: 2,
                                        })}
                                    </td>
                                </tr>

                                {/* Refund adjustments */}
                                {(receiptData.adjustments ?? [])
                                    .filter((a) => a.type === "REFUND")
                                    .map((a, i) => (
                                        <tr key={`ref-${i}`} className="border-b border-orange-50 text-orange-600">
                                            <td className="py-2 pl-4 pr-2 text-sm">
                                                Refund ({a.paymentMethod || "ΓÇö"})
                                                {a.adjustedAt && (
                                                    <span className="ml-1 text-xs text-gray-400">
                                                        {new Date(a.adjustedAt).toLocaleDateString("en-IN", {
                                                            day: "2-digit",
                                                            month: "short",
                                                            year: "numeric",
                                                        })}
                                                    </span>
                                                )}
                                                {a.reason && (
                                                    <span className="block text-xs text-gray-400">{a.reason}</span>
                                                )}
                                                {a.createdByName && (
                                                    <span className="block text-xs text-gray-400">
                                                        Refunded by: {a.createdByName}
                                                    </span>
                                                )}
                                            </td>
                                            <td className="py-2 text-right text-sm whitespace-nowrap">
                                                -Γé╣{Number(a.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                                            </td>
                                        </tr>
                                    ))}

                                {/* Waive-off adjustments */}
                                {(receiptData.adjustments ?? [])
                                    .filter((a) => a.type === "WAIVE_OFF")
                                    .map((a, i) => (
                                        <tr key={`waive-${i}`} className="border-b border-purple-50 text-purple-600">
                                            <td className="py-2 pl-4 pr-2 text-sm">
                                                Fee Waived Off
                                                {a.adjustedAt && (
                                                    <span className="ml-1 text-xs text-gray-400">
                                                        {new Date(a.adjustedAt).toLocaleDateString("en-IN", {
                                                            day: "2-digit",
                                                            month: "short",
                                                            year: "numeric",
                                                        })}
                                                    </span>
                                                )}
                                                {a.reason && (
                                                    <span className="block text-xs text-gray-400">{a.reason}</span>
                                                )}
                                                {a.createdByName && (
                                                    <span className="block text-xs text-gray-400">
                                                        Waived by: {a.createdByName}
                                                    </span>
                                                )}
                                            </td>
                                            <td className="py-2 text-right text-sm whitespace-nowrap">
                                                -Γé╣{Number(a.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}
                                            </td>
                                        </tr>
                                    ))}

                                {/* Excess balance */}
                                {(receiptData.excess ?? 0) > 0 && (
                                    <tr className="text-green-700 border-b border-green-100">
                                        <td className="py-2 pl-4 pr-2 text-sm font-medium">Excess Balance</td>
                                        <td className="py-2 text-right text-sm font-medium whitespace-nowrap">
                                            Γé╣{Number(receiptData.excess).toLocaleString("en-IN", {
                                                minimumFractionDigits: 2,
                                            })}
                                        </td>
                                    </tr>
                                )}

                                {/* Balance remaining */}
                                {balanceDue > 0 && (
                                    <tr className="text-red-600 border-t border-red-100">
                                        <td className="py-2 pl-4 pr-2 text-sm font-medium">Balance Remaining</td>
                                        <td className="py-2 text-right text-sm font-medium whitespace-nowrap">
                                            Γé╣{Number(balanceDue).toLocaleString("en-IN", {
                                                minimumFractionDigits: 2,
                                            })}
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                        </div>

                        {/* Collected / gateway info */}
                        {receiptData.collectedByName ? (
                            <div className="text-xs text-slate-500 flex justify-between border-t border-slate-200 pt-3 mt-4">
                                <span>Collected by:</span>
                                <span className="font-medium text-slate-800">{receiptData.collectedByName}</span>
                            </div>
                        ) : receiptData.gatewayPaymentId ? (
                            <div className="text-xs text-slate-500 flex justify-between border-t border-slate-200 pt-3 mt-4">
                                <span>Processed via:</span>
                                <span className="font-medium text-slate-800">Razorpay</span>
                            </div>
                        ) : null}

                        {receiptData.gatewayPaymentId && (
                            <div className="mt-2 border border-blue-100 bg-blue-50 rounded-lg px-3 py-2 text-xs">
                                <p className="text-gray-500 mb-0.5">Gateway Transaction ID</p>
                                <div className="flex items-center gap-2 justify-between">
                                    <span className="font-mono text-blue-700 break-all">
                                        {receiptData.gatewayPaymentId}
                                    </span>
                                    <button
                                        onClick={() =>
                                            navigator.clipboard.writeText(receiptData.gatewayPaymentId!)
                                        }
                                        className="no-print text-gray-400 hover:text-blue-600 shrink-0"
                                        title="Copy"
                                    >
                                        Γºë
                                    </button>
                                </div>
                                {receiptData.gatewayOrderId && (
                                    <p className="text-gray-400 mt-1 font-mono break-all">
                                        Order: {receiptData.gatewayOrderId}
                                    </p>
                                )}
                            </div>
                        )}

                        {receiptData.remarks && (
                            <p className="mt-3 text-xs text-gray-500">Remarks: {receiptData.remarks}</p>
                        )}

                        {/* Authorized signature line / Digital generation notice */}
                        <div className="mt-6 pt-4 border-t border-slate-200 text-xs text-slate-500 flex justify-between items-center">
                            {isAdmin ? (
                                <div className="text-center">
                                    <div className="w-32 border-b border-slate-400 mb-1 h-6"></div>
                                    <span className="font-medium">Authorized Signature</span>
                                </div>
                            ) : (
                                <span className="italic bg-blue-50 text-blue-700 px-3 py-1.5 rounded-lg border border-blue-100">
                                    This is a digitally generated receipt and does not require a signature.
                                </span>
                            )}
                            <span className="font-medium text-slate-400 uppercase tracking-widest text-[10px]">Thank You</span>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ Pinned footer ΓÇô action buttons always visible ΓöÇΓöÇ */}
                    {/* data-html2canvas-ignore="true" ensures buttons aren't captured in the PDF */}
                    <div data-html2canvas-ignore="true" className="no-print shrink-0 px-6 pb-5 pt-3 border-t border-gray-100 flex flex-wrap gap-2 justify-end rounded-b-2xl bg-white">
                        <button
                            onClick={onClose}
                            className="px-4 py-2 border border-gray-300 rounded-xl text-gray-700 hover:bg-gray-50 transition-colors text-sm"
                        >
                            Close
                        </button>

                        {/* Admin-only: Collect Remaining */}
                        {onCollectRemaining && (receiptData.balanceAfterPayment ?? 0) > 0 && (
                            <button
                                onClick={onCollectRemaining}
                                className="px-4 py-2 bg-blue-100 text-blue-700 border border-blue-200 rounded-xl hover:bg-blue-200 transition-colors text-sm"
                            >
                                Collect Remaining Γé╣{Number(receiptData.balanceAfterPayment).toFixed(2)}
                            </button>
                        )}

                        {/* Admin-only: Waive Off */}
                        {isAdmin && onWaiveOff && (receiptData.balanceAfterPayment ?? 0) > 0 && (
                            <button
                                onClick={onWaiveOff}
                                className="px-4 py-2 bg-purple-100 text-purple-700 border border-purple-200 rounded-xl hover:bg-purple-200 transition-colors text-sm"
                            >
                                Waive Off Remaining
                            </button>
                        )}

                        {/* Admin-only: Issue Refund */}
                        {isAdmin && onIssueRefund && (receiptData.excess ?? 0) > 0 && (
                            <button
                                onClick={onIssueRefund}
                                className="px-4 py-2 bg-orange-100 text-orange-700 border border-orange-200 rounded-xl hover:bg-orange-200 transition-colors text-sm"
                            >
                                Issue Refund (Γé╣{Number(receiptData.excess).toFixed(2)} excess)
                            </button>
                        )}

                        <button
                            onClick={handleDownloadPDF}
                            disabled={isDownloading}
                            className="px-4 py-2 rounded-xl transition-colors text-sm flex items-center gap-2 disabled:opacity-60 disabled:cursor-not-allowed"
                            style={{ backgroundColor: '#047857', color: '#ffffff' }}
                        >
                            {isDownloading ? (
                                <>
                                    <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z" />
                                    </svg>
                                    GeneratingΓÇª
                                </>
                            ) : (
                                <>
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                    </svg>
                                    Download PDF
                                </>
                            )}
                        </button>

                        <button
                            onClick={handlePrint}
                            disabled={isPrinting}
                            className="px-4 py-2 rounded-xl transition-colors text-sm flex items-center gap-2 disabled:opacity-60 disabled:cursor-not-allowed"
                            style={{ backgroundColor: '#1e293b', color: '#ffffff' }}
                        >
                            {isPrinting ? (
                                <>
                                    <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z" />
                                    </svg>
                                    PreparingΓÇª
                                </>
                            ) : (
                                <>
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
                                    </svg>
                                    Print Receipt
                                </>
                            )}
                        </button>
                    </div>
                </div>
            </div>
        </>
    );
}

"use client";
import { getEnv } from "@/lib/env";

import { useEffect, useState } from "react";

export default function SplashScreen() {
  const [show, setShow] = useState(true);
  const [fade, setFade] = useState(false);
  const [imgSrc, setImgSrc] = useState(
    getEnv('SCHOOL_LOGO_URL') || "/colegios/Colegios.png"
  );

  useEffect(() => {
    // Start fading out after 1.5s
    const fadeTimer = setTimeout(() => {
      setFade(true);
    }, 1500);

    // Remove from DOM after 2.0s
    const hideTimer = setTimeout(() => {
      setShow(false);
    }, 2000);

    return () => {
      clearTimeout(fadeTimer);
      clearTimeout(hideTimer);
    };
  }, []);

  if (!show) return null;

  return (
    <div
      className={`fixed inset-0 z-9999 bg-slate-950 flex flex-col items-center justify-center transition-opacity duration-500 ease-in-out ${
        fade ? "opacity-0" : "opacity-100"
      }`}
    >
      <div className="absolute inset-0 bg-slate-950" />
      <div 
        className="absolute inset-0 opacity-30"
        style={{
          backgroundImage: `radial-gradient(ellipse at 50% 50%, rgba(99,102,241,0.5) 0%, transparent 60%)`
        }}
      />
      
      {/* Logo Container */}
      <div className="relative --10 w-48 h-48 md:w-64 md:h-64 rounded-3xl bg-white/10 backdrop-blur-md flex items-center justify-center shadow-2xl border border-white/20 p-6 animate-pulse">
        <img
          src={imgSrc}
          alt="School"
          className="w-full h-full object-contain drop-shadow-xl"
          onError={() => setImgSrc("/colegios/Colegios.png")}
        />
      </div>

      <div className="relative --10 mt-12 text-slate-400 text-sm font-semibold tracking-widest uppercase flex items-center gap-3">
        <svg className="animate-spin w-5 h-5 text-indigo-500" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4-" />
        </svg>
        Initiali-ing...
      </div>
    </div>
  );
}

import { getToken, getRefreshToken, setTokens, logout } from "./auth";
import { getEnv } from "./env";

export const API_BASE_URL = getEnv('API_URL') || "http://localhost:3000";

export const fetcher = async (url: string) => {
    const fullUrl = url.startsWith("http") ? url : `${API_BASE_URL}${url.startsWith("/") ? url : `/${url}`}`;

    const headers: Record<string, string> = {
        'Content-Type': 'application/json',
    };

    if (typeof window !== 'undefined') {
        const token = getToken();
        if (token) {
            headers['Authorization'] = `Bearer ${token}`;
        }
    }

    let res = await fetch(fullUrl, { headers });

    if (res.status === 401) {
        const refreshToken = getRefreshToken();
        if (refreshToken) {
            try {
                const refreshRes = await fetch(`${API_BASE_URL}/auth/refresh-token`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ refreshToken }),
                });

                if (refreshRes.ok) {
                    const data = await refreshRes.json();
                    setTokens(data.access_token, data.refresh_token || refreshToken);
                    headers['Authorization'] = `Bearer ${data.access_token}`;
                    res = await fetch(fullUrl, { headers });
                } else {
                    logout();
                }
            } catch (err) {
                logout();
            }
        } else {
            logout();
        }
    }

    if (!res.ok) {
        const error = new Error("An error occurred while fetching the data.");
        // Attach extra info to the error object.
        (error as any).info = await res.json().catch(() => ({}));
        (error as any).status = res.status;
        throw error;
    }

    return res.json();
};
